/**
 * Synthesize the team-setup compendium: one agent per theme distills the raw,
 * redundant docs-sweep extractions (claims + best practices + gotchas) into a clean,
 * dense, organized reference section. Returns { [theme]: markdown }.
 */
export const meta = {
  name: "synthesize-compendium",
  description: "Distill per-theme docs extractions into a clean compendium section",
  phases: [{ title: "Synthesize" }],
};

const CHUNK = {"Monitoring, analytics & troubleshooting": {"pages": ["analytics", "changelog", "errors", "monitoring-usage", "troubleshoot-install", "troubleshooting", "whats-new/2026-w13", "whats-new/2026-w14", "whats-new/2026-w15", "whats-new/2026-w16", "whats-new/2026-w17", "whats-new/2026-w18", "whats-new/2026-w19", "whats-new/2026-w20", "whats-new/2026-w21", "whats-new/2026-w22", "whats-new/2026-w23", "whats-new/2026-w24", "whats-new/index"], "bestPractices": ["Configure OpenTelemetry export (/en/monitoring-usage) if your team needs per-user token counts and cost estimates — the Team/Enterprise analytics dashboard does not surface these.", "To enable contribution metrics, sequence the setup: have a GitHub admin install the Claude GitHub app first, then have a Claude Owner enable analytics and the GitHub analytics toggle, then authenticate and pick orgs.", "Query Claude Code adoption programmatically by searching GitHub for PRs labeled 'claude-code-assisted' rather than relying solely on the dashboard.", "Use the Leaderboard to identify power users who can share prompting techniques and help onboard others; watch the Adoption chart for usage dips that signal friction.", "Measure ROI by tracking PRs-per-user over time and comparing PRs/lines shipped with vs without Claude Code, correlated with DORA metrics or sprint velocity.", "Use the 'Export all users' CSV (not just top-10 leaderboard) for complete per-user reporting.", "Treat reported contribution numbers as a deliberate underestimate when communicating impact — only high-confidence attributions are counted.", "Govern team model access centrally with enforceAvailableModels + availableModels in managed settings so individual user/project settings cannot widen the allowed model set.", "Pin a minimum/maximum Claude Code version (requiredMinimumVersion / requiredMaximumVersion) in managed settings to keep a team on approved, tested versions.", "Lock login to your org with forceLoginOrgUUID / forceLoginMethod to prevent users routing through unmanaged third-party providers.", "Enforce MCP governance with allowedMcpServers / deniedMcpServers in managed settings plus --strict-mcp-config so subagents and IDE configs cannot bypass policy with inline mcpServers.", "Use Tool(param:value) permission rules (e.g. Agent(model:opus)) to constrain which models subagents may spawn, rather than relying on convention.", "Configure fallbackModel (up to 3, in priority order) so interactive and headless runs and compaction degrade gracefully under provider overload.", "For unattended/long-running sessions, prefer CLAUDE_CODE_RETRY_WATCHDOG over raising CLAUDE_CODE_MAX_RETRIES (which is capped at 15).", "Use /cd to relocate a session instead of restarting, to avoid breaking the prompt cache mid-session and re-paying for cache creation.", "Use /usage per-category breakdown (skills, subagents, plugins, MCP servers) to find and attribute cost hotspots across a team's tool surface.", "Authenticate MCP servers in headless/CI/SSH with claude mcp login <name> --no-browser instead of the interactive /mcp menu.", "For CI and automation, script live-session monitoring with claude agents --json (id/state/waitingFor) to detect sessions blocked on permission prompts.", "Distribute reusable skills via nested .claude/skills directories; rely on <dir>:<name> qualification to avoid collisions and use disableBundledSkills to isolate custom skills during troubleshooting.", "In CI/unattended sessions, set CLAUDE_CODE_RETRY_WATCHDOG=1 so 429/529 capacity errors retry indefinitely rather than failing the job; conversely lower CLAUDE_CODE_MAX_RETRIES in scripts where you want fast failure.", "Standardize team auth: unset stray ANTHROPIC_API_KEY in shell profiles/.env files (direnv, dotenv, IDE terminals can load stale keys); use /login for subscription or a centrally distributed apiKeyHelper script for automation. Run /status to confirm the active credential.", "For org SSL-interception proxies, distribute the CA bundle and set NODE_EXTRA_CA_CERTS centrally; never set NODE_TLS_REJECT_UNAUTHORIZED=0.", "Behind a corporate gateway/relay, set ANTHROPIC_BASE_URL and ensure the gateway forwards the anthropic-beta header (else set CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1) to avoid 'Extra inputs are not permitted' failures.", "Manage context proactively: run /context to see what fills the window, /compact at natural breakpoints, and disable unused MCP servers (/mcp disable) — especially before spawning subagents, which inherit all parent MCP tool definitions.", "Keep CLAUDE.md memory files small and use path-specific rules so instructions load only when relevant; run /doctor to catch oversized memory files and subagent definitions that consume context and degrade response quality.", "Use model aliases (sonnet, opus) in shared settings instead of versioned IDs so they don't go stale; pin the model precedence chain knowingly (--model > ANTHROPIC_MODEL > settings.local.json > project settings.json > ~/.claude/settings.json).", "When a response goes wrong, prefer /rewind or double-Esc to a checkpoint and rephrase, rather than correcting in-thread — leftover wrong attempts anchor later answers.", "Reference large files by path (let Claude Read in chunks) instead of pasting to stay under the 30 MB request limit and the context window; for big PDFs, ask Claude to Read a page range rather than attaching the whole file.", "Set per-workspace spend caps in the Console to stop one project draining the org credit balance; enable auto-reload so prepaid credits don't hit zero mid-work.", "On a 529/overload or 'high load' notice, switch models via /model since capacity is per-model — keeps the team working during incidents.", "Reduce 429s under heavy parallel workloads by lowering CLAUDE_CODE_MAX_TOOL_USE_CONCURRENCY, limiting parallel subagents, or using a smaller model for high-volume scripted runs.", "For Bedrock/Vertex, set MAX_THINKING_TOKENS below the provider output limit (or raise CLAUDE_CODE_MAX_OUTPUT_TOKENS) to avoid thinking-budget-exceeds-output errors.", "Enable telemetry fleet-wide via the managed settings file `env` block: set CLAUDE_CODE_ENABLE_TELEMETRY=1, OTEL_METRICS_EXPORTER, OTEL_LOGS_EXPORTER, OTEL_EXPORTER_OTLP_PROTOCOL, OTEL_EXPORTER_OTLP_ENDPOINT, OTEL_EXPORTER_OTLP_HEADERS. Env vars in managed settings have high precedence and cannot be overridden by users; distribute via MDM.", "For multi-team cost/usage attribution, set OTEL_RESOURCE_ATTRIBUTES (e.g. department=engineering,team.id=platform,cost_center=eng-123) per group via managed settings or a launch wrapper. These become queryable labels on every metric datapoint and event; segment dashboards/alerts by them.", "Keep production export intervals at defaults (metrics 60000ms, logs 5000ms); only lower OTEL_METRIC_EXPORT_INTERVAL / OTEL_LOGS_EXPORT_INTERVAL during setup/debugging, then reset.", "Use OTEL_METRICS_TEMPORALITY_PREFERENCE=delta (default) unless your backend expects cumulative (e.g. set cumulative for Prometheus-style backends as needed).", "Control metrics cardinality and storage cost: high-cardinality OTEL_RESOURCE_ATTRIBUTES values add a label to every series. To send custom attributes in the OTLP resource block only and omit from datapoint labels, set OTEL_METRICS_INCLUDE_RESOURCE_ATTRIBUTES=false. Drop session.id (OTEL_METRICS_INCLUDE_SESSION_ID=false) and account UUIDs (OTEL_METRICS_INCLUDE_ACCOUNT_UUID=false) if you don't need that granularity.", "For SIEM/audit: enable the OTLP logs exporter and set OTEL_LOG_TOOL_DETAILS=1 to capture MCP server/tool names, Bash commands, and call arguments on tool_result, tool_decision, and mcp_server_connection events; point OTEL_EXPORTER_OTLP_LOGS_ENDPOINT at the SIEM OTLP receiver or a Collector.", "Attribute spend to skills/plugins/subagents using the skill.name, plugin.name, agent.name attributes on claude_code.cost.usage and claude_code.token.usage; break tokens down by type (input/output/cacheRead/cacheCreation) and model.", "For direct-API / Bedrock / Vertex / Foundry deployments there is no Claude account identity (only user.id and session.id populate), so inject user identity yourself via OTEL_RESOURCE_ATTRIBUTES (e.g. enduser.id=jdoe@example.com) per user through managed settings or launch wrapper.", "Use prompt.id to correlate all api_request/tool_result events from one user prompt for event-level analysis and audit trails (it is intentionally absent from metrics).", "Detect stalled vs recovered sessions by grouping events on session.id and checking for an api_request after an api_error; treat attempt > CLAUDE_CODE_MAX_RETRIES as retry exhaustion on a transient error.", "For dynamic/short-lived OTLP auth tokens (http/protobuf or http/json only), configure otelHeadersHelper in settings.json pointing to a script that prints JSON header key/values; it refreshes every ~29 min (tune via CLAUDE_CODE_OTEL_HEADERS_HELPER_DEBOUNCE_MS).", "Use the official ROI/monitoring repo (anthropics/claude-code-monitoring-guide) for ready-made Docker Compose, Prometheus, and OTel Collector setups and Linear-integrated productivity reports.", "Standardize on the native installer (~/.local/bin/claude) across the team and remove npm-global, legacy ~/.claude/local, Homebrew, and WinGet installs to avoid version drift; audit with which -a claude.", "For corporate networks, distribute HTTP_PROXY/HTTPS_PROXY and NODE_EXTRA_CA_CERTS (pointing at the corporate CA bundle) so both install and API requests work; ensure downloads.claude.ai and the API endpoints are allowlisted.", "When using a corporate npm registry mirror, mirror all eight @anthropic-ai/claude-code-* platform packages plus the meta package, and never disable optional dependencies.", "For Windows fleets, pin CLAUDE_CODE_GIT_BASH_PATH in settings.json and require v2.1.116+ so endpoint security (AppLocker/EDR) doesn't break shell detection; allowlist claude.exe and its child processes (cmd.exe, bash.exe).", "Have admins assign the 'Claude Code'/'Developer' role to all Console org members before onboarding; tell users to run /status to confirm active auth and to clear stray ANTHROPIC_API_KEY from shell profiles.", "Provision at least 4 GB RAM (add swap on low-memory Linux/CI) and use WSL2 (not WSL1) for Windows developer environments.", "Use /compact regularly to reduce context size when working on large codebases; close and restart Claude Code between major tasks.", "Add large build directories to .gitignore to reduce resource usage on large codebases (also keeps them out of search/indexing).", "When auto-compact thrashing fires, recover by: reading oversized files in line-range/function chunks; running /compact with a focus (e.g. '/compact keep only the plan and the diff'); moving large-file work to a subagent (separate context window); or /clear if the prior conversation is no longer needed.", "Move large-output or large-file work to a subagent so it runs in a separate context window and doesn't refill the main context.", "Run /doctor inside Claude Code (or `claude doctor` from the shell if it won't start) for an automated check of installation, settings, MCP servers, and context usage before deeper debugging.", "Use `claude --safe-mode` to disable all customizations (plugins, MCP servers, hooks) for a session to isolate whether a customization is causing high CPU/memory.", "After a hang, recover the session with `claude --resume` in the same directory rather than losing the conversation.", "On WSL, keep projects on the Linux filesystem (/home/) not the Windows mount (/mnt/c/) to avoid degraded/incomplete search results; or use more specific scoped searches by directory/file type.", "If the bundled ripgrep doesn't run, install the platform ripgrep package and set USE_BUILTIN_RIPGREP=0 so Search, @file mentions, custom agents, and custom skills find files.", "For teams wanting reduced prompt friction without full risk, set permissions.defaultMode to \"auto\" in settings.json instead of using --dangerously-skip-permissions; the classifier still blocks destructive/suspicious actions.", "Gate expensive hooks (linters, pre-commit checks) with the \"if\" field using permission-rule syntax (e.g. \"if\": \"Bash(git commit *)\") so they only spawn on relevant tool calls, cutting process overhead on busy sessions.", "For enterprise governance, layer managed policy as fragments in managed-settings.d/ rather than one monolithic managed-settings file.", "Use transcript search (Ctrl+O then /, n/N to navigate) to recover a specific command or decision from long sessions instead of scrolling.", "Distribute plugin configuration to a team via userConfig (prompt at enable time, keychain-backed secrets) rather than asking users to hand-edit settings.", "Heed the 75-minute idle nudge to /clear to keep context fresh and avoid stale long-running sessions.", "MCP server authors: only set `anthropic/maxResultSizeChars` (up to 500K) on the specific tools that genuinely return large payloads (DB schemas, full file trees); leave others at default so large results offload to disk and don't bloat context.", "For team security/governance, set `disableSkillShellExecution` to prevent skills, slash commands, and plugin commands from running inline shell.", "Bundle plugin CLI helpers in a `bin/` directory at the plugin root so agents call them as bare commands instead of hardcoded absolute paths.", "Use the `defer` permissionDecision in PreToolUse hooks for headless `-p`/SDK pipelines so tool calls that need human/UI approval pause cleanly (deferred_tool_use payload) and resume with `--resume` rather than failing.", "Use the `PermissionDenied` hook with `retry: true` so auto-mode denials redirect Claude to an alternate approach instead of dead-ending.", "Keep hook outputs under 50K chars where you need them in context; larger outputs are offloaded to disk (path + preview only).", "To onboard new teammates, run /team-onboarding in a project you've spent real time in and hand the generated ramp-up guide to them so they replay your setup instead of starting from defaults.", "Use the Monitor tool (or ask Claude to 'watch X in the background and tell me the moment Y happens') instead of writing Bash sleep loops to poll logs, CI, or dev servers — it streams events back as transcript messages and frees the turn.", "Run /loop without an interval to let Claude self-pace recurring checks (e.g. '/loop check CI on my PR') rather than hardcoding a polling interval.", "For PR cleanup without leaving the terminal, push your branch then run /autofix-pr from that branch to have Claude Code on the web watch CI and review comments and push fixes until green.", "Use /cost to inspect per-model and cache-hit breakdowns (subscription users) when tracking spend and cache efficiency.", "Use /ultraplan to offload planning of large/risky changes to a cloud session, keeping the terminal free, then review and comment on plan sections in the browser before executing.", "Set CLAUDE_CODE_PERFORCE_MODE in Perforce repos so Edit/Write fail loudly on read-only files (with a p4 edit hint) instead of silently overwriting.", "For enterprise TLS-proxy environments, rely on the now-default OS CA cert trust rather than manual cert setup; only set CLAUDE_CODE_CERT_STORE=bundled if you must opt out.", "Adjust reasoning effort with /effort; be aware the default is now high for API-key/Bedrock/Vertex/Foundry/Team/Enterprise users (higher cost/latency).", "Use /usage (press d/w for day/week) to diagnose what is consuming limits — parallel sessions, subagents, cache misses, long context — and act on the per-item optimization tips.", "For most coding/agentic work on Opus 4.7, use the 'xhigh' effort level (default on first switch) rather than always reaching for 'max'; use the /effort slider to trade intelligence against speed.", "Reduce repeated permission prompts for a team by running /fewer-permission-prompts to auto-generate a read-only Bash/MCP allowlist into .claude/settings.json.", "Set ENABLE_PROMPT_CACHING_1H for API key/Bedrock/Vertex/Foundry to cut cost on long sessions via a 1-hour prompt cache TTL.", "Use Routines for unattended team automation (e.g. PR-opened or release-published triggers) so cloud agents run without anyone's machine being on; scope each routine to specific repos and connectors.", "Enable mobile push ('Push when Claude decides' in /config) with Remote Control so you can step away during long agent runs.", "Use PreCompact hooks (exit 2 or {\"decision\":\"block\"}) to prevent context compaction at moments where losing context would be harmful.", "Use sandbox.network.deniedDomains to surgically block specific hosts inside a broad allowedDomains wildcard for tighter egress control.", "Run /ultrareview before merging critical changes (e.g., auth changes, data migrations) to get cloud bug-hunting agent findings on the branch or PR.", "Use /usage (which subsumes /cost and /stats) to inspect cost and usage stats; old command names still route to the right tab.", "Ship team-wide color themes inside plugins so all members get a consistent named theme; otherwise place JSON theme files in ~/.claude/themes/ overriding only specific tokens on a base preset.", "Use `type: \"mcp_tool\"` hooks to invoke an already-connected MCP server tool from a hook without the overhead of spawning a process.", "When customizing auto mode rules, include \"$defaults\" in autoMode.allow/soft_deny/environment to extend the built-in list rather than silently replacing it.", "Use `claude plugin tag` to create version-validated release git tags for plugins so plugin dependency version resolution works.", "Set CLAUDE_CODE_FORK_SUBAGENT=1 to enable forked subagents that inherit full conversation context when a subagent needs the parent's accumulated state instead of a fresh start.", "For team members on WSL2, SSH, containers, or IPv6-only devcontainers, use `claude auth login` and paste the OAuth code into the terminal when the localhost browser callback fails.", "Wire `claude ultrareview --json` into CI pipelines as an automated review gate — it exits 1 on failure so it can block merges.", "Set `alwaysLoad: true` only on MCP servers whose tools are needed every session; leave others deferred to preserve context window in large/multi-server setups.", "Use `claude plugin prune` (and `uninstall --prune`) to keep team plugin installs clean of orphaned auto-installed dependencies.", "Resume review work efficiently by pasting a PR URL into `/resume` or running `claude --from-pr <number>` instead of hunting for the session name.", "To onboard Windows teammates without Git Bash, ensure PowerShell 7 is installed (Store, MSI, or .NET global tool) — it is auto-detected.", "Use `claude project purge --dry-run` before `claude project purge` to preview deletion of project state during cleanup/offboarding.", "Distribute internal/team plugins via an artifact store and load them with `claude --plugin-url https://.../plugin.zip` (or a local .zip via --plugin-dir) to trial before committing to a marketplace.", "For multi-developer worktree workflows, set worktree.baseRef=head if you want new worktrees to include local unpushed commits; leave it at default `fresh` to branch from the remote default and keep unpushed work out.", "Use settings.autoMode.hard_deny to hard-block dangerous actions (e.g. destructive commands) in auto mode even when broad allow rules are present — allow exceptions cannot override hard_deny.", "Gate hook behavior on effort: read effort.level (JSON) or $CLAUDE_EFFORT in hooks/Bash to vary checks by the active effort level.", "Admins integrating the SDK should set parentSettingsBehavior to fold SDK managedSettings into the managed-policy merge for consistent governance.", "Run `/mcp` to verify server tool counts; a server flagged as connected with 0 tools indicates a misconfigured/broken MCP server.", "Upgrade Claude Code to v2.1.136+ for the parallel-session OAuth/MCP-refresh reliability fixes if you run multiple concurrent sessions or many MCP servers.", "Use `claude agents` to run multiple background sessions (e.g., a bug fix, a PR review, a flaky-test investigation) as separate rows and only step in when one is blocked on your input.", "Use `/goal` for substantial work with a verifiable end state (e.g., 'all tests in test/auth pass and lint is clean' or migrating a module until every call site compiles and tests pass) so Claude iterates autonomously instead of handing control back each turn.", "Reserve `/fast` (Opus 4.7) for rapid iteration and live debugging where ~2.5x speed is worth the higher per-token cost; it is the same model quality, not lower.", "Prefer the hook `args: string[]` exec form over shell-string commands to avoid quoting bugs with path placeholders.", "Use `continueOnBlock` on `PostToolUse` hooks when you want a hook's rejection reason fed back to Claude to self-correct, rather than ending the turn.", "Use Rewind's 'Summarize up to here' to compress old context while keeping recent turns, as a context-management tool on long sessions.", "Run `claude plugin details <name>` before installing/distributing a plugin to a team to review its component inventory and projected per-session token cost (context budget impact).", "Use /usage to attribute plan-limit consumption per skill, subagent, plugin, and MCP server — identify which components are expensive before trimming them.", "Before installing a plugin, check the /plugin Browse/Discover screens to review its bundled commands, agents, skills, hooks, MCP/LSP servers, and projected context cost.", "Use /code-review high (with --comment to post inline PR comments) for correctness-bug review; use /simplify separately when you only want cleanup, not bug hunting.", "On the Pro plan, enable auto mode (Shift+Tab) to remove routine permission prompts while keeping background safety blocking for destructive actions.", "Use 'claude agents --json' to script session pickers/status bars; pin sessions with Ctrl+T to keep them alive when idle.", "For repos where git worktrees are impractical, set worktree.bgIsolation: \"none\" so background sessions edit the working copy directly.", "Pin team minimum Claude Code version to v2.1.154+ so members can use Opus 4.8.", "Use /effort xhigh on Opus 4.8 for genuinely hard tasks; leave it at the default high for normal work to control cost.", "Reach for dynamic workflows (/workflows) for codebase-wide audits, large migrations, or cross-checked research that one conversation cannot coordinate, rather than overloading a single session.", "Install the security-guidance plugin (security-guidance@claude-plugins-official) and commit a .claude/claude-security-guidance.md with project security rules so vulnerability review runs automatically on each edit, turn, and commit/push.", "After installing or changing plugins, run /reload-plugins (or /reload-skills for skills) to activate them in the current session without restarting.", "Drop team skills directly into .claude/skills (now auto-loaded, no marketplace needed) and scaffold new plugins with `claude plugin init <name>`.", "Set disallowed-tools in skill/command frontmatter to constrain which tools the model can use while a given skill is active.", "Set --fallback-model so the session degrades gracefully instead of failing every request when the primary model is unavailable.", "Ship plugins to a team with defaultEnabled: false so they install dormant and members opt in.", "Use fast mode (/fast) deliberately — it is ~2x the cost for ~2.5x speed; reserve it for latency-sensitive work.", "For managed/enterprise rollouts, pin an approved version range with requiredMinimumVersion (and optionally requiredMaximumVersion) in managed-settings.json so non-compliant clients refuse to start while still allowing claude update/install/doctor for recovery.", "On third-party providers (Bedrock/Vertex/Foundry) running Opus 4.7/4.8, set CLAUDE_CODE_ENABLE_AUTO_MODE=1 to replace permission prompts with background safety checks; reach it via Shift+Tab.", "Set OTEL_RESOURCE_ATTRIBUTES with custom dimensions (e.g. team, repo) so fleet usage/cost metrics can be sliced by those labels.", "Use Stop/SubagentStop hooks returning hookSpecificOutput.additionalContext to inject feedback and keep a turn going, rather than emitting an error that halts the turn.", "Use /plugin list --enabled (or 'claude plugin list') to audit which plugins are active across a team without opening the interactive menu.", "When a team member's config behaves unexpectedly, run `claude --safe-mode` (or set CLAUDE_CODE_SAFE_MODE) to disable CLAUDE.md, skills, plugins, hooks, MCP servers, and custom commands/agents at once — if the problem disappears, one of those surfaces is the cause; bisect from there.", "Set `fallbackModel` (up to three models, tried in order) to keep sessions resilient to primary-model overload/unavailability instead of failing; this now also applies to interactive sessions via --fallback-model.", "For managed/governed deployments, combine `availableModels` allowlist with the `enforceAvailableModels` managed setting so the allowlist also constrains the Default model, not just explicit selections.", "Use `\"*\"` as the tool-name in a deny rule to deny all tools as a baseline-lockdown policy; watch startup warnings for typo'd/unknown tool names in deny rules.", "Use `/cd <dir>` to move an in-progress session into another project without restarting or losing the prompt cache; it is preferable to quitting and relaunching when switching repos mid-task.", "Set `disableBundledSkills` (or CLAUDE_CODE_DISABLE_BUNDLED_SKILLS) to hide bundled skills/workflows/built-in commands from the model when a team wants only its own curated skill set in context.", "Use auto mode instead of `--dangerously-skip-permissions` for unattended/agentic runs: it runs safe actions automatically and blocks risky ones via a background classifier, rather than blindly approving everything.", "For teams, enforce a managed deployment with an approved Claude Code version range ('version requirements') so all members run a vetted version.", "Use `/usage` to audit and attribute plan-limit consumption across skills, subagents, plugins, and MCP servers — the lever for cost/limit governance.", "Distribute team setup with `/team-onboarding` to capture and replay a standardized configuration; pair with the security-guidance plugin for in-flight vulnerability review.", "For large/long tasks: use `/goal` to drive Claude until a completion condition holds, `/loop` (self-paced) for recurring work, and the Rewind menu's 'Summarize up to here' to compress context.", "Use `/cd` to switch working directory mid-session without paying to rebuild the prompt cache (preserves cache cost savings).", "Configure `fallbackModel` (up to three, tried in order) so sessions degrade gracefully when the primary model is unavailable.", "Distribute plugins to a team via `.zip` archives (`--plugin-dir <zip>`) or hosted URLs (`--plugin-url`) instead of manual installs.", "Set `worktree.baseRef` explicitly to control whether new worktrees branch from the remote default or local HEAD — avoids branching from the wrong base in shared repos.", "Raise the per-tool MCP result-size override (up to 500K) only for tools that truly need large outputs; default keeps context lean.", "Use `--safe-mode` to bisect misbehavior caused by customizations (hooks/plugins/skills) by starting with all customizations disabled."], "gotchas": ["Contribution metrics are disabled entirely for orgs with Zero Data Retention — only usage metrics appear.", "Contribution metrics only cover users inside your claude.ai org; Console API and third-party-integration usage is excluded, so totals undercount mixed-channel teams.", "API/Console customers cannot get contribution/GitHub metrics at all — usage and spend only.", "Console 'Spend this month' figures are estimates for analytics, NOT actual billing — reconcile against the billing page.", "Attribution silently drops contributions: developer rewrites >20% different are not credited, and sessions outside the 21-day-before / 2-day-after merge window are ignored.", "Many file types are auto-excluded from analysis (lock files, generated/minified code, build dirs, test fixtures, lines >1000 chars), so work in those areas shows zero credit.", "Metrics are deliberately conservative and underestimate real impact — don't read low numbers as low usage.", "Contribution data can take up to 24 hours (or 'a few days' for processing) to appear; an empty dashboard often just means the GitHub app isn't installed yet.", "Lines of code accepted does not account for code later deleted, so it can overstate net retained output.", "Setting ! bash commands now triggers an automatic Claude response by default; set respondToBashCommands: false to restore context-only behavior.", "MCP timeout values under 1000ms are silently ignored and fall back to MCP_TOOL_TIMEOUT or the default — sub-second timeouts won't take effect.", "CLAUDE_CODE_MAX_RETRIES is hard-capped at 15; values above that are clamped.", "Managed MCP allow/deny rules load BEFORE remote settings and enforce on reconnect/IDE/first session, so a server allowed by remote settings can still be denied by managed policy.", "Unapproved .mcp.json servers now show '⏸ Pending approval' when output is piped (previously auto-approved in piped/non-interactive contexts).", "Auto mode blocks destructive git and terraform/pulumi/cdk destroy commands unless you explicitly asked — automation expecting these to run will be silently halted.", "Relayed cross-session messages (SendMessage) no longer carry user authority; a teammate session cannot grant permissions on your behalf.", "Resumed sessions keep their own model and no longer inherit another session's /model choice — don't assume a /model switch propagates across sessions.", "This changelog page contains apparent hallucinated/fabricated model entries (e.g. 'Fable 5', 'Mythos-class', 'Opus 4.8/4.7 effort levels') introduced by the summarizer; treat any model-name-specific claim as unverified and confirm against the real source.", "Whole-file reads exceeding the token limit now return a truncated PARTIAL view rather than erroring — agents may proceed on incomplete file content if they don't notice the notice.", "Environment ANTHROPIC_API_KEY silently overrides /login subscription auth (always used in -p mode); a key from a disabled org, a low-tier key, or a stale .env-loaded key can break or mis-route requests even when you have a working Pro/Max subscription.", "Running /login alone does NOT fix auth while an ANTHROPIC_API_KEY env var or apiKeyHelper still supplies a key — you must unset/remove the higher-precedence source first.", "Usage Policy refusals and tool-block mismatches persist across --continue/--resume because the triggering content remains in the on-disk transcript; only /rewind or /clear (new session without --continue) recovers.", "Subagents inherit ALL parent MCP tool definitions, which can exhaust their context before the first turn — a hidden cause of 'Prompt is too long' in subagents.", "Plan/subscription changes on the web do not take effect in an existing session ('Claude Opus is not available...') until you /logout then /login — the stored token reflects the plan at sign-in time.", "Before v2.1.172, the 1M-context credits error repeated on every request including /compact (needed /clear to recover); before v2.1.142 an oversized pasted image repeated the error on every subsequent message (needed Esc-twice to step back).", "Org-level settings (subscription access disabled, routines disabled) cannot be overridden by any local setting, env var, or CLI flag — only an admin can change them.", "In non-interactive mode (-p), an auto-mode classifier that exceeds its context window aborts the run entirely (retrying can't help since the transcript only grows).", "'Conversation too long' during /compact means there's not enough free context to hold the summary; you must Esc-back to drop turns or /clear, not just rerun /compact.", "A successful 'curl -I https://api.anthropic.com' but failing Claude Code points to something between runtime and network: broken /etc/resolv.conf nameserver (common in WSL), stale macOS utun VPN interfaces, or Docker Desktop intercepting outbound traffic.", "OTEL_* env vars are NOT inherited by subprocesses (Bash, hooks, MCP servers, language servers) — an instrumented app run via Bash won't pick up Claude Code's exporter endpoint/headers; set them in the command.", "OTEL_RESOURCE_ATTRIBUTES values cannot contain spaces, and wrapping in quotes does NOT escape them (org.name=\"My Company\" yields the literal value including quotes). Use underscores/camelCase or percent-encoding.", "Each OTEL_RESOURCE_ATTRIBUTES custom key becomes a label on every metric series — high-cardinality values silently inflate backend storage; set OTEL_METRICS_INCLUDE_RESOURCE_ATTRIBUTES=false to keep them resource-block-only.", "Cost metrics (claude_code.cost.usage) are approximations, not billing-grade; reconcile with the provider console.", "When authenticated via OAuth, user.email is exported in telemetry by default — redact at the backend if that's a privacy concern.", "Enabling OTEL_LOG_RAW_API_BODIES exports the full conversation history (system prompt + all prior turns + tool results) and implies consent to everything the other OTEL_LOG_* content flags reveal; only extended-thinking is always redacted.", "Default log export interval is 5s and metric 60s — leaving the debug intervals (e.g. 1s) in production floods the exporter; reset them.", "Per-model breakdown of commit/PR counts isn't directly available before/across model spans — you must approximate by joining commit/PR against token/cost metrics on session.id (one session can span multiple models).", "claude_code.api_error fires only after retries are exhausted (terminal); intermediate retries are not separate events, so retry counting relies on the attempt attribute.", "In interactive CLI, tool_decision source collapses later rule-matched calls to 'config', so user_permanent/user_temporary/user_reject only mark the original choice — Agent SDK / -p sessions behave differently (report the original source on every match).", "Detailed hook-span tracing needs extra gates (ENABLE_BETA_TRACING_DETAILED + BETA_TRACING_ENDPOINT and, for interactive CLI, org allowlisting) beyond just CLAUDE_CODE_ENHANCED_TELEMETRY_BETA — setting only the latter won't emit hook spans.", "traceparent propagation through a custom ANTHROPIC_BASE_URL proxy is off by default (some proxies reject the header) and requires CLAUDE_CODE_PROPAGATE_TRACEPARENT=1; interactive sessions also ignore inbound TRACEPARENT to avoid inheriting ambient CI/container values.", "On Bedrock/Vertex/Foundry or direct-API-key auth there is no Claude account, so only user.id and session.id populate — without injecting enduser.id via OTEL_RESOURCE_ATTRIBUTES, events can't be attributed to real users.", "Dynamic OTLP headers (otelHeadersHelper) only apply to http/protobuf and http/json; the grpc exporter uses only the static OTEL_EXPORTER_OTLP_HEADERS value.", "A leftover ANTHROPIC_API_KEY in a shell profile (e.g. from a previous employer) silently overrides subscription auth and can produce 'This organization has been disabled' even with an active subscription; with -p the key is always used when present.", "VS Code extension's bundled CLI is not on PATH, so ~/.local/bin/claude won't exist if only the extension was installed — easy to mistake for a broken install.", "WSL commonly picks up the Windows npm/node (paths under /mnt/c/), causing platform-mismatch or 'exec: node: not found'; do not disable Windows PATH importing via appendWindowsPath=false.", "Homebrew claude-code cask lags ~1 week behind latest, so teams pinning to it run older versions than expected.", "Installer run from / (e.g. Docker as root) scans the whole filesystem and hangs/uses excessive memory; set WORKDIR /tmp first.", "IDE extension processes may not inherit shell env, so cloud-provider credentials that work in the terminal fail in VS Code/JetBrains unless set in IDE settings.", "Installing the npm package with --ignore-scripts skips the postinstall link step and falls back to a slower per-launch wrapper rather than direct binary execution.", "Auto-compaction can succeed yet immediately thrash when a single oversized file/tool output refills the context; the fix is to chunk file reads or focus /compact, not to retry.", "On WSL with a project on the Windows filesystem (/mnt/c/), search silently returns fewer matches while /doctor still reports Search as OK — so /doctor will not flag this degradation.", "The bundled ripgrep may fail to run on some systems, silently breaking Search, @file mentions, custom agents, and custom skills (file discovery) — not just plain search.", "High CPU/memory may be caused by a plugin, MCP server, or hook; --safe-mode is needed to confirm before blaming the core tool.", "Integrated-terminal garbled text is a GPU-renderer issue, not a Claude Code bug; fixed via /terminal-setup or disabling gpuAcceleration.", "After a freeze, closing the terminal does not lose the conversation — but you must re-run `claude --resume` from the same directory to recover it.", "Auto mode is a research preview and relies on a classifier — it is not a guarantee; it can let through actions a human would have paused on, and it is distinct from (safer than) --dangerously-skip-permissions.", "Computer use is off by default and prompts before every action; it grants OS-level keyboard/mouse/screenshot control, so enabling it broadly is a meaningful trust expansion for a team.", "PR auto-fix runs unattended (watches CI and pushes until green) — review what it pushes; it acts on review comments and CI without per-step approval.", "Conditional hook \"if\" matching uses permission rule syntax, so a too-broad pattern will still fire the hook on more calls than intended; scope patterns precisely.", "MCP per-tool override is capped at 500K chars — you cannot keep arbitrarily large tool results inline; beyond the cap they still get truncated/persisted to disk.", "Thinking summaries are now OFF by default in interactive sessions; you must set `showThinkingSummaries: true` to see them — a silent behavior change.", "Flicker-free renderer is gated by an env var; rollback requires UNsetting `CLAUDE_CODE_NO_FLICKER` (the inverse of the usual enable pattern), which is easy to get backwards.", "Computer use in the CLI is a research preview with known rough edges — not production-stable for team-critical verification loops yet.", "Hook outputs over 50K chars silently move to disk (only a path + preview reach context), so downstream logic expecting full inline output may break.", "Default effort level silently changed to high for API-key, Bedrock, Vertex, Foundry, Team, and Enterprise users — this raises cost/latency unless you lower it with /effort.", "Ultraplan is a research preview and runs in the cloud (Claude Code on the web), not locally — plans are drafted remotely and reviewed in the browser.", "Without CLAUDE_CODE_PERFORCE_MODE, Edit/Write can silently overwrite read-only (Perforce) files; the mode must be explicitly enabled to get the fail-loud behavior.", "Bash permission prompting previously had gaps — backslash-escaped flags, env-var prefixes, /dev/tcp redirects, and compound commands were not prompting correctly before this hardening, meaning older versions could under-prompt on these.", "The OS CA cert store is now trusted by default, which changes TLS behavior; opt out with CLAUDE_CODE_CERT_STORE=bundled if that's undesirable.", "Switching to Opus 4.7 silently sets effort to 'xhigh' the first time — verify your effort level if you expected high or max.", "As of v2.1.113 the installed 'claude' no longer runs Node; it spawns a native per-platform binary pulled via an optional npm dependency (e.g. @anthropic-ai/claude-code-darwin-arm64). Environments that assumed a Node-based CLI or pinned the old bundle may break.", "Bash permission hardening can change behavior: deny rules now also match commands wrapped in env/sudo/watch, and 'Bash(find:*)' allow rules no longer auto-approve -exec/-delete — previously-allowed find invocations may now prompt.", "Auto mode is gated to Max subscribers on Opus 4.7; the old --enable-auto-mode flag is removed/no longer required, so scripts passing it are obsolete.", "Each routine exposes a tokened /fire endpoint — treat that token as a secret since it can trigger the agent externally.", "Focus view keybinding moved off Ctrl+O to a dedicated /focus command — old muscle memory/keybindings will not work.", "Replacing autoMode.allow/soft_deny/environment without including \"$defaults\" replaces the entire built-in rule list rather than appending — custom rules silently drop the defaults unless \"$defaults\" is present.", "/cost and /stats no longer exist as standalone commands; they are now shortcuts that open tabs within /usage.", "Forked subagents (full-context inheritance) are off by default on external builds — they require the CLAUDE_CODE_FORK_SUBAGENT=1 env var to enable.", "Before v2.1.114–119 fix, Opus 4.7 sessions mis-computed context against a smaller window, causing inflated /context percentages and premature autocompaction.", "Default effort level silently changed to `high` for Pro/Max on Opus 4.6 and Sonnet 4.6 — this affects cost and latency without explicit user action.", "On native macOS/Linux builds, Glob and Grep tools are gone (replaced by bfs/ugrep via Bash) — workflows or hooks that assume those tool names exist may need adjustment.", "`--dangerously-skip-permissions` now silently bypasses writes to sensitive paths (`.claude/`, `.git/`, `.vscode/`, shell config files) that were previously protected — a real risk for teams that relied on those prompts; only catastrophic removal commands still prompt.", "Gateway model discovery in the `/model` picker is OFF by default and requires both `ANTHROPIC_BASE_URL` pointing at an Anthropic-compatible gateway AND `CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1`.", "`alwaysLoad: true` keeps all of an MCP server's tools in context — overusing it across many servers can bloat the context window.", "`claude project purge` is destructive (deletes transcripts, tasks, file history, config entry); `--all` wipes every project — use `--dry-run` first.", "settings.autoMode.hard_deny overrides allow exceptions — a hard_deny match blocks unconditionally even if a broader allow rule would otherwise permit it.", "worktree.baseRef default `fresh` branches from the remote default branch, so local unpushed HEAD commits will NOT appear in new worktrees unless you set baseRef=head.", "Before this fix, parallel sessions could dead-end at a 401 after a refresh-token race, and concurrent MCP server OAuth refreshes could lose refresh tokens — upgrade if affected.", "OTEL-instrumented apps launched via the Bash tool previously inherited the CLI's own OTLP endpoint (OTEL_* vars); now fixed so subprocesses no longer inherit OTEL_*.", "Ctrl+R history search scope changed across versions: it searched all projects, then narrowed at v2.1.124, then reverted to all-projects at v2.1.129 (use Ctrl+S to re-narrow).", "Remote Control, `/schedule`, Claude.ai MCP connectors, and notification preferences silently become unavailable if any of `ANTHROPIC_API_KEY`, `apiKeyHelper`, or `ANTHROPIC_AUTH_TOKEN` is set — even when you are also logged into Claude.ai. You must unset the API key to use them.", "Fast mode costs more per token than standard Opus despite identical model quality; the win is speed (~2.5x), not price.", "Fast mode silently changed its default model (Opus 4.6 → 4.7); pin with `CLAUDE_CODE_OPUS_4_6_FAST_MODE_OVERRIDE=1` if your team depends on 4.6 behavior.", "Agent view and fast-mode-on-Opus-4.7 are research previews (behavior may change).", "/extra-usage was renamed to /usage-credits and 'extra usage' to 'usage credits' — the old command still works but docs/scripts referencing the old name may confuse teammates.", "'claude plugin disable' will refuse if another enabled plugin depends on the target; 'claude plugin enable' silently force-enables transitive dependencies (you may enable more than you intended).", "PowerShell tool is now ON by default on Windows for Bedrock/Vertex/Foundry users — set CLAUDE_CODE_USE_POWERSHELL_TOOL=0 to opt out if undesired.", "auto mode only appears after the account 'meets requirements' — it won't show up immediately for all Pro users.", "Opus 4.8 requires v2.1.154+; on older clients it is unavailable.", "Opus 4.6 fast mode is deprecated; Opus 4.7/4.6 fast mode stays at the old $30/$150 rate while 4.8 fast mode is $10/$50.", "Fast mode is not free speed — it costs 2x the standard token rate.", "Previously, piping `claude mcp list`/`claude mcp get` output could auto-approve and connect unapproved .mcp.json servers; this now correctly shows them as pending approval (a prior silent-trust pitfall now fixed).", "Skills installed by a SessionStart hook are not available mid-session unless the hook returns reloadSkills: true (or you run /reload-skills).", "Even in acceptEdits mode, writes to protected paths (.zshenv, .bash_login, ~/.config/git/, .npmrc, .bazelrc, .pre-commit-config.yaml) now pause for a prompt — only bypassPermissions auto-approves them. Automation expecting silent acceptEdits writes to these files will now block.", "A managed requiredMinimumVersion/requiredMaximumVersion mismatch causes the client to exit at startup; users must update through the org's distribution method (auto-update may not apply).", "The dynamic-workflows keyword silently changed: 'workflow' no longer triggers it — use 'ultracode' (or natural language).", "Previously, listing Grep/Glob in --tools on native embedded-search builds was silently ignored; behavior changed to actually provide them.", "Autocomplete behavior changed: clicking a command now only fills it rather than running it — you must press Enter (could surprise muscle memory).", "/cd appends the new directory's CLAUDE.md as a message rather than replacing the system prompt — the original directory's CLAUDE.md/system prompt context persists, so accumulated instructions may stack rather than swap.", "Nested subagent trees are hard-capped at five levels deep; deeper spawning is prevented (intentional guard against runaway concurrent trees).", "In safe mode, permissions still apply — it disables customizations but is not a permission bypass.", "Deny rules previously may have silently ignored unknown/misspelled tool names; they now warn at startup, implying earlier configs could have had non-functioning deny rules without notice.", "availableModels allowlist did NOT constrain the Default model unless enforceAvailableModels is set — a model thought to be blocked could still be reachable as the Default.", "`acceptEdits` mode previously wrote code-executing files silently; only as of Week 23 does 'safer automatic edits' prompt before writing files that can run code — older versions auto-write them.", "Auto mode availability is plan/provider-gated: Pro (Week 21), and Bedrock/Vertex/Foundry only for Opus 4.7/4.8 (Week 23) — not uniformly available everywhere.", "Background subagent chains are hard-capped at five levels deep — deep recursive orchestration silently bottoms out.", "Background sessions only stay alive if pinned; otherwise they may not persist in `/resume`.", "Auto mode allow exceptions do NOT override hard deny rules — denies always win.", "Fast mode pricing ($10/$50 per MTok on Opus 4.8) is materially higher than bulk/cheap models — don't default agentic loops to it.", "This page is a digest of headline features only; for every bug fix and minor change you must consult the separate changelog (/en/changelog)."], "claims": ["Team/Enterprise analytics dashboard is at claude.ai/analytics/claude-code; API/Console dashboard is at platform.claude.com/claude-code.", "Only Admins and Owners can view the Team/Enterprise analytics dashboard.", "API/Console dashboard requires the UsageView permission, granted to Developer, Billing, Admin, Owner, and Primary Owner roles.", "Configuring analytics settings requires the Owner role; a GitHub admin must install the GitHub app at github.com/apps/claude.", "Enabling contribution metrics: GitHub admin installs Claude GitHub app -> Owner enables Claude Code analytics at claude.ai/admin-settings/claude-code -> enable 'GitHub analytics' toggle -> authenticate with GitHub and select orgs.", "Contribution metrics are in public beta, only on Claude for Teams and Enterprise, and only cover users within your claude.ai org; Console API or third-party integration usage is not included.", "Contribution metrics are NOT available for orgs with Zero Data Retention enabled; only usage metrics show in that case.", "Contribution data typically appears within 24 hours after enabling, with daily updates.", "Contribution metrics support both GitHub Cloud and GitHub Enterprise Server.", "PR attribution time window: sessions from 21 days before to 2 days after the PR merge date are considered for matching.", "Code substantially rewritten by developers (more than 20% difference) is not attributed to Claude Code.", "'Effective lines' counted = lines with more than 3 characters after normalization, excluding empty lines and lines with only brackets/trivial punctuation.", "Attribution normalizes lines before comparison: trims whitespace, collapses multiple spaces, standardizes quotes, lowercases text.", "Excluded-from-analysis files: lock files (package-lock.json, yarn.lock, Cargo.lock), generated code (protobuf, build artifacts, minified), build dirs (dist/, build/, node_modules/, target/), test fixtures (snapshots, cassettes, mock data), and any line over 1,000 characters.", "Merged PRs containing Claude Code-assisted lines are labeled 'claude-code-assisted' in GitHub; you can query attribution programmatically by searching GitHub for PRs with that label.", "Attribution does not consider the PR source or destination branch.", "Summary metrics: PRs with CC, Lines of code with CC, PRs with Claude Code (%), Suggestion accept rate, Lines of code accepted.", "Suggestion accept rate = percentage of times users accept code editing tool usage, including Edit, Write, and NotebookEdit tools.", "Lines of code accepted excludes rejected suggestions and does not track subsequent deletions.", "Leaderboard shows top 10 users; 'Export all users' downloads complete contribution data for ALL users as CSV, not just the top 10.", "For per-user token counts and cost estimates, configure OpenTelemetry export (/en/monitoring-usage); the Team/Enterprise dashboard does not provide them natively.", "Console dashboard team insights: Members (API key users by key identifier, OAuth users by email), Spend this month (per-user), Lines this month (per-user).", "Console Spend figures are estimates for analytics purposes only; actual costs are on the billing page.", "Contribution metrics with GitHub integration are not currently available for API/Console customers (usage and spend only).", "Contribution metrics and GitHub integration are gated to Claude for Teams and Claude for Enterprise plans only.", "Managed setting enforceAvailableModels, when enabled, constrains the Default model to the availableModels allowlist; user/project settings cannot widen it (falls back to first allowed model).", "Managed settings requiredMinimumVersion / requiredMaximumVersion refuse to start Claude Code outside the approved version range.", "Managed settings forceLoginOrgUUID / forceLoginMethod pin the login method/org and block third-party providers (Bedrock, Vertex, Foundry, Mantle).", "Managed setting pluginSuggestionMarketplaces allowlists org marketplaces for context-aware plugin suggestions.", "Setting allowAllClaudeAiMcps loads claude.ai cloud MCP connectors alongside managed-mcp.json.", "CLI commands claude mcp login <name> and claude mcp logout <name> authenticate MCP servers without the interactive /mcp menu; use --no-browser for SSH/headless.", "--strict-mcp-config blocks inline mcpServers in agent definitions and enforces managed MCP policies on subagent spawn; it also blocks non-MCP globs in deny rules.", "Enterprise managed MCP allowlist/denylist keys are allowedMcpServers and deniedMcpServers; they enforce on reconnect, IDE configs, and first session, and load before remote settings.", "Permission deny rules accept glob patterns: \"*\" denies all tools; allow rules reject non-MCP globs.", "Env var MCP_TOOL_TIMEOUT sets per-request fetch timeout for remote HTTP/SSE MCP servers (previously capped at 60s). MCP timeout values under 1000ms are ignored and fall back to MCP_TOOL_TIMEOUT or default; claude mcp get annotates such values.", "Stdio MCP servers receive env vars CLAUDE_CODE_SESSION_ID and CLAUDECODE=1 (including on --resume).", "Permission rules support Tool(param:value) syntax matching tool input parameters with a * wildcard; e.g. Agent(model:opus) blocks Opus subagents.", "acceptEdits mode now prompts before writing build-tool config that grants code execution: .npmrc, .yarnrc*, bunfig.toml, .bazelrc, .pre-commit-config.yaml, .devcontainer/. It also prompts before writing shell startup files: .zshenv, .zlogin, .bash_login, ~/.config/git/.", "Auto mode blocks destructive commands unless explicitly requested: git reset --hard, git checkout -- ., git clean -fd, git stash drop, git commit --amend (unless agent made it this session), and terraform/pulumi/cdk destroy (unless a specific stack was named).", "Setting disableBundledSkills and env var CLAUDE_CODE_DISABLE_BUNDLED_SKILLS hide bundled skills, workflows, and built-in slash commands.", "Nested .claude/skills directories auto-load; on name collision they are qualified as <dir>:<name>, and the closest .claude/ wins on multi-level nesting (agent/workflow/output-style).", "Skill/SKILL.md frontmatter keys accept kebab-case, snake_case, and camelCase (e.g. display-name, default-enabled, fallback, metadata.*). Malformed SKILL.md YAML loads the body with empty metadata rather than failing.", "SessionStart hook can set the session title via hookSpecificOutput.sessionTitle and re-scan skill directories mid-session by returning reloadSkills: true.", "Stop and SubagentStop hooks can return hookSpecificOutput.additionalContext to feed Claude and keep the turn going; a new MessageDisplay hook can transform or hide displayed assistant text.", "Skill/slash-command frontmatter disallowed-tools removes tools from the model while the skill is active.", "claude plugin disable refuses if another enabled plugin depends on the target; enable force-enables transitive dependencies.", "Env var CLAUDE_CODE_PLUGIN_PREFER_HTTPS clones GitHub plugin sources over HTTPS (no SSH key required). /plugin list supports --enabled / --disabled filters.", "Subagents can spawn up to 5 levels deep (foreground and background).", "CLAUDE_CODE_SUBAGENT_MODEL applies to teammate processes (tmux/pane backends). Agent(type) deny rules and Agent(x,y) allowed-types are enforced for named subagent spawns.", "Setting fallbackModel accepts up to 3 models tried in order on overload/unavailability; --fallback-model applies to both interactive and non-interactive runs and is respected by context compaction.", "/usage breakdown shows per-category costs for skills, subagents, plugins, and MCP servers.", "Setting respondToBashCommands: false in settings.json keeps ! bash command output as context-only (default is now that ! commands trigger an automatic Claude response).", "/cd moves the session to a new directory without breaking the prompt cache mid-session.", "claude agents --json lists live sessions as JSON for scripting (includes id, state, and waitingFor fields); --all includes completed sessions.", "Background sessions: claude --bg --exec '<command>' runs a shell command as a background session; claude --bg --dangerously-skip-permissions persists across retire/wake.", "worktree.bgIsolation: \"none\" lets background sessions edit the working copy directly (skip EnterWorktree); worktree.baseRef: \"head\" resolves to the current worktree HEAD.", "Read tool returns a truncated first page with a PARTIAL view notice instead of a hard error when a whole-file read exceeds the token limit.", "CLAUDE_CODE_MAX_RETRIES is capped at 15; for unattended sessions use CLAUDE_CODE_RETRY_WATCHDOG instead.", "Auto mode for third-party providers (Bedrock, Vertex, Foundry) is opt-in via CLAUDE_CODE_ENABLE_AUTO_MODE=1.", "Cross-session messages relayed via SendMessage no longer carry user authority; receivers refuse relayed permission requests and auto mode blocks them.", "Thinking can be disabled on models that think by default via MAX_THINKING_TOKENS=0, --thinking disabled, or a per-model toggle (Claude API only; third-party providers unchanged).", "Vertex/Foundry have a default 5-minute idle timeout that aborts a stalled stream; opt out with API_FORCE_IDLE_TIMEOUT=0.", "The /model picker shows the model family the Default resolves to per plan: Opus on Max/Team Premium/Enterprise and pay-as-you-go; Sonnet on Pro/Team.", "These changelog entries span versions roughly 2.1.141 through 2.1.186; version numbers and exact behaviors are subject to change in later releases.", "Claude Code retries transient failures (5xx, 529 overloaded, request timeouts, temporary 429 throttles, dropped connections) up to 10 times by default with exponential backoff before showing an error; spinner shows 'Retrying in Ns · attempt x/y'.", "CLAUDE_CODE_MAX_RETRIES (default 10) sets retry attempts; capped at 15 as of v2.1.186. Lower it to surface failures faster in scripts.", "CLAUDE_CODE_RETRY_WATCHDOG=1 (default unset) makes unattended sessions (CI) retry 429 and 529 capacity errors indefinitely instead of failing after CLAUDE_CODE_MAX_RETRIES.", "API_TIMEOUT_MS (default 600000 ms = 10 min) is the per-request timeout; raise for slow networks/proxies.", "As of v2.1.185, if no data arrives on the response stream for 20 seconds while a request is pending, the spinner shows 'Waiting for API response · will retry in …'; earlier versions used a 10-second threshold.", "529 Overloaded and 'Server is temporarily limiting requests' are NOT your usage limit and do not count against quota; capacity is tracked per model, so '/model' to switch models keeps you working.", "Run '/status' to see which credential is active; a stray ANTHROPIC_API_KEY in the environment can route requests through a low-tier key instead of your subscription, causing 429s.", "Reduce concurrency for 429s by lowering CLAUDE_CODE_MAX_TOOL_USE_CONCURRENCY, avoiding many parallel subagents, or switching to a smaller model via /model for high-volume scripted runs.", "Authentication precedence: environment variables (ANTHROPIC_API_KEY) and apiKeyHelper take precedence over /login; in non-interactive mode (-p) an ANTHROPIC_API_KEY is always used when present. Running /login alone does not help while an env var or apiKeyHelper still supplies a key.", "For CI/automation where interactive login is impossible, configure an apiKeyHelper script in settings.json that fetches a key at startup; or set CLAUDE_CODE_OAUTH_TOKEN in the worker's environment.", "'Your organization has disabled Claude subscription access' is a server-side org setting that cannot be overridden by local settings, env vars, or CLI flags; SDK/-p surface it as oauth_org_not_allowed.", "'Routines are disabled by your organization's policy' is a Team/Enterprise server-side setting; admins toggle Routines at claude.ai/admin-settings/claude-code. Cannot be overridden locally.", "SSL/TLS interception by corporate proxy: point Claude Code at the CA bundle with NODE_EXTRA_CA_CERTS=/path/to/ca-bundle.pem. Do NOT set NODE_TLS_REJECT_UNAUTHORIZED=0 (disables cert validation entirely).", "Corporate proxy: set HTTPS_PROXY before launching; for an LLM gateway/relay set ANTHROPIC_BASE_URL to its address. Verify reachability with 'curl -I https://api.anthropic.com' (Windows: 'curl.exe -I').", "Cloud sessions and routines run sandboxed with outbound traffic filtered to an allowlist; 403 with 'x-deny-reason: host_not_allowed' means a host is blocked. Default environment uses 'Trusted' access (default allowlist of package registries, cloud APIs, container registries, dev domains). Change Network access to Custom (per-domain, one per line) or Full. Local CLI sessions are unaffected.", "'Prompt is too long' = context window full. Recover with /compact (summarize) or /clear; /context shows breakdown (system prompt, tools, memory files, messages). Disable unused MCP servers with '/mcp disable <name>' to remove their tool definitions from context.", "Subagents inherit every MCP tool definition from the parent session, which can fill their context window before the first turn; disable unused MCP servers before spawning subagents.", "Auto-compact is on by default and normally prevents 'Prompt is too long'; DISABLE_AUTO_COMPACT turns it off.", "Request body byte limit is 30 MB ('Request too large (max 30 MB)'), separate from the context window limit; reference large files by path instead of pasting.", "PDF limits: max 100 pages, 32 MB; password-protected and invalid PDFs are rejected. Image limits: up to 8000px on longest edge for a single image, 2000px when many images are in context.", "LLM gateways that strip the anthropic-beta header cause 'Extra inputs are not permitted' (context_management, effort, tools input_examples). Fix: forward the anthropic-beta header, or set CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1.", "Model selection precedence (to clear a stale model ID): --model flag > ANTHROPIC_MODEL env var > model field in .claude/settings.local.json > project .claude/settings.json > ~/.claude/settings.json. Prefer aliases (sonnet, opus) over versioned IDs so they don't go stale.", "CLAUDE_CODE_DISABLE_1M_CONTEXT=1 removes 1M-context [1m] model variants from the model picker. 1M context may require usage credits depending on plan ('/usage-credits').", "Bedrock/Vertex 'max_tokens must be greater than thinking.budget_tokens': lower MAX_THINKING_TOKENS or raise CLAUDE_CODE_MAX_OUTPUT_TOKENS above the thinking budget.", "Tool-use/thinking-block mismatch (API Error 400 tool use concurrency / unexpected tool_use_id): run /rewind or press Esc twice to a checkpoint before the corrupted turn.", "Usage Policy refusal evaluates the full conversation, not just the latest prompt; --continue/--resume re-triggers it because the on-disk transcript still contains the triggering content. Recover via /rewind or /clear.", "Diagnostic commands: /status (active credential), /doctor (local config problems, flags oversized memory files and subagent definitions), /context (window breakdown + MCP tool token usage), /usage and /usage-credits (plan limits/credits), /effort (reasoning level), /feedback (send transcript to Anthropic, offers prefilled GitHub issue).", "Run 'claude --debug' (or claude with --debug) to see underlying classifier responses in the debug log when auto mode blocks an action with 'run with --debug for details'.", "Auto mode classifier exceeding its context window: in non-interactive mode the run aborts (transcript only grows); in interactive mode it falls back to a manual permission prompt. Run /compact to fit subsequent actions within the classifier window.", "Opus 4.7 requires Claude Code v2.1.111+; Opus 4.8 requires v2.1.154+; versions before v2.1.156 can trigger tool-use mismatch errors during normal tool use that /rewind cannot clear.", "Telemetry requires CLAUDE_CODE_ENABLE_TELEMETRY=1. Exporters chosen via OTEL_METRICS_EXPORTER (otlp|prometheus|console|none) and OTEL_LOGS_EXPORTER (otlp|console|none), comma-separated for multiple.", "Default export intervals: metrics OTEL_METRIC_EXPORT_INTERVAL=60000ms, logs OTEL_LOGS_EXPORT_INTERVAL=5000ms, traces OTEL_TRACES_EXPORT_INTERVAL=5000ms.", "Administrators configure telemetry for all users via the managed settings file `env` block; env vars there have high precedence and cannot be overridden by users; distributable via MDM.", "Claude Code does NOT pass OTEL_* env vars to subprocesses it spawns (Bash tool, hooks, MCP servers, language servers); set them directly in the command if a subprocess app needs its own telemetry.", "OTEL_LOG_USER_PROMPTS=1 enables logging user prompt content (default disabled; only prompt length recorded otherwise).", "OTEL_LOG_TOOL_DETAILS=1 enables logging tool parameters/input args (Bash commands, MCP server/tool names, skill names, tool input) on events and span attributes; default disabled. Data goes only to your OTEL endpoint, never to Anthropic.", "OTEL_LOG_TOOL_CONTENT=1 logs tool input/output content in span events; requires tracing; content truncated at 60 KB; default disabled.", "OTEL_LOG_RAW_API_BODIES emits full Messages API request/response JSON as api_request_body/api_response_body events. =1 inlines truncated at 60 KB; =file:<dir> writes untruncated bodies to disk with a body_ref pointer. Bodies include full conversation history; extended-thinking content always redacted.", "Metrics cardinality toggles: OTEL_METRICS_INCLUDE_SESSION_ID (default true), OTEL_METRICS_INCLUDE_ACCOUNT_UUID (default true), OTEL_METRICS_INCLUDE_RESOURCE_ATTRIBUTES (default true), OTEL_METRICS_INCLUDE_VERSION (default false), OTEL_METRICS_INCLUDE_ENTRYPOINT (default false).", "Exported metrics: claude_code.session.count, claude_code.lines_of_code.count, claude_code.pull_request.count, claude_code.commit.count, claude_code.cost.usage (USD), claude_code.token.usage (tokens), claude_code.code_edit_tool.decision, claude_code.active_time.total (s).", "Cost metrics are approximations; for official billing refer to Claude Console, Amazon Bedrock, or Google Cloud Vertex.", "model attribute is on claude_code.token.usage and claude_code.cost.usage; on claude_code.lines_of_code.count only from Claude Code v2.1.172+.", "Tracing (beta) is off by default; requires CLAUDE_CODE_ENABLE_TELEMETRY=1 AND CLAUDE_CODE_ENHANCED_TELEMETRY_BETA=1 plus OTEL_TRACES_EXPORTER. Span tree: claude_code.interaction > claude_code.llm_request / claude_code.hook / claude_code.tool (with blocked_on_user + execution children).", "When tracing is active, Bash/PowerShell subprocesses inherit a TRACEPARENT env var (W3C trace context). With a custom ANTHROPIC_BASE_URL proxy, traceparent propagation requires CLAUDE_CODE_PROPAGATE_TRACEPARENT=1.", "claude_code.hook span (and detailed content attributes) require ENABLE_BETA_TRACING_DETAILED=1 and BETA_TRACING_ENDPOINT; interactive CLI also needs org allowlisting, but Agent SDK and -p sessions are not gated.", "OTEL_RESOURCE_ATTRIBUTES forbids spaces and quotes don't escape them; format is comma-separated key=value; special chars must be percent-encoded. Custom keys never override standard attributes on collision (built-in value wins).", "CLAUDE_CODE_MAX_RETRIES default is 10, capped at 15; attempt > MAX_RETRIES on api_error indicates retry exhaustion.", "Standard attributes include organization.id, user.account_uuid, user.account_id, user.email (OAuth only), user.id (anonymous, persisted in ~/.claude.json), session.id, terminal.type. user.email is included when OAuth-authenticated.", "tool_decision event source values: config, hook, user_permanent, user_temporary, user_abort, user_reject. In interactive CLI, later rule-matched calls report 'config'; in Agent SDK / -p sessions they report the original source.", "Audit events for security: tool_decision, permission_mode_changed, hook_execution_complete, auth, mcp_server_connection, plugin_installed/plugin_loaded, tool_result. Claude Code emits raw events only; anomaly detection/alerting is the SIEM's responsibility.", "internal_error events are not emitted on Bedrock/Vertex/Foundry or when DISABLE_ERROR_REPORTING is set; only error class name + errno code recorded (no message/stack).", "Resource attributes on all exports: service.name=claude-code, service.version, os.type, os.version, host.arch, wsl.version (WSL only). Meter Name: com.anthropic.claude_code.", "Third-party plugin/skill names are redacted (to 'third-party' or 'custom') in events/metrics unless OTEL_LOG_TOOL_DETAILS=1; official-marketplace plugin names appear verbatim. plugin_id_hash allows counting distinct plugins without names and is sent only to your exporter, not Anthropic.", "OTEL_LOG_TOOL_DETAILS=1 tool_input attribute truncates individual values over 512 chars and bounds the total payload to ~4K characters.", "mTLS: for http/protobuf|http/json use CLAUDE_CODE_CLIENT_CERT/CLAUDE_CODE_CLIENT_KEY (+optional passphrase) and NODE_EXTRA_CA_CERTS; for grpc use OTEL_EXPORTER_OTLP_CLIENT_KEY/CERTIFICATE and OTEL_EXPORTER_OTLP_CERTIFICATE.", "Tracing/enhanced telemetry is a beta feature (CLAUDE_CODE_ENHANCED_TELEMETRY_BETA / detailed hook tracing gated behind org allowlist for interactive CLI).", "Native installer places the binary at ~/.local/bin/claude on macOS/Linux and %USERPROFILE%\\.local\\bin\\claude.exe on Windows; the native install is the recommended one over npm/Homebrew/WinGet.", "Three places a claude binary can come from on macOS/Linux: ~/.local/bin/claude (native installer), ~/.claude/local/ (legacy local npm install from older versions), and an npm -g global install. Multiple installs cause version mismatches; keep only the native one.", "which -a claude lists all claude binaries on PATH; npm -g ls @anthropic-ai/claude-code shows a global npm install. Remove extras with npm uninstall -g @anthropic-ai/claude-code, rm -rf ~/.claude/local, brew uninstall --cask claude-code, or winget uninstall Anthropic.ClaudeCode.", "The VS Code extension bundles a private copy of the CLI inside the extension directory and does NOT add claude to PATH; if only the extension is installed, ~/.local/bin/claude will not exist. Run the standalone install to get a terminal claude.", "Corporate proxy: set HTTP_PROXY and HTTPS_PROXY before installing. For Claude Code API requests through a corporate CA, set NODE_EXTRA_CA_CERTS=/path/to/corporate-ca.pem. For the install curl behind TLS-inspecting proxy, use curl --cacert /path/to/corporate-ca.pem.", "On Windows, set Git Bash path in settings.json env: {\"CLAUDE_CODE_GIT_BASH_PATH\": \"C:\\\\Program Files\\\\Git\\\\bin\\\\bash.exe\"}. Claude Code uses the PowerShell tool when Git Bash is absent; Git Bash enables the Bash tool.", "Authentication precedence: when ANTHROPIC_API_KEY is set (and approved), Claude Code uses that key instead of subscription OAuth credentials; in non-interactive mode with -p the key is always used when present. A stale ANTHROPIC_API_KEY can cause 'This organization has been disabled' despite an active subscription. Unset it and remove from shell profile to use the subscription.", "Run /status inside Claude Code to confirm which authentication method is active. Run claude doctor for an automated diagnostic report (also checks macOS Keychain access).", "Anthropic Console users need the 'Claude Code' or 'Developer' role to use Claude Code; admins assign this in the Anthropic Console under Settings -> Members. Pro/Max users need an active subscription. Missing role yields API Error 403 forbidden after login.", "Native binary delivered only as an optional npm dependency (e.g. @anthropic-ai/claude-code-darwin-arm64); do not use --omit=optional/--no-optional/--ignore-optional or optional=false in .npmrc. Prebuilt platforms: darwin-arm64, darwin-x64, linux-x64, linux-arm64, linux-x64-musl, linux-arm64-musl, win32-x64, win32-arm64.", "Corporate npm mirrors must mirror all eight @anthropic-ai/claude-code-* platform packages plus the meta package, or claude reports 'Could not find native binary package'.", "Claude Code requires at least 4 GB of available RAM (install can be OOM-killed on low-memory Linux). Requires a 64-bit OS and macOS 13.0+; pre-2013 CPUs lacking AVX cannot run the native binary (no workaround).", "The Homebrew claude-code cask tracks the stable channel and is typically ~1 week behind latest; use brew install --cask claude-code@latest for the newest version. See /en/setup#configure-release-channel.", "In IDE extensions (VS Code/JetBrains), the IDE process may not inherit shell environment, so Bedrock/Vertex/Foundry env vars (e.g. ANTHROPIC_VERTEX_PROJECT_ID, CLOUD_ML_REGION, ANTHROPIC_FOUNDRY_API_KEY) must be set in the IDE's own settings or the IDE launched from a terminal where they are exported.", "claude auth login reads a pasted OAuth code from standard input, a fallback for remote/SSH/WSL2/container sessions where the interactive paste prompt fails. In WSL2 set BROWSER to the Windows browser path if the browser doesn't open.", "Claude Code v2.1.116+ checks the Git Bash filesystem path directly instead of spawning cmd.exe; earlier versions spawned cmd.exe which AppLocker/Group Policy/EDR could block, causing 'requires Git for Windows or PowerShell' errors.", "Run /doctor inside Claude Code for an automated check of installation, settings, MCP servers, and context usage; if claude won't start, run `claude doctor` from the shell.", "`claude --safe-mode` disables all customizations (plugins, MCP servers, hooks) for the session to isolate the source of high resource usage.", "/heapdump writes a JS heap snapshot and memory breakdown to ~/Desktop (or the home directory on Linux without a Desktop folder). The .heapsnapshot can be opened in Chrome DevTools under Memory -> Load.", "Error `Autocompact is thrashing: the context refilled to the limit...` means auto-compaction succeeded but a file/tool output immediately refilled the context several times; Claude Code stops retrying to avoid wasting API calls.", "`claude --resume` in the same directory restores a session after a hang/restart; restarting does not lose the conversation.", "Setting USE_BUILTIN_RIPGREP=0 in the environment tells Claude Code to use a system-installed ripgrep instead of the bundled binary.", "On WSL across filesystems, search returns fewer-than-expected matches but /doctor still reports Search as OK.", "/terminal-setup sets terminal.integrated.gpuAcceleration to 'off' to fix garbled text in VS Code/Cursor/Devin Desktop integrated terminals.", "Configuration debugging guidance lives at /en/debug-your-config including 'test against a clean configuration' for isolating which plugin/MCP/hook causes issues.", "/feedback reports problems directly to Anthropic from within Claude Code.", "Auto mode (research preview, v2.1.83–v2.1.85 window) routes permission prompts to a classifier: safe edits/commands run uninterrupted, destructive/suspicious actions are blocked and surfaced. It is the middle ground between approving every write and running with --dangerously-skip-permissions.", "Cycle to auto mode with Shift+Tab, or set it as default in ~/.claude/settings.json via {\"permissions\": {\"defaultMode\": \"auto\"}}.", "Computer use (Desktop app) lets Claude control the actual desktop (open native apps, drive iOS simulator, hardware control panels, verify on screen). It is OFF by default and asks before each action; enabled in Settings after granting OS permissions.", "PR auto-fix (Web, Claude Code on the web): toggling Auto fix in the CI panel after creating a PR makes Claude watch CI, fix failures and review nits, and push until green. Description reads 'Proactively fix CI failures and review comments'.", "Transcript search (v2.1.83): in transcript/fullscreen mode (open via Ctrl+O), press / to search the conversation; n steps to next match, N to previous match.", "PowerShell tool (preview, v2.1.84) for Windows runs alongside Bash; opt in via .claude/settings.json env var {\"env\": {\"CLAUDE_CODE_USE_POWERSHELL_TOOL\": \"1\"}}. Lets Claude run cmdlets and Windows-native paths without Git Bash translation.", "Conditional hooks (v2.1.85): a hook entry can declare an \"if\" field using permission rule syntax (e.g. \"if\": \"Bash(git commit *)\") so the hook only spawns for matching tool calls instead of every Bash call, reducing process overhead.", "Plugin userConfig is now public: plugins can prompt for settings at enable time, with keychain-backed secrets.", "managed-settings.d/ is a new drop-in directory for layered managed-policy fragments (composable enterprise policy).", "New hook events CwdChanged and FileChanged were added (intended for direnv-style setups).", "Agents can declare initialPrompt in frontmatter to auto-submit a first turn.", "Pasted images insert [Image #N] chips that can be referenced positionally.", "After 75+ minutes idle, Claude Code nudges you to /clear (idle-return reminder).", "/status now works while Claude is responding; Ctrl+X Ctrl+E opens the external editor (readline-matching); interrupting before any response restores your input automatically.", "This digest covers releases v2.1.83 through v2.1.85 (Week 13, March 23–27, 2026).", "MCP server authors can raise a per-tool truncation cap by setting `anthropic/maxResultSizeChars` in the tool's `_meta` field of the `tools/list` response, up to a hard ceiling of 500K characters.", "Without a per-tool override, MCP results exceeding the global cap are truncated and persisted to disk with a file reference instead of staying inline.", "Placing an executable in a `bin/` directory at a plugin root adds that directory to the Bash tool's PATH while the plugin is enabled, letting Claude invoke the binary as a bare command (no absolute path).", "Plugin layout: `bin/` sits at the plugin root alongside `.claude-plugin/plugin.json`.", "The `disableSkillShellExecution` setting blocks inline shell execution from skills, slash commands, and plugin commands.", "Hook output over 50K characters is saved to disk with a path + preview instead of being injected into context.", "Thinking summaries are off by default in interactive sessions; set `showThinkingSummaries: true` to restore them.", "A new `PermissionDenied` hook fires on auto-mode classifier denials; returning `retry: true` lets Claude try a different approach. `/permissions` → Recent allows manual retry with `r`.", "`PreToolUse` hooks support a new `defer` value for `permissionDecision`; in `-p` (non-interactive) sessions this pauses at the tool call and exits with a `deferred_tool_use` payload, resumable with `--resume`.", "Flicker-free alt-screen renderer with virtualized scrollback (v2.1.89) is opt-in via env var; unset `CLAUDE_CODE_NO_FLICKER` to roll back. Docs show `export CLAUDE_CODE_NO_FLICKER=1` then `claude` to enable.", "Computer use in the CLI (research preview, v2.1.86–91) is enabled via `/mcp` → find `computer-use` → toggle on; lets Claude drive native GUI apps (iOS simulator, macOS) end-to-end.", "The Edit tool now works on files viewed via `cat` or `sed -n` without a separate Read call first.", "`/powerup` (v2.1.90) runs interactive in-terminal lessons teaching Claude Code features via animated demos.", "`claude-cli://` deep links accept multi-line prompts when newlines are encoded as `%0A`.", "Computer use in the CLI is a research preview and explicitly flagged as early with rough edges.", "Week 15 (April 6–10, 2026) covers releases v2.1.92 through v2.1.101.", "/ultraplan runs plan mode in the cloud; you can also trigger it by including the keyword in any prompt. As of v2.1.101 the first run auto-creates a default cloud environment (no web setup step needed).", "The Monitor tool (v2.1.98) spawns a background watcher and streams each event into the conversation as a new transcript message; it pairs with /loop and avoids Bash sleep loops.", "/loop with the interval omitted self-paces — Claude schedules the next tick or uses the Monitor tool instead of polling.", "/autofix-pr infers the open PR for the current branch and enables auto-fix on Claude Code on the web in one command; run it from the PR's branch.", "/team-onboarding (v2.1.101) generates a teammate ramp-up guide from your local Claude Code usage; run it in a project you've spent real time in.", "Default effort level is now high for API-key, Bedrock, Vertex, Foundry, Team, and Enterprise users; control it with /effort.", "/cost shows a per-model and cache-hit breakdown for subscription users.", "Ctrl+O in flicker-free mode collapses the view (Focus view) to the last prompt, a one-line tool summary with diffstats, and Claude's final response.", "/agents has a tabbed layout: a Running tab shows live subagents with a '● N running' count, plus Run agent and View running instance actions in the Library tab.", "Status line gains a refreshInterval setting that re-runs the command every N seconds, and a workspace.git_worktree field in the JSON input.", "Setting CLAUDE_CODE_PERFORCE_MODE makes Edit/Write fail on read-only files with a 'p4 edit' hint instead of silently overwriting.", "The OS CA certificate store is now trusted by default so enterprise TLS proxies work without extra setup; set CLAUDE_CODE_CERT_STORE=bundled to opt out.", "Amazon Bedrock powered by Mantle is enabled by setting CLAUDE_CODE_USE_MANTLE=1.", "Bash tool permissions were hardened so backslash-escaped flags, env-var prefixes, /dev/tcp redirects, and compound commands now prompt correctly.", "UserPromptSubmit hooks can set the session title via hookSpecificOutput.sessionTitle.", "Login screen offers guided Bedrock and Vertex AI setup wizards: pick '3rd-party platform' for step-by-step auth, region, credential check, and model pinning.", "/release-notes is now an interactive version picker.", "Claude Opus 4.7 is the default model on Max and Team Premium; available elsewhere via /model.", "Opus 4.7 adds an 'xhigh' effort level sitting between 'high' and 'max'; xhigh is applied as the default the first time you switch to 4.7.", "/effort with no arguments opens an interactive arrow-key slider to dial intelligence vs speed.", "Effort/model can be set via '/model opus' then '/effort xhigh'.", "Routines are templated cloud agents that fire on a schedule, a GitHub event, or an API call; defined on Claude Code on the web with a prompt, allowed repos, and connectors. Triggers include PR-opened, release-published, and webhooks. Every routine gets a tokened /fire endpoint for external systems.", "'/schedule daily PR review at 9am' scaffolds a routine from the terminal.", "/usage now breaks down what drives limits: parallel sessions, subagents, cache misses, and long context — each shown as a percentage of the last 24 hours with an optimization tip. Press 'd' or 'w' to switch between day and week views.", "With Remote Control connected, Claude can send a mobile push notification when a long task finishes or it needs a decision. Enable via 'Push when Claude decides' in /config, or request it in-prompt.", "As of v2.1.113, the 'claude' CLI spawns a native per-platform binary instead of bundled JavaScript; the installed 'claude' command no longer invokes Node. npm pulls the binary via an optional dependency such as @anthropic-ai/claude-code-darwin-arm64. Install command unchanged.", "/ultrareview runs comprehensive code review in the cloud using parallel multi-agent analysis plus an adversarial critique pass. Bare = review current branch; '/ultrareview <PR#>' = review a specific PR.", "Auto mode is now available for Max subscribers on Opus 4.7, and the --enable-auto-mode flag is no longer required.", "Session recap shows a one-line summary of what happened while you were away; run /recap on demand or disable from /config.", "New /tui command and 'tui' setting switch between classic and flicker-free rendering mid-conversation. Focus view moved from Ctrl+O to its own /focus command.", "Plugins can ship background watchers via a top-level 'monitors' manifest key that auto-arms at session start or on skill invoke.", "/theme has an 'Auto (match terminal)' option that follows the terminal's dark/light mode.", "/fewer-permission-prompts scans transcripts for common read-only Bash and MCP calls and proposes an allowlist for .claude/settings.json.", "Claude can discover and run built-in commands like /init, /review, and /security-review via the Skill tool.", "PreCompact hooks can block compaction by exiting with code 2 or returning {\"decision\":\"block\"}.", "Setting ENABLE_PROMPT_CACHING_1H opts API key, Bedrock, Vertex, and Foundry users into a 1-hour prompt cache TTL.", "The sandbox.network.deniedDomains setting carves specific domains out of a broader sandbox.network.allowedDomains wildcard.", "/undo is now an alias for /rewind; /proactive is an alias for /loop.", "Hardened Bash permissions: deny rules now match through env/sudo/watch wrappers, and 'Bash(find:*)' allow rules no longer auto-approve -exec or -delete.", "Releases v2.1.114 through v2.1.119 are covered in Week 17 (April 20–24, 2026).", "/ultrareview (research preview) runs a fleet of bug-hunting cloud agents against your current branch or a PR; findings return to CLI or Desktop. Syntax: `/ultrareview` for current branch, `/ultrareview 1234` for a PR number.", "/recap generates a one-line session recap of what happened while you were away; automatic recaps can be turned off from /config.", "Custom themes (v2.1.118): build/switch named color themes via /theme, or hand-edit JSON files in ~/.claude/themes/. Each theme picks a base preset and overrides only chosen tokens. Plugins can ship themes.", "Hooks can call MCP tools directly via `type: \"mcp_tool\"`, hitting an already-connected MCP server without spawning a process.", "/cost and /stats are merged into /usage; the old names still work as typing shortcuts that open the relevant tab.", "/config changes (theme, editor mode, verbose, etc.) now persist to ~/.claude/settings.json and follow the same project/local/policy precedence as other settings.", "Forked subagents can be enabled on external builds with env var CLAUDE_CODE_FORK_SUBAGENT=1; a forked subagent inherits the full conversation context instead of starting fresh.", "Default effort level for Pro and Max subscribers on Opus 4.6 and Sonnet 4.6 is now `high` (previously `medium`).", "Native macOS and Linux builds replace the Glob and Grep tools with embedded `bfs` and `ugrep` available through Bash, for faster searches without a separate tool round-trip.", "--from-pr now accepts GitLab merge request, Bitbucket pull request, and GitHub Enterprise PR URLs in addition to github.com.", "Auto mode: include \"$defaults\" in autoMode.allow, soft_deny, or environment to add custom rules alongside the built-in list instead of replacing it.", "New `claude plugin tag` command creates release git tags for plugins with version validation (for plugin dependency version resolution).", "Opus 4.7 sessions now compute against the model's native 1M context window, fixing inflated /context percentages and premature autocompaction.", "/resume on large sessions is up to 67% faster and now offers to summarize stale, large sessions before re-reading them.", "Vim visual mode added in the prompt input: `v` for character selection, `V` for line selection, with operators and visual feedback.", "`claude auth login` now accepts an OAuth code pasted directly into the terminal when the browser callback cannot reach localhost — supports WSL2, SSH sessions, and containers (v2.1.126). Same release fixes login timeouts on slow/proxied connections and IPv6-only devcontainers.", "`claude project purge` deletes all Claude Code state for a project (transcripts, tasks, file history, the project's config entry). Flags: `--dry-run` to preview, `-y`/`--yes` to skip confirmation, `-i`/`--interactive` to choose, `--all` to clear every project (v2.1.124).", "Resume by PR URL: `gh pr create` links a PR to the session that produced it. `/resume` then accepts a pasted PR URL — the first character of the paste enters search mode and filters to the session that created that PR. Works for GitHub, GitHub Enterprise, GitLab, and Bitbucket pull/merge request URLs (v2.1.122).", "`claude --from-pr 1234` resumes the session that created PR #1234 directly, skipping the picker.", "MCP servers can set `alwaysLoad: true` in their config to opt out of tool-search deferral, so all of that server's tools are always available (not deferred behind tool search).", "MCP servers that hit a transient error during startup now auto-retry up to 3 times instead of staying disconnected.", "`claude plugin prune` removes orphaned auto-installed plugin dependencies; `claude plugin uninstall --prune` cascades the prune to dependencies.", "`PostToolUse` hooks can replace tool output for ANY tool (not only MCP tools) via `hookSpecificOutput.updatedToolOutput`.", "`claude ultrareview` subcommand runs `/ultrareview` non-interactively from CI or scripts: prints findings to stdout (`--json` for raw output), exits 0 on completion or 1 on failure.", "`--dangerously-skip-permissions` now also bypasses prompts for writes to `.claude/`, `.git/`, `.vscode/`, shell config files, and other previously protected paths; catastrophic removal commands still prompt as a safety net.", "The `/model` picker can list models from a gateway's `/v1/models` endpoint when `ANTHROPIC_BASE_URL` points at an Anthropic-compatible gateway; opt in via `CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1` (since v2.1.129).", "`ANTHROPIC_BEDROCK_SERVICE_TIER` selects a Bedrock service tier: `default`, `flex`, or `priority`.", "Vertex AI supports X.509 certificate-based Workload Identity Federation (mTLS ADC).", "On Windows, Git for Windows / Git Bash is no longer required: Claude Code uses PowerShell as the shell tool when Bash is absent, and treats PowerShell as the primary shell when the PowerShell tool is enabled. PowerShell 7 installed via Microsoft Store, MSI without PATH, or .NET global tool is auto-detected.", "`/skills` now has a type-to-filter search box to find a skill in a long list without scrolling.", "Memory leak fixes for image-heavy sessions, `/usage` on large transcript histories, and long-running tools without progress events.", "--plugin-dir now accepts a .zip plugin archive in addition to a directory.", "The new --plugin-url flag fetches a plugin archive from a URL for the current session only, e.g. `claude --plugin-url https://example.com/my-plugin.zip`. Useful for shipping internal plugins from an artifact store before adding to a marketplace.", "Ctrl+R reverse-search defaults (as of v2.1.129) to all prompts across every project; press Ctrl+S while searching to narrow to the current project or session. This restores pre-v2.1.124 behavior.", "New worktree.baseRef setting takes values `fresh` or `head`; it controls whether --worktree, the EnterWorktree tool, and agent-isolation worktrees branch from the remote default branch (fresh) or local HEAD (head). Default is `fresh`, which keeps unpushed commits out of new worktrees.", "New settings.autoMode.hard_deny rules block matching actions unconditionally in auto mode, regardless of allow exceptions — they override broader allow rules.", "Hooks now receive the active effort level via the effort.level JSON input field and the $CLAUDE_EFFORT environment variable; Bash tool commands can also read $CLAUDE_EFFORT.", "CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN=1 opts out of the fullscreen alternate-screen renderer, keeping the conversation in the terminal's native scrollback.", "CLAUDE_CODE_PACKAGE_MANAGER_AUTO_UPDATE lets Homebrew or WinGet installations run the upgrade in the background and prompt to restart.", "CLAUDE_CODE_SESSION_ID is now in the Bash tool subprocess environment, matching the session_id passed to hooks.", "/mcp now shows the tool count for connected servers and flags servers that connected with 0 tools.", "--channels now works with console (API key) authentication.", "Subprocesses (Bash, hooks, MCP, LSP) no longer inherit OTEL_* environment variables, so OTEL-instrumented apps run via the Bash tool no longer pick up the CLI's own OTLP endpoint.", "Sub-agent progress summaries now hit the prompt cache, cutting cache_creation token cost by roughly 3x.", "New parentSettingsBehavior admin key lets admins opt SDK managedSettings into the policy merge.", "OAuth/credential reliability fixes: parallel sessions no longer dead-end at 401 after a refresh-token race; MCP OAuth refresh tokens no longer lost when multiple servers refresh concurrently; a rare login loop from a concurrent credential write is fixed.", "Page covers releases v2.1.128 → v2.1.136 (Week 19, May 4–8, 2026).", "`claude agents` opens a dashboard listing every Claude Code session (running, blocked-on-input, done). Attach to a row to enter its conversation; press `←` to return to the list. Background sessions keep running without a terminal attached. (research preview)", "`claude agents` dispatch flags to configure background sessions: `--add-dir`, `--settings`, `--mcp-config`, `--plugin-dir`, `--permission-mode`, `--model`, `--effort`, `--dangerously-skip-permissions`.", "`claude agents --cwd <path>` scopes the session list to a directory.", "`/goal <condition>` sets a completion condition; after every turn a fast model checks whether the condition holds, and if not Claude starts another turn instead of returning control. The goal clears once met. Works in interactive, `-p`, and Remote Control. Added in v2.1.139.", "`/fast` (fast mode) now runs on Opus 4.7 by default instead of Opus 4.6. Set `CLAUDE_CODE_OPUS_4_6_FAST_MODE_OVERRIDE=1` to pin fast mode to Opus 4.6. (research preview)", "Fast mode is a high-speed Opus config: same model quality at about 2.5x speed for higher per-token cost. Pricing unchanged at $30/$150 per MTok (input/output), same as Opus 4.6 fast mode.", "New hook `args: string[]` exec form spawns the command directly without a shell, so path placeholders never need quoting.", "New `continueOnBlock` config option for `PostToolUse` hooks feeds the hook's rejection reason back to Claude and continues the turn instead of ending it.", "New `terminalSequence` field in hook JSON output lets hooks emit desktop notifications, window titles, and bells without a controlling terminal.", "Rewind menu added 'Summarize up to here' to compress earlier context while keeping recent turns intact.", "Remote Control, `/schedule`, Claude.ai MCP connectors, and notification preferences are disabled when `ANTHROPIC_API_KEY`, `apiKeyHelper`, or `ANTHROPIC_AUTH_TOKEN` is set, even alongside a Claude.ai login. Unset the API key to use these features.", "MCP stdio servers now receive `CLAUDE_PROJECT_DIR` in their environment (matching hooks); plugin configs can reference `${CLAUDE_PROJECT_DIR}` in commands.", "`claude plugin details <name>` shows a plugin's component inventory and projected per-session token cost; the `/plugin` details pane now also lists the LSP servers a plugin provides.", "Plugins with a root-level `SKILL.md` and no `skills/` subdirectory are now surfaced as a skill.", "`/feedback` can include recent sessions from the last 24 hours or 7 days, for issues spanning more than the current session.", "Agent tool `subagent_type` now matches case- and separator-insensitively, so `\"Code Reviewer\"` resolves to `code-reviewer`.", "Releases covered: v2.1.139 → v2.1.142 (week of May 11–15, 2026).", "Auto mode is available on the Pro plan and supports Sonnet 4.6 alongside Opus. It replaces permission prompts with background safety checks: routine actions run uninterrupted, destructive/suspicious ones are blocked and surfaced. Cycle modes with Shift+Tab; auto mode appears once the account meets requirements.", "/usage now shows a per-category breakdown of what's driving plan limits, attributing recent usage to skills, subagents, plugins, and individual MCP servers.", "'Extra usage' is renamed to 'usage credits' across the CLI; /extra-usage is now /usage-credits (the old name still works).", "New /code-review command reports correctness bugs at a chosen effort level, e.g. /code-review high; --comment posts findings as inline GitHub PR comments. /simplify remains a separate cleanup-only review.", "Background sessions now appear in /resume alongside interactive ones, marked with 'bg'. Sessions pinned with Ctrl+T in 'claude agents' stay alive when idle.", "'claude agents --json' lists live sessions as JSON for scripting (status bars, session pickers).", "The PowerShell tool is enabled by default on Windows for Bedrock, Vertex, and Foundry users; opt out with env var CLAUDE_CODE_USE_POWERSHELL_TOOL=0.", "'claude plugin disable' refuses when another enabled plugin depends on the target; 'claude plugin enable' force-enables transitive dependencies.", "The /plugin marketplace browse pane shows projected context cost; Discover and Browse screens list a plugin's commands, agents, skills, hooks, and MCP/LSP servers before installation.", "New worktree.bgIsolation: \"none\" setting lets background sessions edit the working copy directly without EnterWorktree, for repos where worktrees are impractical.", "Status line JSON input now includes GitHub repo and PR information when detected.", "Enterprise: the allowAllClaudeAiMcps managed setting loads claude.ai cloud MCP connectors alongside managed-mcp.json.", "Releases covered: v2.1.143 → v2.1.149 (May 18–22, 2026).", "Releases v2.1.150 through v2.1.157 covered in Week 22 (May 25-29, 2026).", "Claude Opus 4.8 is the default on Max, Team Premium, Enterprise pay-as-you-go, and the Anthropic API.", "Opus 4.8 defaults to high effort; use /effort xhigh for harder tasks.", "Opus 4.8 requires Claude Code v2.1.154 or later.", "Select Opus 4.8 with /model claude-opus-4-8 or via the model picker.", "Dynamic workflows (research preview): Claude writes an orchestration script for a task and runs it across many subagents in the background. Manage runs with /workflows.", "Use a dynamic workflow when a task is too large for one conversation to coordinate: codebase-wide audit, large migration, cross-checking research question. Request via natural language e.g. 'create a workflow that migrates every internal fetch() call to the new HttpClient wrapper'.", "security-guidance plugin reviews Claude's code changes for vulnerabilities and fixes them in the same session: fast pattern check on each edit, model review at end of each turn, deeper agentic review on commit or push.", "Add project-specific security rules in .claude/claude-security-guidance.md.", "Install security-guidance with /plugin install security-guidance@claude-plugins-official, then activate in current session with /reload-plugins.", "Fast mode defaults to Opus 4.8 at $10/$50 per MTok (2x standard rate for ~2.5x speed). Opus 4.7 and 4.6 fast mode stay at $30/$150. Opus 4.6 fast mode is deprecated. Toggle with /fast.", "In `claude agents`, prefix a shell command with ! to run it as a background job you can attach/detach; also available as `claude --bg --exec 'pytest -x'`.", "Plugins in .claude/skills directories are now loaded automatically with no marketplace required; `claude plugin init <name>` scaffolds a new plugin.", "/reload-skills re-scans skill directories without restarting. SessionStart hooks can return reloadSkills: true to make skills they install available in the same session.", "Skills and commands can set disallowed-tools in frontmatter to remove tools from the model while the skill is active.", "New MessageDisplay hook event lets hooks transform or hide assistant message text as it is displayed.", "Claude Code now switches to the configured --fallback-model for the rest of the session when the primary model is not found, instead of failing every request.", "Plugins can declare defaultEnabled: false in plugin.json or a marketplace entry, so they install without turning on until enabled.", "Streaming tool execution is now always enabled, including with telemetry disabled and on Bedrock, Vertex, and Foundry.", "`claude mcp list` and `claude mcp get` now show unapproved .mcp.json servers as pending approval instead of auto-approving and connecting when output is piped.", "Auto mode (replaces permission prompts with background safety checks) is available on Bedrock, Vertex, and Foundry for Opus 4.7 and Opus 4.8 as of v2.1.158; opt in by setting env var CLAUDE_CODE_ENABLE_AUTO_MODE=1, then cycle to it with Shift+Tab.", "As of v2.1.160, Claude Code prompts before writing files that can run code even in acceptEdits mode. Protected set: shell startup files (.zshenv, .bash_login), git config under ~/.config/git/, and build-tool configs (.npmrc, .bazelrc, .pre-commit-config.yaml).", "Writes to the protected path set are never auto-approved in any mode except bypassPermissions.", "/plugin list (v2.1.163) prints installed plugins inline without opening the /plugin menu; also available from shell as 'claude plugin list'. Interactive form accepts --enabled or --disabled to filter by state.", "Two managed settings in managed-settings.json — requiredMinimumVersion and requiredMaximumVersion — let an org require an approved Claude Code version range. A client outside the range exits at startup and tells the user to update via the org's method.", "Even when a managed version range blocks startup, 'claude update', 'claude install', and 'claude doctor' keep working so users can recover.", "The dynamic-workflows trigger keyword changed from 'workflow' to 'ultracode'; asking for a workflow in natural language still works, and the keyword is highlighted violet in the prompt.", "Stop and SubagentStop hooks can return hookSpecificOutput.additionalContext to give Claude feedback and continue the turn, instead of the output being treated as an error.", "'claude mcp' list/get/add no longer print secrets: environment-variable references are not expanded, and credential headers and URL secrets are redacted.", "A failed Bash command in a parallel tool batch no longer cancels the others; each tool returns its own result independently.", "Editing a file no longer requires a separate Read first if you viewed it with a single-file grep, egrep, or fgrep.", "Listing Grep or Glob in --tools now provides the dedicated search tools on native builds with embedded search, instead of silently ignoring those names.", "OTEL_RESOURCE_ATTRIBUTES values are now attached as labels on metric datapoints, so usage metrics can be sliced by custom dimensions like team or repo.", "/effort now confirms when the chosen level will persist as the default for new sessions.", "Clicking a command in the autocomplete menu now fills it into the prompt instead of running it immediately; press Enter to run.", "/cd <dir> moves the current session to a different working directory without rebuilding the prompt cache; the new directory's CLAUDE.md is appended as a message instead of replacing the system prompt (v2.1.169).", "After /cd, the session relocates to the new directory's project storage, so --resume and --continue find it there.", "/cd prompts to trust the directory if you have not worked in it before.", "Subagents can spawn their own subagents; subagent chains are capped at five levels deep to prevent runaway concurrent trees (v2.1.172).", "The /agents subagent panel shows the full tree: each row carries a count of its descendants and a path back to main.", "--safe-mode flag, or env var CLAUDE_CODE_SAFE_MODE, launches Claude Code with all customizations disabled: CLAUDE.md, skills, plugins, hooks, MCP servers, and custom commands and agents do not load (v2.1.169).", "In safe mode, authentication, model selection, built-in tools, and permissions still work.", "fallbackModel setting configures up to three fallback models tried in order when the primary is overloaded or unavailable; --fallback-model now applies to interactive sessions too.", "disableBundledSkills setting and CLAUDE_CODE_DISABLE_BUNDLED_SKILLS env var hide bundled skills, workflows, and built-in commands from the model.", "Deny rules accept a glob in the tool-name position, so \"*\" denies all tools; unknown tool names in deny rules now warn at startup.", "enforceAvailableModels managed setting makes the availableModels allowlist also constrain the Default model.", "Cross-session messaging hardened: messages relayed via SendMessage from other sessions no longer carry user authority, and auto mode blocks them.", "claude agents --json adds --all to include completed sessions plus new id and state fields, and no longer omits blocked or newly dispatched sessions.", "On Amazon Bedrock, Claude Code reads the AWS region from ~/.aws config files when AWS_REGION is unset; /status shows where the region came from.", "footerLinksRegexes setting adds regex-matched link badges to the footer row.", "language setting pins the language used for generated session titles.", "Releases covered: v2.1.166 through v2.1.176 (Week 24, June 8–12, 2026).", "`/cd` moves the current session to a new working directory mid-conversation without rebuilding the prompt cache (Week 24).", "Sub-agents can spawn their own sub-agents; background chains are capped at five levels deep (Week 24).", "`--safe-mode` starts Claude Code with all customizations disabled, for troubleshooting (Week 24).", "`fallbackModel` setting configures up to three fallback models tried in order (Week 24).", "Auto mode is available on third-party providers (Bedrock, Vertex, Foundry) for Opus 4.7 and Opus 4.8, replacing permission prompts with background safety checks (Week 23).", "In `acceptEdits` mode, Claude Code now prompts before writing files that can run code ('safer automatic edits') (Week 23).", "`/plugin list` prints installed plugins inline (Week 23).", "Version requirements let managed deployments require an approved Claude Code version range (Week 23) — a governance control for teams/enterprise.", "Claude Opus 4.8 is the default model for Max, Team Premium, Enterprise pay-as-you-go, and Anthropic API accounts, with high effort by default and `/effort xhigh` for the hardest tasks (Week 22).", "Dynamic workflows orchestrate dozens to hundreds of subagents from a script Claude writes (Week 22).", "The security-guidance plugin reviews Claude's changes for vulnerabilities as it works (Week 22).", "Fast mode runs on Opus 4.8 at $10/$50 per MTok (Week 22).", "Auto mode runs on the Pro plan and supports Sonnet 4.6 alongside Opus (Week 21).", "`/usage` breaks down what drives plan limits by skill, subagent, plugin, and MCP server (Week 21; also Week 16).", "`/code-review` command reports correctness bugs (Week 21).", "Background sessions appear in `/resume` and stay alive when pinned (Week 21).", "`claude agents` opens one screen for every Claude Code session, showing what's running, blocked, or done (Week 20).", "`/goal` keeps Claude working across turns until a completion condition holds (Week 20).", "Rewind menu can compress earlier context via 'Summarize up to here' (Week 20).", "`--plugin-dir` accepts `.zip` files; `--plugin-url` fetches a plugin archive for the current session (Week 19).", "`worktree.baseRef` setting chooses whether new worktrees branch from the remote default or local `HEAD` (Week 19).", "Auto mode hard deny rules block actions unconditionally regardless of allow exceptions (Week 19).", "Hooks see the active effort level via `effort.level` and the `$CLAUDE_EFFORT` environment variable (Week 19).", "On Windows, Git for Windows is no longer required; Claude Code uses PowerShell as the shell tool when Bash is absent (Week 18).", "`claude ultrareview` brings cloud code review to CI and scripts (Week 18).", "`claude project purge` cleans up local state for a project (Week 18).", "Pasting a PR URL into `/resume` finds the session that created it (Week 18).", "Claude Opus 4.7 with `xhigh` effort level is the recommended setting for most coding work; `/effort` is an interactive slider (Week 16).", "Routines (Claude Code on the web) fire templated cloud agents from a schedule, GitHub event, or API call (Week 16).", "The Monitor tool streams background events into the conversation so Claude can tail logs and react live (Week 15).", "`/loop` self-paces when you omit the interval (Week 15).", "`/team-onboarding` packages your setup into a replayable guide (Week 15).", "`/autofix-pr` turns on PR auto-fix from the terminal (Week 15).", "Per-tool MCP result-size override up to 500K (Week 14).", "Plugin executables are placed on the Bash tool's `PATH` (Week 14).", "Auto mode (research preview, Week 13): a classifier handles permission prompts so safe actions run uninterrupted and risky ones are blocked — the middle ground between approving everything and `--dangerously-skip-permissions`.", "Conditional `if` hooks are supported (Week 13)."]}, "Surfaces & mobility": {"pages": ["channels", "channels-reference", "claude-code-on-the-web", "computer-use", "deep-links", "desktop", "desktop-quickstart", "jetbrains", "remote-control", "voice-dictation", "vs-code", "web-quickstart", "worktrees"], "bestPractices": ["After pairing a Telegram/Discord channel, immediately run /<channel>:access policy allowlist to lock down to only your account.", "For unattended/always-on channel use, run Claude in a background process or persistent terminal — events only arrive while the session is open.", "Only add allowlist senders you fully trust: if the channel declares permission relay, any allowlisted sender can approve or deny tool use in your session.", "Org admins: set allowedChannelPlugins in managed settings to restrict registration to specific official/internal-marketplace plugins; requires channelsEnabled:true.", "To fully block channels org-wide (including the dev bypass flag), leave channelsEnabled unset rather than using an empty allowedChannelPlugins array.", "Run channels in non-interactive (-p) mode to auto-disable terminal-input tools so the session never stalls waiting for input when you're away.", "Use the fakechat localhost demo (http://localhost:8787) to validate the plugin/channel flow before wiring a real platform.", "Gate inbound channel messages against a sender allowlist BEFORE calling mcp.notification(); an ungated channel is a prompt-injection vector since anyone reaching the endpoint can inject text into Claude's context.", "Gate on the sender's identity (message.from.id), never on the chat/room id (message.chat.id): in group chats they differ, and room-gating lets anyone in an allowlisted group inject messages.", "Only declare the 'claude/channel/permission' capability on channels that authenticate the sender, because anyone who can reply through the channel can approve or deny tool use in your session.", "Bind the channel's local HTTP listener to 127.0.0.1 (localhost-only) so nothing outside the machine can POST events.", "Bootstrap sender allowlists via a pairing flow (user DMs bot → bot returns pairing code → user approves in their Claude Code session), as the Telegram/Discord reference channels do.", "Include the five-letter request_id verbatim in the outbound permission prompt and parse it from replies; tolerate phone-autocorrect capitalization with a case-insensitive regex (e.g. /^\\s*(y|yes|n|no)\\s+([a-km-z]{5})\\s*$/i) and lowercase the captured ID before sending the verdict.", "For a delivery-confirmation requirement, expose a reply tool Claude can call to report status, since channel notifications are fire-and-forget with no ack.", "Run separate Claude Code sessions to process independent event streams concurrently rather than relying on one session to interleave them.", "For user-level (~/.claude.json) channel registration use an absolute command/path so the server is found from any project; project-level .mcp.json can use a relative path.", "Restrict channel plugins org-wide via the admin 'allowedChannelPlugins' list (Team/Enterprise) instead of relying on the default Anthropic allowlist when distributing internal channels.", "Drive cloud config through the repo, not user settings: commit CLAUDE.md, .claude/settings.json hooks, .mcp.json (project scope), .claude/skills, .claude/agents, .claude/commands, and declare plugins in repo .claude/settings.json — user-scoped ~/.claude config is invisible to cloud sessions.", "Put dependency installs that the cloud needs but your laptop already has (runtimes, CLI tools) in the per-environment setup script so they get cached; put project setup that should run everywhere (npm install) in a repo SessionStart hook gated on CLAUDE_CODE_REMOTE.", "Keep setup scripts under ~5 minutes and append '|| true' to non-critical commands so a flaky install doesn't fail the whole session; pre-pull/build Docker images in the setup script so they're cached on disk.", "Use the plan-locally-execute-remotely pattern: 'claude --permission-mode plan' to design, commit/push the plan to the repo, then 'claude --remote \"Execute the plan in docs/...\"' so the VM can clone it.", "Fan out independent work across parallel cloud sessions with multiple 'claude --remote' commands and monitor with /tasks; remember they share your account rate limits.", "Restrict cloud repo reach via GitHub team/repository membership (not App installation, which is not an access control); disable /web-setup org-wide via the admin Quick web setup toggle if you don't want token-sync onboarding.", "Treat env vars and setup scripts as visible to anyone who can edit the environment — since there is no secrets store, scope secrets accordingly and prefer GitHub-proxy auth (token never enters the container) over embedding tokens.", "Lower CLAUDE_AUTOCOMPACT_PCT_OVERRIDE (e.g. 70) and offload research to subagents to manage context proactively in long cloud runs; use /compact with focus instructions and /context (note /clear is unavailable — start a new session instead).", "Set network access to Custom with a minimal allowlist (optionally including default package registries) rather than Full when reaching internal/private hosts, to limit egress; keep only the MCP connectors you actually need per session/routine.", "Before enabling Auto-fix, audit repo automation that triggers on issue_comment (Atlantis/Terraform Cloud/custom Actions), since Claude's PR replies post under your account and can trigger privileged workflows.", "If your org uses IP allowlisting, get Anthropic-hosted services exempted before relying on cloud sessions/Code Review/Routines, or every session fails with an auth error.", "Embed the session URL (Claude-Session git trailer / CLAUDE_CODE_REMOTE_SESSION_ID) in PRs, commits, or reports for traceability back to the run that produced them.", "Prefer a dedicated MCP server, Bash, or Claude in Chrome over computer use when available — computer use is the broadest and slowest path; reserve it for native apps, simulators, and GUI-only tools with no API.", "For UI/visual work, have Claude build, launch, click through, and screenshot in one pass to validate native/Electron apps and reproduce layout bugs without a separate test harness.", "Enable `computer-use` once per project via /mcp; grant Accessibility + Screen Recording, then restart Claude Code if Screen Recording was just granted.", "Keep an eye on sessions: finish/exit any session holding the computer-use lock before starting another, since only one session can control the machine.", "Watch the live session via your (always-visible, screenshot-excluded) terminal and use Esc or Ctrl+C to abort immediately if Claude does something unexpected.", "Use `repo=owner/name` (not `cwd`) for links shared across a team where each person clones to a different path; use `cwd` only when everyone has the project at the same absolute path (standardized devcontainer/VM image).", "Embed deep links in incident runbooks, monitoring alerts, dashboards, and onboarding wikis to give one-click, repo-scoped, prompt-prepared entry points — store long runbook prompts as a repo `/skill` and have the `q` parameter just name the skill instead of inlining a giant prompt.", "URL-encode the `q` prompt via encodeURIComponent; use `%0A` for line breaks; keep under the 5,000-char limit.", "For org governance, set `disableDeepLinkRegistration` in managed (server-managed) settings to enforce it so users cannot re-enable handler registration.", "When publishing deep links on GitHub (READMEs/issues/wikis), put them in a code block since GitHub strips the `claude-cli://` scheme and renders only the label.", "If `repo` opens the home directory instead of the clone, run `claude` once inside the intended clone to record its path, or switch the link to `cwd` with an absolute path.", "Start complex tasks in Plan mode so Claude maps an approach before editing; once approved, switch to Auto accept edits or Ask permissions to execute (explore → plan → code).", "For new users, start in Ask permissions to see each change, then graduate to Auto accept edits or Auto as trust grows.", "Only use Bypass permissions in sandboxed containers/VMs; admins should disable it org-wide via managed settings or admin console where appropriate.", "Put org-governed controls (`disableBypassPermissionsMode`, `disableAutoMode`, `autoMode`, `sshConfigs`, `sshHostAllowlist`, `managedMcpServers`) in managed settings, not user/project settings, so users cannot override them.", "For Desktop enterprise rollouts, distribute the managed settings file via MDM (admin-console remote push does not reach Desktop) and pair `sshHostAllowlist` with network/zero-trust controls since it does not restrict egress or Bash `ssh`.", "Use `/compact` proactively to free context before it auto-summarizes, and check the usage ring to monitor per-session context.", "Use a `.worktreeinclude` to carry `.env`/gitignored files into worktree sessions so parallel sessions build correctly.", "Keep secrets out of `.claude/launch.json` `env` (it's committed); set them in the local environment editor instead.", "Use Verbose transcript view to debug why Claude took an action; use Summary view to scan results across many parallel sessions.", "Run long refactors/migrations/test suites as Remote (cloud) sessions so they continue when the app is closed.", "Use Plan mode for exploration without source edits; use side chats (`/btw`, Cmd/Ctrl+;) to ask context-aware questions without derailing the main session.", "Set `autoPort: false` for servers that need a fixed port (OAuth callbacks, CORS allowlists); otherwise leave default/true.", "Manage permission rules, hooks, and skills by editing settings files directly in Desktop since `/permissions`, `/config`, `/agents`, `/doctor` are unavailable there.", "Use Plan mode before a large refactor so Claude maps the approach without touching files.", "Isolate concurrent work into separate parallel sessions (each gets its own Git worktree) instead of multiplexing tasks in one session, to keep contexts from interfering.", "Use a side chat for tangential questions to avoid derailing/polluting the main session's context.", "Add specific context up front with @filename, attached images/PDFs, or drag-and-drop, rather than relying on Claude to find files.", "Interrupt and steer mid-run: type a correction and press Enter to redirect without stopping, or click stop to halt immediately, rather than waiting or restarting.", "Push long-running tasks to the cloud (Remote) so they survive closing the app, and continue a session on web/IDE if it overruns.", "Review diffs before committing and comment on specific lines; Claude reads the comments and revises.", "Capture repeatable team procedures (code-review checklists, deploy steps) as custom skills/slash commands so they are invocable on demand.", "Start Claude Code from the same directory as the IDE project root so Claude has access to the same files the IDE sees (required for the integration to work correctly).", "Use `Read` deny rules in permissions config to prevent the IDE from auto-sharing sensitive files (selection/tab context) with Claude.", "In JetBrains IDEs, prefer manual approval mode for edits rather than auto-edit, because auto-edit can let Claude modify IDE config files that the IDE auto-executes, bypassing bash permission prompts.", "If ESC doesn't interrupt Claude in the JetBrains terminal, uncheck 'Move focus to the editor with Escape' (Settings → Tools → Terminal) or delete the 'Switch focus to Editor' keybinding.", "For a team, treat Remote Control as an explicit opt-in capability: on Team/Enterprise it is off by default and an admin must enable the org-wide toggle at claude.ai/admin-settings/claude-code; if you want it blocked on specific machines regardless, set `disableRemoteControl` in managed settings files.", "When running server mode for parallel work on the same repo, use `--spawn=worktree` (or press `w`) so concurrent sessions get isolated git worktrees instead of conflicting in the shared cwd under the default `same-dir`.", "For shared/CI-style machines, run server mode with `--sandbox` to add filesystem/network isolation (it is off by default), and bound concurrency with `--capacity <N>` (default 32).", "Standardize team auth on claude.ai OAuth via `/login`; do not rely on `ANTHROPIC_API_KEY`, `claude setup-token`, or `CLAUDE_CODE_OAUTH_TOKEN` for anyone who needs Remote Control — those tokens are inference-only or unsupported.", "To debug eligibility/connection errors, run `claude doctor` (shows which eligibility check failed) and re-run with `--verbose`; after a plan change run `claude auth logout` then `claude auth login` to refresh stale entitlements.", "Set `CLAUDE_CLIENT_PRESENCE_FILE` plus a screen-lock listener so mobile pushes are suppressed while you're at the machine and only fire when you've stepped away.", "If a team standardizes Claude Code auth on Bedrock/Vertex/Foundry/API-key (common for enterprise/governed deployments), expect voice dictation to be unavailable — don't document it as a feature for those users.", "To eliminate hold-mode warmup, rebind voice:pushToTalk to a modifier combo (e.g. meta+k) in ~/.claude/keybindings.json, or use tap mode.", "On WSL2 dev setups, install `sox libsox-fmt-pulse` (not plain sox) to get a working voice recorder.", "Govern team config through ~/.claude/settings.json (allowed commands, env vars, hooks, MCP servers) since it is shared between the extension and CLI; reserve VS Code extension settings for per-developer UI preferences.", "Add the $schema line (https://json.schemastore.org/claude-code-settings.json) to settings.json so the whole team gets autocomplete and validation and avoids malformed settings.", "Distribute team plugins via 'Install for this project' (project scope) so they are shared through the repo and also work in the CLI; add a shared marketplace (GitHub repo/URL/path) under the Marketplaces tab.", "To keep secrets out of model context, add a Read deny rule for sensitive paths (e.g. .env); this blocks both selected-text and open-file context from the IDE MCP, not just file reads.", "If your org uses PreToolUse hooks to allowlist MCP tools, account for the hidden built-in 'ide' server and its tools mcp__ide__getDiagnostics and mcp__ide__executeCode.", "Set claudeCode.initialPermissionMode to 'plan' or 'default' for new conversations rather than acceptEdits/bypassPermissions when working with untrusted or shared code.", "Enable VS Code Restricted Mode for untrusted workspaces and prefer manual edit approval, because auto-edit can modify VS Code config files (settings.json, tasks.json) that VS Code may auto-execute.", "Use /usage to find what drives plan limits (cache misses, long context, subagent-heavy/parallel sessions, per-MCP/skill/plugin attribution) and act on the flagged >=10% contributors to cut cost.", "Use claude --worktree <name> to run parallel Claude sessions on isolated branches so concurrent agents don't interfere.", "Install the standalone CLI alongside the extension so CLI-only features (full skill/command set, claude mcp add, claude --resume, '!' bash, tab completion) and 'claude' on PATH are available.", "Configure MCP servers once via 'claude mcp add' in the integrated terminal (config is shared with the panel), then enable/disable and manage OAuth via /mcp.", "For Bedrock/Vertex/Foundry, set claudeCode.disableLoginPrompt and put provider config in ~/.claude/settings.json so it is shared with the CLI.", "Write specific cloud task prompts: name the file/function (e.g. 'Fix the failing auth test in tests/test_auth.py'), paste error output, describe expected behavior not just the symptom.", "Use cloud sessions for parallel independent tasks, repos you don't have checked out locally, and well-defined tasks that don't need frequent steering; use local CLI / Remote Control when the task needs local config, tools, or environment.", "Keep setup scripts under the ~5-minute cache-build budget: run independent installs in parallel with '&' plus a final 'wait', move large downloads (Docker images, model weights, full dependency trees) into a background SessionStart hook, and remove long retry sleeps.", "Debug a failing setup script by adding 'set -x' at the top to see which command failed, and append '|| true' to non-critical commands so they don't block session start.", "If you use the gh CLI, run /web-setup from the terminal to set up cloud sessions without the browser flow.", "Use Plan mode for cloud tasks when you want Claude to propose an approach and wait before editing (default Accept edits pushes a branch without stopping).", "Build issue-tracker integrations by linking to claude.ai/code with prompt/repositories query params so a button opens a prefilled session.", "Use CLAUDE.md (/memory) to give cloud sessions persistent standing instructions since they don't inherit local config.", "Add `.claude/worktrees/` to `.gitignore` so worktree contents don't show as untracked files in the main checkout.", "Use a `.worktreeinclude` file to auto-copy gitignored config (`.env`, `.env.local`, `config/secrets.json`) into each worktree — otherwise the fresh checkout lacks them.", "Run one Claude session per worktree in separate terminals (e.g. `claude --worktree feature-auth` and `claude --worktree bugfix-123`) to build a feature and fix a bug concurrently without file collisions.", "Set `worktree.baseRef: \"head\"` when isolating subagents that must operate on in-progress/unpushed work; leave default `fresh` for clean-tree feature work.", "Re-initialize the dev environment in each new worktree (install deps, create venv, run project setup) — a fresh checkout does not inherit them.", "For non-git VCS, pair `WorktreeCreate` with a `WorktreeRemove` hook and copy local config inside the hook (since `.worktreeinclude` is bypassed).", "For deep control over location/branch (e.g. checking out a specific existing branch or placing the worktree outside the repo), create worktrees manually with `git worktree add` rather than `--worktree`.", "Name sessions you want to persist — named-session worktrees prompt before cleanup instead of being auto-removed."], "gotchas": ["Adding a channel server to .mcp.json does NOT let it push messages — it must also be named in --channels for the session.", "An empty allowedChannelPlugins array blocks allowlisted plugins but does NOT block --dangerously-load-development-channels; only leaving channelsEnabled unset blocks channels including the dev flag.", "If channelsEnabled is off/unset, the MCP server still connects and its tools work — but channel messages silently never arrive (only a startup warning).", "When Claude replies through a channel, the reply text is NOT shown in the terminal — only the tool call and a 'sent' confirmation; the actual reply appears on the other platform.", "iMessage requires Full Disk Access for the launching terminal/IDE or the server exits immediately with 'authorization denied'.", "If Claude hits a permission prompt while you're away and the channel lacks permission relay, the session pauses until you respond at the terminal.", "Off-allowlist plugins passed to --channels don't error loudly — Claude starts normally and the channel silently fails to register (startup notice only).", "Channels are blocked by default on claude.ai Team and Enterprise plans until an admin explicitly enables them.", "Events are dropped SILENTLY (no error to the server) if the channel isn't loaded as a channel or org policy blocks it — a curl that succeeds does not mean Claude received the event; use /mcp and ~/.claude/debug/<session-id>.txt to diagnose.", "meta keys with hyphens or non-identifier characters are silently dropped (only [A-Za-z0-9_] survive as <channel> attributes).", "'--dangerously-load-development-channels' bypasses ONLY the allowlist and only per listed entry — it does not bypass the 'channelsEnabled' org policy and does not extend the bypass to --channels entries; the flag name warns against running untrusted-source channels.", "Community-marketplace plugins (added via in-app submission forms) are NOT on the channel allowlist, so a channel you publish there still needs the dangerous dev flag to run.", "Project-trust and MCP-server-consent dialogs never relay to a remote channel — only tool-use approvals (Bash/Write/Edit) relay; the rest require someone at the local terminal.", "The permission request_id is not shown in the local terminal dialog, so the outbound permission handler is the only way to learn it — if your handler doesn't include it, remote approval is impossible.", "request_id alphabet deliberately excludes 'l' (five lowercase letters a-z minus l) to avoid confusion with 1/I on phones; a verdict with the wrong/expired ID is silently dropped while the dialog stays open.", "An ungated channel exposed to a chat platform or public endpoint is a direct prompt-injection path into the session; gating is mandatory, not optional.", "'curl: connection refused' on the channel port usually means a stale process from a prior run holds the port — find it with 'lsof -i :<port>' and kill it before restarting the session.", "'Failed to connect' in /mcp usually means a dependency/import error in the server file; the stderr trace is only in ~/.claude/debug/<session-id>.txt, not the terminal.", "App installation does NOT scope which repos a cloud session can reach — any repo the connected GitHub account can see is reachable; only GitHub-side membership limits this.", "User-level config is silently absent in cloud: ~/.claude/CLAUDE.md, user skills/agents/commands, user enabledPlugins, and 'claude mcp add' servers (local user config) do not carry over — only repo-committed config does.", "No secrets store: env vars and setup scripts are visible to anyone who can edit the environment.", "Even with network access None, Claude can still reach the Anthropic API, so data may still exit the VM.", "The security proxy breaks some package managers — Bun is a known example for package fetching.", "Setup script exiting non-zero fails the whole session to start; an intermittent install failure can block startup unless you append '|| true'.", "Setup scripts only re-run when you change the script or allowed hosts, or after ~7-day cache expiry — resuming a session never re-runs them, so config changes inside a script may not take effect as expected.", "SessionStart hooks have no cloud-only scoping (run local too) and add startup latency every session/resume since they don't benefit from caching.", "git push is restricted by the proxy to the current working branch only.", "Session handoff is one-way from the CLI: you can --teleport web→terminal but cannot push terminal→web (only the Desktop app's 'Continue in' can).", "Bundled (non-GitHub) sessions can't push results back unless GitHub auth is also configured; untracked files are excluded from the bundle unless git-added; bundle must be under 100MB.", "/clear, /model, and /config (interactive pickers) do not work in cloud sessions.", "--teleport requires claude.ai subscription auth — API key/Bedrock/Vertex/Foundry users must /login with their claude.ai account first; teleport also requires a clean git tree, same (non-fork) repo, and the branch pushed to remote.", "Auto-fix can't react to merge conflicts (no GitHub webhook on base-branch advance) — you must ask Claude to rebase manually.", "Auto-fix PR replies post under your GitHub username and can trigger issue_comment-based automation (Atlantis/Terraform/Actions) that may run privileged operations.", "Organization IP allowlisting causes every cloud session (and Code Review/Routines) to fail with an auth error because traffic originates from Anthropic infrastructure.", "Zero Data Retention orgs cannot use /web-setup or cloud session features at all.", "Max/Pro Public session sharing has repository access verification OFF by default and sessions may contain private-repo code and credentials — check before sharing.", "Memory/CPU/disk ceilings (4 vCPU / 16GB / 30GB) can silently terminate large builds or memory-heavy tests.", "Cloud sessions share account rate limits; running many parallel --remote tasks consumes them proportionately.", "Not available on Team or Enterprise plans — only Pro or Max; teams on Enterprise plans cannot use CLI computer use at all.", "Not available with `-p` non-interactive mode, so it can't be scripted/automated headlessly via the CLI flag.", "Not available with third-party providers (Bedrock, Vertex, Foundry) — requires claude.ai auth; provider-only access needs a separate claude.ai account.", "macOS may silently keep re-prompting for Screen Recording until you fully quit and restart Claude Code (and confirm the terminal app is enabled in System Settings > Privacy & Security > Screen Recording).", "Approving a terminal/IDE app for computer use is effectively granting shell access; approving Finder grants any-file read/write; approving System Settings allows changing system settings — these aren't blocked, only warned.", "Runs on the real desktop (not sandboxed like Bash), so the trust boundary is weaker; prompt injection from on-screen content is a real risk despite per-action checks.", "If text/controls are too small for Claude to read after downscaling, you must increase size in the app — changing display resolution won't help and there's no downscale setting.", "CLI has no denied-apps list yet (Desktop does), so you can't pre-block apps from computer use in the CLI.", "Passing both `cwd` and `repo` silently ignores `repo` — and `cwd` wins even when the `cwd` path does not exist (so a typo'd cwd does NOT fall back to repo).", "`repo` only resolves to clones where `claude` has already been run at least once; otherwise the session silently opens in the home directory.", "GitHub Markdown strips `claude-cli://` links in READMEs, issues, PRs, and wikis — the link silently renders as plain non-clickable text.", "`repo` does not change the checked-out branch; the session opens whatever state the directory currently has.", "Network/UNC paths are rejected for `cwd`.", "Handler registration only happens after the first interactive `claude` session — clicking a link before that does nothing (especially on Linux without a desktop environment / xdg-open).", "Long prompts (over 1,000 chars) can push instructions off-screen; the warning banner reminds users to scroll and review the full external prompt before sending — a prompt-injection consideration for links from untrusted sources.", "Windows terminal order is fixed (Windows Terminal > PowerShell > cmd.exe); to get Windows Terminal you must install it.", "Admin-console remotely-pushed managed settings currently reach only CLI and IDE sessions, NOT Desktop — Desktop requires the managed file on disk (MDM) or admin console toggles.", "`autoMode` classifier rules are deliberately NOT read from checked-in `.claude/settings.json`, so a cloned repo cannot inject auto-mode trust rules (only user settings, settings.local.json, and managed settings).", "`sshHostAllowlist` is honored only by the Desktop app — the CLI, IDE extensions, and Bash-tool `ssh` ignore it; it controls Desktop connections, not network egress.", "The standalone CLI does not read `claude_desktop_config.json`; MCP servers configured in the Desktop chat app must be imported with `claude mcp add-from-claude-desktop`.", "On macOS, launching Desktop from Dock/Finder only inherits PATH and a fixed set of Claude Code vars from your shell profile — other exported env vars are silently dropped (use the local environment editor).", "Windows does not read PowerShell profiles for env vars; PATH changes after install only apply to new terminal windows.", "The `env` key in `~/.claude/settings.json` reaches Claude sessions but NOT dev/preview servers — use the local environment editor for vars dev servers need.", "Preview detection uses the folder you selected as cwd; if you opened a parent folder, subfolders with their own dev servers won't be auto-detected.", "Terminal-dialog slash commands (`/permissions`, `/config`, `/agents`, `/doctor`) reply 'isn't available in this environment' in the Code tab.", "Bypass permissions still honors explicit `ask` permission rules — it is not a total bypass.", "Computer use and Dispatch are unavailable on Team/Enterprise plans (Pro/Max only); Desktop itself is unavailable on Linux.", "Cloud sessions lack @mention, the + button (Connectors/Plugins), terminal pane, and file editing — you must ask Claude to make file changes there.", "Cloud sessions can create branches that don't exist locally ('Branch doesn't exist yet'); fetch with `git fetch origin <branch>` then checkout.", "`/desktop` migration is unavailable with API key auth or on Bedrock/Vertex/Foundry.", "`MAX_THINKING_TOKENS=0` has no effect on Fable 5; on adaptive-reasoning models (Opus 4.7+) any value is ignored and there is no fixed-budget mode.", "Desktop app is not available on Linux at all; Linux users must use the CLI.", "On Windows, local sessions silently require Git to be installed first or they won't work.", "The bundled Claude Code does NOT give you the `claude` terminal command; the CLI must be installed separately to use it.", "A 403 error in the Code tab indicates an authentication problem requiring sign-in/restart troubleshooting.", "Because CLI and Desktop share the same config (CLAUDE.md, MCP, hooks, skills, settings) and can run simultaneously on the same project, config changes affect both surfaces at once.", "Security: with auto-edit permissions enabled in a JetBrains IDE, Claude may modify IDE configuration files that the IDE auto-executes — this can bypass Claude Code's bash-execution permission prompts. Use manual edit approval and only trusted prompts.", "The plugin does not ship the CLI; if `claude` isn't on PATH the plugin shows 'Cannot launch Claude Code'. Set the full path in plugin settings if needed.", "Installing the plugin often requires a COMPLETE IDE restart — sometimes multiple times — before features appear.", "For Remote Development, installing the plugin on the local client (instead of the remote host) silently fails to enable features.", "Integration features only activate when running from the integrated terminal at the project root; running elsewhere causes 'No available IDEs detected' or missing features.", "Default `--spawn=same-dir` server mode lets multiple remote sessions edit the same working directory simultaneously — they can silently conflict on the same files. Switch to worktree mode for safety.", "Sandboxing is OFF by default in server mode — a remote-driven session has full local filesystem/network access unless you pass `--sandbox`.", "Remote Control will not work if `ANTHROPIC_API_KEY` is set in the environment; it requires claude.ai OAuth, so API-key and Console-account users are silently excluded.", "Tokens from `claude setup-token` / `CLAUDE_CODE_OAUTH_TOKEN` are inference-only and cannot establish Remote Control sessions even though they authenticate you for normal use.", "The session is entirely tied to the local process: closing the terminal or quitting VS Code ends it, and ~10 minutes of network unreachability times it out and exits the process.", "Starting an ultraplan session silently disconnects any active Remote Control session because both compete for the claude.ai/code interface.", "The org admin toggle can be permanently grayed out by a data-retention/compliance configuration — only Anthropic support can change it, not the admin panel.", "Interactive-picker commands (`/plugin`, `/resume`) are local-only and cannot be run from mobile/web; managing plugins or resuming a different session must be done at the terminal.", "Outside server mode only one remote session exists per process — enabling Remote Control for all sessions means each `claude` instance registers its own session, which can proliferate sessions in the claude.ai/code list.", "Voice dictation silently unavailable for any org/user authenticating via API key, Bedrock, Vertex, or Foundry — so teams standardized on those auth modes cannot use it at all.", "HIPAA-enabled organizations have voice dictation fully disabled.", "In hold mode, binding a bare letter key (e.g. `v`) breaks because hold detection relies on key-repeat and the letter types into the prompt during warmup; use Space or a modifier combo like meta+k.", "Hold detection fails if OS-level key-repeat is disabled — symptom is nothing happening on hold; workaround is tap mode.", "Does not work on headless servers / remote shells with no audio passthrough; repeated start-up failures cause voice to self-pause until a session succeeds.", "The `hold Space to speak` footer hint does not appear if a custom status line is configured.", "Installing the VS Code extension does NOT add 'claude' to PATH — the bundled CLI is private to the panel; the standalone CLI is a separate install.", "The extension cannot ADD MCP servers (CLI-only via 'claude mcp add'); /mcp only manages existing ones. MCP support is listed as 'Partial'.", "The built-in 'ide' MCP server is hidden from /mcp, so PreToolUse allowlist hooks can silently miss mcp__ide__getDiagnostics / mcp__ide__executeCode unless you know it exists.", "An allowlist entry for mcp__ide__executeCode only lets Claude PROPOSE running a notebook cell; the in-VS-Code Quick Pick is a separate, always-on confirmation that actually runs it.", "While the IDE MCP is connected the CLI sends your current selection and active file path with every prompt — sensitive files leak into context unless you add a Read deny rule.", "With auto-edit enabled, Claude can modify VS Code config files (settings.json, tasks.json) that VS Code may execute automatically — a code-execution risk with untrusted workspaces.", "The extension subset of commands/skills differs from the CLI; some commands you rely on may simply not exist in the panel (type / to see what's available).", "/usage figures are computed only from local sessions on this machine — usage from other devices or claude.ai is not counted, so it under-reports team/multi-device usage.", "Resuming claude.ai cloud sessions requires Claude.ai Subscription sign-in (not Console), only shows web sessions started with a GitHub repo, and does not sync changes back.", "If ANTHROPIC_API_KEY is set but the sign-in prompt still appears, VS Code didn't inherit the shell environment — launch via 'code .' from a terminal.", "On macOS Tahoe+, the system Game Overlay shortcut steals Cmd+Esc (Focus Input) before VS Code sees it.", "The '!' bash shortcut and tab completion are not available in the extension; background-process visibility is limited vs the CLI (have Claude print the command to run it in the integrated terminal).", "Cloud sessions ignore all local config (settings, tools, env) — only the repo is cloned; anything in your local setup won't be present.", "Closing the browser tab does NOT stop a cloud session — it keeps running in the background by design until the task finishes.", "Environment variable values must not be quoted in the .env field — quotes become part of the stored value.", "Environment variables are visible to anyone who can edit the environment (not a per-user secret store).", "Setup scripts referencing files/paths absent from a fresh clone, or commands needing different invocation on Ubuntu, will fail and block session start (non-zero exit blocks startup).", "A heavy setup script silently pushes past the ~5-minute cache budget and makes new sessions hang or fail with a generic container error.", "'/web-setup' typed in the shell returns 'Unknown command' — it must be run inside the Claude Code CLI; 'Unknown command' inside the CLI means CLI < v2.1.80 or you're on an API key / third-party provider instead of claude.ai.", "Cloud sessions lack Ask and Bypass permission modes available in the terminal CLI.", "A repo can appear in cloud sessions without the GitHub App installed, but Auto-fix won't work unless the App is installed on that specific repo.", "ZDR-enabled orgs are entirely blocked from cloud session features.", "`claude -p --worktree` skips the trust check AND is never auto-cleaned (no exit prompt) — these orphan worktrees must be removed with `git worktree remove`.", "First interactive `--worktree` use fails with an error unless you've already run `claude` once in that directory to accept the workspace trust dialog.", "Worktrees created with `--worktree` are never removed by the `cleanupPeriodDays` sweep — only subagent/background-session worktrees are swept (and only if fully clean).", "Configuring a `WorktreeCreate` hook silently disables `.worktreeinclude` processing for `--worktree`; you must copy env/secrets files in the hook yourself or they'll be missing.", "`worktree.baseRef` only accepts `\"fresh\"` or `\"head\"` — passing an arbitrary git ref won't work.", "Default `fresh` baseRef branches from origin/HEAD, so a worktree will NOT contain your unpushed local commits unless you set baseRef to `head` or branch from a PR.", "Removing a worktree with changes (via prompt or `git worktree remove --force`) discards uncommitted changes, untracked files, and commits.", "Running agents lock their worktree (`git worktree lock`), so cleanup/removal is blocked until the agent finishes."], "claims": ["Channels are an MCP server (installed as a plugin) that pushes events into a running Claude Code session so Claude can react while you're away; can be two-way (Claude replies through the same channel).", "Channels are in research preview and require Claude Code v2.1.80 or later; the --channels flag syntax and protocol contract may change.", "Channels require Anthropic authentication via claude.ai or a Console API key; NOT available on Amazon Bedrock, Google Vertex AI, or Microsoft Foundry.", "Enable a channel per-session with: claude --channels plugin:<name>@<marketplace> . Multiple plugins can be passed space-separated.", "Being in .mcp.json is NOT enough to push messages — a server must also be explicitly named in --channels for that session.", "Two managed settings govern channels, unoverridable by users: channelsEnabled (master switch, must be true for any channel to deliver) and allowedChannelPlugins (restricts which plugins can register).", "Default differs by auth: claude.ai Team and Enterprise block channels until an admin enables them; Anthropic Console with API key auth permits channels by default (unless the org deploys managed settings, then blocked until channelsEnabled is set).", "Pro/Max users without an organization skip enterprise checks entirely; channels available, opt in per session with --channels.", "Admins enable via claude.ai → Admin settings → Claude Code → Channels toggle, or set channelsEnabled:true in managed settings.", "allowedChannelPlugins is a JSON array of {marketplace, plugin} entries; when set it REPLACES the Anthropic-maintained allowlist entirely (only listed plugins register). Only applies when channelsEnabled is true.", "An empty allowedChannelPlugins array blocks all allowlist plugins, but --dangerously-load-development-channels can still bypass it. To block channels including the dev flag, leave channelsEnabled unset.", "If channelsEnabled is disabled/unset, the MCP server still connects and its tools work, but channel messages won't arrive; a startup warning tells the user to ask an admin to enable it.", "Each channel plugin maintains a sender allowlist: only added sender IDs can push messages; everyone else is silently dropped. Telegram/Discord bootstrap via pairing code; iMessage self-chat bypasses the gate.", "The sender allowlist also gates permission relay if the channel declares it — anyone who can reply through the channel can approve/deny tool use in your session.", "Channel plugins are Bun scripts and require Bun installed (bun --version to check).", "Plugin tokens are saved to ~/.claude/channels/<name>/.env (e.g. telegram/.env, discord/.env); can also set TELEGRAM_BOT_TOKEN / DISCORD_BOT_TOKEN in shell env before launch.", "After installing a channel plugin run /reload-plugins to activate its configure command. Marketplace fixes: /plugin marketplace update claude-plugins-official or /plugin marketplace add anthropics/claude-plugins-official.", "iMessage channel reads ~/Library/Messages/chat.db directly and requires macOS Full Disk Access for the terminal; without it the server exits with 'authorization denied'. Replies use AppleScript (triggers an Automation prompt).", "In non-interactive mode (-p) with channels, tools needing terminal input (multiple-choice questions, plan mode approval) are disabled so the session never stalls.", "For unattended use, --dangerously-skip-permissions bypasses prompts other than explicit ask rules; channel servers with the permission relay capability can forward prompts for remote approve/deny.", "Supported channels in the preview: Telegram, Discord, iMessage; plus fakechat (localhost demo at http://localhost:8787) and custom channels via --dangerously-load-development-channels.", "During preview, --channels only accepts plugins from the Anthropic-maintained allowlist (claude-plugins-official) or the org's allowedChannelPlugins; off-list plugins cause Claude to start normally but the channel doesn't register, with a startup notice.", "A channel is an MCP server that runs on the same machine as Claude Code, spawned as a stdio subprocess, that pushes external events (webhooks, alerts, chat messages) into the session via 'notifications/claude/channel' so Claude can react.", "Channels are in research preview and require Claude Code v2.1.80 or later.", "Permission relay (forwarding tool-approval prompts to a remote channel) requires Claude Code v2.1.81 or later; earlier versions ignore the 'claude/channel/permission' capability.", "Team and Enterprise organizations must explicitly enable channels; an admin org policy 'channelsEnabled' gates them. If disabled, registering a channel fails with 'blocked by org policy'.", "On Team and Enterprise plans, an admin can set an 'allowedChannelPlugins' list that replaces the default Anthropic allowlist, controlling which channel plugins can run org-wide.", "To register as a channel an MCP server must declare capability 'capabilities.experimental[\"claude/channel\"]' = {} (presence registers the notification listener).", "Optional capability 'capabilities.experimental[\"claude/channel/permission\"]' = {} declares the channel can receive permission relay requests (remote approve/deny of tool use).", "Two-way channels add standard MCP 'capabilities.tools' = {} plus ListTools/CallTool handlers to expose a reply tool; one-way channels omit tools.", "The server 'instructions' string is injected into Claude's system prompt; it should describe the <channel> tag attributes, whether to reply, and which tool/attribute (e.g. chat_id) to route replies through.", "Register a channel server in MCP config: project-level '.mcp.json' (relative path allowed) or user-level '~/.claude.json' (use absolute path). Format: {\"mcpServers\":{\"name\":{\"command\":\"bun\",\"args\":[\"./webhook.ts\"]}}}.", "Only the '@modelcontextprotocol/sdk' npm package and a Node-compatible runtime (Bun, Node, or Deno) are required to build a channel; bundled preview plugins use Bun but it is not required.", "During research preview every channel must be on the Anthropic-curated approved allowlist (channel plugins in claude-plugins-official). Custom/community-marketplace channels are NOT on it and require the '--dangerously-load-development-channels' flag to run.", "Enable a specific channel for a session with '--channels plugin:<name>@<marketplace>' or '--channels server:<name>'. Development testing uses 'claude --dangerously-load-development-channels server:webhook' or 'plugin:yourplugin@yourmarketplace'.", "'--dangerously-load-development-channels' bypasses the allowlist per-entry only; combining it with '--channels' does not extend the bypass to --channels entries. It skips the allowlist only and the 'channelsEnabled' org policy still applies.", "First use of a new MCP server from .mcp.json prompts per-project consent: dialog 'New MCP server found in this project: <name>' with 'Use this MCP server'.", "Channel events arrive wrapped in a <channel> tag; 'source' attribute is set automatically from the server name, 'content' becomes the tag body, and each 'meta' key becomes a tag attribute.", "meta keys must be identifiers (letters, digits, underscores only); keys containing hyphens or other characters are silently dropped.", "Notifications are not acknowledged: mcp.notification()'s await resolves when written to transport, not when Claude processes it. If the channel isn't loaded or org policy blocks it, events are dropped silently with no error to the server.", "Events queue and are processed in order; multiple notifications arriving while Claude is busy are delivered together on the next turn and handled as a group. Use separate sessions for concurrent independent event streams.", "Permission relay covers tool-use approvals (Bash, Write, Edit). Project trust and MCP server consent dialogs do NOT relay and only appear in the local terminal.", "Permission request notification 'notifications/claude/channel/permission_request' params: request_id, tool_name, description, input_preview (JSON args truncated to 200 chars). request_id is five lowercase letters from a-z excluding 'l'.", "The verdict is sent back via 'notifications/claude/channel/permission' with request_id (echoed) and behavior 'allow' or 'deny'. Neither verdict affects future calls. Claude Code only accepts a verdict whose ID matches an open request; mismatched IDs are dropped silently.", "Local terminal dialog and remote relay stay live simultaneously; the first answer to arrive (terminal or remote) is applied and the other is dropped.", "Debug/stderr trace for a failed channel server is at '~/.claude/debug/<session-id>.txt'; use '/mcp' in-session to check server connection status.", "In-app plugin submission forms add plugins to the community marketplace, which is NOT on the channel allowlist; official-marketplace listing requires coordinating with an Anthropic partner contact.", "Claude Code on the web is in research preview for Pro, Max, and Team users, and for Enterprise users with premium seats or Chat + Claude Code seats. It runs at claude.ai/code on Anthropic-managed cloud infrastructure.", "Two GitHub auth methods: (1) GitHub App authorized during web onboarding (required for Auto-fix PR webhooks); (2) run /web-setup in terminal to sync local gh CLI token to your Claude account.", "App installation is NOT a session-level access control: a cloud session can access any repository the connecting GitHub account can see, not just repos the App is installed on. To restrict repo reach, restrict access on GitHub itself (team/repo membership).", "Team and Enterprise admins can disable /web-setup with the 'Quick web setup' toggle at claude.ai/admin-settings/claude-code.", "Organizations with Zero Data Retention enabled cannot use /web-setup or other cloud session features.", "What carries over to cloud sessions (because it's in the repo clone): repo CLAUDE.md, repo .claude/settings.json hooks, repo .mcp.json MCP servers, repo .claude/rules/, repo .claude/skills/, .claude/agents/, .claude/commands/, and plugins declared in repo .claude/settings.json.", "What does NOT carry over: user ~/.claude/CLAUDE.md, user ~/.claude/skills/agents/commands, plugins enabled only in user settings (enabledPlugins in ~/.claude/settings.json), MCP servers added via 'claude mcp add' (write to local user config), static API tokens/credentials, and interactive auth like AWS SSO.", "To make config available in cloud: commit it to the repo. Declare MCP servers in repo .mcp.json (project scope), declare plugins in repo .claude/settings.json, commit user skills/agents/commands to repo .claude/.", "Skills you enable on claude.ai are loaded into cloud sessions automatically (unlike user ~/.claude/skills which do not carry over).", "No dedicated secrets store exists yet. Both environment variables and setup scripts are stored in the environment configuration and are visible to anyone who can edit that environment.", "Each session runs in a fresh isolated Anthropic-managed VM (Ubuntu 24.04) with the repo cloned. Setup scripts run as root.", "Cloud session resource ceilings (approximate, may change): 4 vCPUs, 16 GB RAM, 30 GB disk. Memory-intensive jobs may fail/be terminated; use Remote Control on your own hardware for larger workloads.", "Pre-installed runtimes/tools include Python 3.x (pip/poetry/uv/black/mypy/pytest/ruff), Node 20/21/22 via nvm (npm/yarn/pnpm/bun/eslint/prettier/chromedriver), Ruby 3.1-3.3, PHP 8.4, OpenJDK 21 (Maven/Gradle), Go, Rust, C/C++ toolchains, Docker/compose, PostgreSQL 16, Redis 7.0, git/jq/yq/ripgrep/tmux/vim/nano. Run 'check-tools' in a cloud session for exact versions (command only exists in cloud).", "gh CLI is NOT pre-installed. Built-in GitHub tools (read issues, list PRs, fetch diffs, post comments) authenticate via the GitHub proxy so your token never enters the container. For gh release/workflow run, install gh in setup script (apt install -y gh) and set GH_TOKEN env var (gh reads it automatically).", "PostgreSQL and Redis are pre-installed but NOT running by default; start with 'service postgresql start' / 'service redis-server start' per session.", "Setup scripts: Bash, run as root before Claude Code launches, only when no cached environment exists. Configured in cloud environment UI (per environment). Keep total runtime under ~5 minutes so the cache can build. Non-zero exit causes session to fail to start; append '|| true' to non-critical commands. Parallelize installs with '&' and 'wait'.", "Environment caching: after setup script completes, Anthropic snapshots the filesystem and reuses it; later sessions skip the setup step. Cache captures files only, not running processes/containers. Setup script re-runs when you change the setup script or allowed network hosts, or when cache expires (~7 days). Resuming an existing session never re-runs the setup script.", "SessionStart hooks (repo .claude/settings.json) run in BOTH local and cloud, after Claude Code launches, on every session including resumed. They add startup latency (no caching benefit). User-level ~/.claude/settings.json SessionStart hooks do NOT carry over to cloud.", "CLAUDE_CODE_REMOTE=true is set in cloud sessions; check it in a SessionStart hook to skip local execution (e.g. exit 0 when not 'true'). To persist env vars for later Bash commands, write to the file at $CLAUDE_ENV_FILE.", "Replacing the base image with your own Docker image is NOT supported. Use a setup script on top of the provided image, or run your image as a container via docker compose.", "Network access levels per environment: None (no outbound), Trusted (default; allowlisted package registries/GitHub/cloud SDKs), Full (any domain), Custom (your allowlist, optionally including defaults). Custom uses one domain per line with '*.' wildcard subdomain matching, plus a checkbox to also include the default package-manager list.", "None network access breaks setup scripts and SessionStart hooks that install packages (can't reach registries). Trusted covers npm, PyPI, RubyGems, crates.io and many others.", "All outbound traffic passes through an HTTP/HTTPS security proxy (abuse prevention, content filtering, DNS-level audit of hostnames). Some package managers don't work with this proxy; Bun is a known broken example for package fetching.", "GitHub operations use a separate dedicated proxy independent of the network access level. Inside the sandbox git authenticates with a scoped credential the proxy translates to your real token. The proxy RESTRICTS git push to the current working branch only.", "MCP connector traffic is routed through Anthropic's servers, so enabled connectors work without adding their hosts to Allowed domains. Connectors are configured per session or per routine; remove unneeded ones to limit reachable tools.", "'claude --remote \"<task>\"' creates a NEW cloud session for the current repo, cloning the current branch from GitHub (push local commits first). Works one repo at a time. Each --remote command is an independent session, so multiple run in parallel; monitor with /tasks.", "--remote (create cloud session) is unrelated to --remote-control (expose a local CLI session for web monitoring, see Remote Control).", "Session handoff from CLI is one-way: pull cloud sessions into terminal with --teleport, but you cannot push an existing terminal session to web from the CLI. The Desktop app has a 'Continue in' menu that can send a local session to web.", "Pull a cloud session locally with 'claude --teleport' (interactive picker) or 'claude --teleport <session-id>'; or /teleport (alias /tp) inside a session; or press 't' in /tasks; or 'Open in CLI' from web. --teleport differs from --resume (which only reopens local history and doesn't list cloud sessions).", "Teleport requirements: clean git working dir (prompts to stash), same repository checkout (not a fork), the cloud branch must have been pushed to remote, and same claude.ai account. --teleport requires claude.ai subscription auth; API key/Bedrock/Vertex/Foundry auth must /login with claude.ai account.", "Send local repos without GitHub: 'claude --remote' from a non-GitHub repo bundles and uploads the local repo (full history all branches + uncommitted tracked changes). Force with CCR_FORCE_BUNDLE=1. Limits: must be a git repo with >=1 commit; bundle under 100 MB (falls back to current branch only, then squashed snapshot); untracked files excluded (git add first); bundled sessions can't push back unless GitHub auth is configured.", "Context commands in cloud: /compact works (accepts focus instructions e.g. '/compact keep the test output'), /context works, /clear does NOT (start a new session from the sidebar). Interactive picker commands like /model and /config are unavailable in cloud.", "Auto-compaction runs automatically near capacity. Set CLAUDE_AUTOCOMPACT_PCT_OVERRIDE (e.g. 70) in environment variables to compact earlier; CLAUDE_CODE_AUTO_COMPACT_WINDOW changes the effective window size for compaction calculations.", "Subagents work the same as locally; repo .claude/agents/ are picked up automatically. Agent teams are OFF by default in cloud; enable by adding CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 to environment variables.", "As of v2.1.179 web-session commits include a 'Claude-Session: <url>' git trailer and PR bodies include the session URL. From v2.1.182, set attribution.sessionUrl=false to omit both. Session id is in CLAUDE_CODE_REMOTE_SESSION_ID; build a transcript link by replacing the 'cse_' prefix with 'session_'.", "Auto-fix PRs requires the Claude GitHub App installed. Enable via the CI status bar 'Auto-fix' toggle on web, /autofix-pr from terminal on the PR branch, the mobile app, or by pasting a PR URL. It's a per-PR toggle.", "Auto-fix cannot react to merge conflicts on its own because GitHub emits no webhook when the base branch advances; open the session and ask Claude to rebase.", "Auto-fix replies to PR review threads are posted under YOUR GitHub account (labeled as from Claude Code). This can trigger issue_comment-based automation (Atlantis, Terraform Cloud, custom Actions).", "Session sharing visibility: Enterprise/Team accounts choose Private or Team (Team visibility shows session to org members; repository access verification enabled by default; Claude in Slack sessions auto-share with Team visibility). Max/Pro accounts choose Private or Public (Public = visible to any claude.ai user; repo access verification NOT enabled by default).", "Sharing settings (require recipient repo access, hide your name) are at Settings > Claude Code > Sharing settings. Shared-session recipients see latest state on open but the view does not update in real time.", "Cloud sessions share rate limits with all other Claude/Claude Code usage in the account; parallel tasks consume proportionately more. There is no separate compute charge for the cloud VM.", "Platform restrictions: cloning and PR creation require GitHub. Self-hosted GitHub Enterprise Server is supported for Team/Enterprise. GitLab/Bitbucket/non-GitHub repos can be sent as a local bundle but cannot push results back.", "Organization IP allowlisting breaks cloud sessions (and Code Review, Routines): cloud sessions call the Anthropic API from Anthropic-managed infrastructure, not your network, so every session fails with an auth error. Contact Anthropic support to exempt Anthropic-hosted services.", "Even with network access disabled (None), Claude Code can still communicate with the Anthropic API, which may allow data to exit the VM.", "Cloud sessions stop after inactivity and the environment is reclaimed ('environment has expired'); reopen from claude.ai/code to provision a fresh environment with conversation history restored. Sensitive credentials (git creds, signing keys) are never inside the sandbox; auth is via secure proxy with scoped credentials.", "Set the default environment for --remote with '/remote-env' in the terminal; add/edit/archive environments only from the web interface. Environment variables use .env format (KEY=value per line); do NOT wrap values in quotes (quotes become part of the value).", "Computer use is a macOS-only research preview that requires a Pro or Max plan; it is NOT available on Team or Enterprise plans.", "Computer use requires Claude Code v2.1.85 or later (check with `claude --version`).", "Computer use requires an interactive session; it is NOT available in non-interactive mode with the `-p` flag.", "Computer use is exposed as a built-in MCP server named `computer-use`, off by default, enabled via `/mcp` → select `computer-use` → Enable.", "The `computer-use` enable setting persists per project (enable once per project).", "First use prompts for two macOS permissions: Accessibility (click/type/scroll) and Screen Recording (see screen); macOS may require restarting Claude Code after granting Screen Recording.", "Tool precedence: Claude prefers the most precise tool first — MCP server for the service > Bash for shell commands > Claude in Chrome for browser work > computer use as the broadest/slowest fallback.", "App access is per-session: each new app needs approval ('Allow for this session' or 'Deny'); approvals last only for the current session; multiple apps can be approved together.", "Control level varies by app category: browsers and trading platforms are view-only, terminals and IDEs are click-only, everything else gets full control.", "Sentinel warnings flag high-reach apps before approval: 'Equivalent to shell access' (Terminal, iTerm, VS Code, Warp, IDEs), 'Can read or write any file' (Finder), 'Can change system settings' (System Settings).", "Computer use holds a machine-wide lock — only one Claude session can control the machine at a time; new attempts fail and name the holding session; the lock auto-releases if the holding process crashes.", "While Claude works, other visible apps are auto-hidden; the terminal window stays visible and is excluded from screenshots; hidden apps restore automatically at end of turn.", "Screenshots are auto-downscaled before being sent to the model (e.g. 3456×2234 → ~1372×887, aspect preserved); there is no setting to change the target size.", "Stop computer use anytime with `Esc` (anywhere) or `Ctrl+C` (terminal); the Esc keypress is consumed so prompt injection can't dismiss dialogs.", "Computer use is unavailable with third-party providers (Amazon Bedrock, Google Cloud Vertex AI, Microsoft Foundry); you must be authenticated through claude.ai.", "Computer use in the CLI is macOS-only (not Linux/Windows); on Windows use computer use in the Desktop app.", "CLI vs Desktop differences: Desktop supports macOS+Windows and has a configurable denied-apps list and optional auto-unhide toggle; CLI has no denied-apps list yet and auto-unhide is always on.", "Unlike the sandboxed Bash tool, computer use runs on the actual desktop with access to approved apps (different trust boundary).", "Deep links require Claude Code v2.1.91 or later.", "A deep link is a `claude-cli://` custom URL scheme that opens Claude Code in a new terminal window with a pre-filled working directory and prompt; the prompt is populated but NOT sent until the user presses Enter.", "The only accepted path is `claude-cli://open`; the minimal form `claude-cli://open` opens in the home directory with an empty prompt.", "Parameter `q` pre-fills the prompt box; value must be URL-encoded (encodeURIComponent), use `%0A` for line breaks; maximum 5,000 characters.", "Parameter `cwd` sets an absolute working directory path; network and UNC paths are rejected.", "Parameter `repo` takes a GitHub `owner/name` slug and resolves to a local clone Claude Code has previously seen; if no matching clone exists, the session opens in the home directory.", "If both `cwd` and `repo` are passed, `cwd` takes precedence and `repo` is ignored — even if the `cwd` path does not exist.", "`repo` lookup: each time you run `claude` in a Git repo, that directory's path is recorded against the repo's GitHub slug; the deep link opens the most-recently-used matching path; multiple clones/worktrees are tracked separately. Only paths where claude has run at least once are found.", "A deep link never executes anything on its own — it only selects a directory and fills the prompt; nothing reaches the model until the user presses Enter.", "A launched session shows a warning line `Prompt from an external link` below the input box until the prompt is sent or cleared; for prompts over 1,000 characters the warning includes the character count and tells the user to scroll and review.", "Permission rules, CLAUDE.md, and directory trust prompts apply to deep-link sessions the same as any other session.", "To disable handler registration, set `disableDeepLinkRegistration` to `\"disable\"` in settings.json.", "To enforce disabling org-wide so users cannot re-enable it, set `disableDeepLinkRegistration` in managed settings (server-managed-settings) instead of settings.json.", "The `claude-cli://` handler is registered automatically the first time an interactive session starts on macOS, Linux, or Windows — no separate install command; registration writes to user-level locations only.", "Handler locations: macOS `~/Applications/Claude Code URL Handler.app`; Linux `claude-code-url-handler.desktop` under `$XDG_DATA_HOME/applications` (default `~/.local/share/applications`); Windows registry `HKEY_CURRENT_USER\\Software\\Classes\\claude-cli`.", "GitHub-rendered Markdown strips non-http(s) URL schemes: `[label](claude-cli://...)` in READMEs, issues, PRs, and wikis renders as plain text with the link removed. Workaround: put the deep link in a code block so readers can copy-paste it.", "Shell invocation of a deep link: macOS `open \"claude-cli://...\"`; Linux `xdg-open \"claude-cli://...\"`; Windows PowerShell `Start-Process \"claude-cli://...\"`; cmd.exe `start \"\" \"claude-cli://...\"` (empty title required because start treats the first quoted arg as a window title).", "Terminal selection: macOS reuses the terminal from your most recent interactive session (iTerm2, Ghostty, kitty, Alacritty, WezTerm, Terminal.app); Linux honors `$TERMINAL`, then `x-terminal-emulator`, then common emulators; Windows fixed order Windows Terminal > PowerShell > cmd.exe.", "The VS Code extension registers a separate handler `vscode://anthropic.claude-code/open` that opens a Claude Code editor tab instead of a terminal.", "The deep link does not change which branch is checked out; the session opens in whatever current state that directory is in.", "Permission modes map to settings keys: Ask permissions=`default`, Auto accept edits=`acceptEdits`, Plan mode=`plan`, Auto=`auto`, Bypass permissions=`bypassPermissions`. `dontAsk` mode is CLI-only, not available in Desktop.", "Bypass permissions mode is equivalent to the CLI `--dangerously-skip-permissions` flag; it still honors explicit `ask` permission rules. It must be enabled in Settings → Claude Code → 'Allow bypass permissions mode' and enterprise admins can disable it.", "Auto mode is a research preview requiring Claude Opus 4.6+ or Sonnet 4.6 on the Anthropic API. On enterprise Vertex AI deployments it is off until `CLAUDE_CODE_ENABLE_AUTO_MODE` is set, and only Opus 4.7 and 4.8 are supported there.", "Admins distribute SSH connections via `sshConfigs` in a managed settings file; each entry requires `id`, `name`, `sshHost` (optional: `sshPort`, `sshIdentityFile`, `startDirectory`). Managed connections appear in the dropdown but users cannot edit/delete them. Users can also add `sshConfigs` to their own `~/.claude/settings.json`.", "`sshHostAllowlist` (in managed settings only — user/project values ignored) restricts Desktop SSH sessions to matching resolved hostnames; an empty array disables SSH entirely. Patterns are case-insensitive: `*` matches any host, `*.example.com` matches example.com and subdomains, else exact match. Checked against hostname after `~/.ssh/config` resolution via `ssh -G`.", "`sshHostAllowlist` is honored only by the Desktop app — the CLI and IDE extensions do not read it, and it does not restrict `ssh` commands run through the Bash tool. It governs Desktop connections, not network egress.", "Managed settings keys for Desktop: `permissions.disableBypassPermissionsMode`=\"disable\", `disableAutoMode`=\"disable\" (also accepted under `permissions`), `autoMode` (classifier config), `sshConfigs`, `sshHostAllowlist`, `managedMcpServers`. Managed settings override project and user settings.", "`managedMcpServers` pushes MCP server configs to all users in third-party (3P) Desktop deployments only; each entry specifies transport `http`/`sse`/`stdio`, connection details, and an optional `toolPolicy` map restricting which tools users can invoke.", "`autoMode` is read from user settings, `.claude/settings.local.json`, and managed settings, but NOT from checked-in `.claude/settings.json` — a cloned repo cannot inject its own auto-mode classifier rules.", "A managed settings file deployed to disk on each machine applies to Desktop sessions. Managed settings pushed remotely via the admin console currently reach CLI and IDE sessions only, not Desktop — for Desktop, distribute the file via MDM or use admin console controls.", "Admin console (claude.ai/admin-settings/claude-code) controls: 'Code in the desktop', 'Code in the web', 'Remote Control', and 'Disable Bypass permissions mode'. Available on Team/Enterprise plans.", "Device management: macOS via `com.anthropic.claudefordesktop` preference domain (Jamf/Kandji); Windows via registry `SOFTWARE\\Policies\\Claude`. Policies include enable/disable Claude Code, control auto-updates, set custom deployment URL.", "Desktop deployment: macOS via MDM (.dmg); Windows via MSIX package or .exe (supports silent install).", "Desktop and CLI share config: CLAUDE.md and CLAUDE.local.md, MCP servers in `~/.claude.json` or `.mcp.json`, hooks and skills, and settings in `~/.claude.json` and `~/.claude/settings.json`. Permission rules in settings.json apply to Desktop sessions. Each maintains separate session history.", "Desktop loads MCP servers from `claude_desktop_config.json` into Code tab sessions, alongside `~/.claude.json` and `.mcp.json`. The standalone CLI does NOT read `claude_desktop_config.json`; on macOS/WSL run `claude mcp add-from-claude-desktop` to import them into `~/.claude.json`.", "Each Git-repo session gets its own isolated copy via Git worktrees, stored in `<project-root>/.claude/worktrees/` by default (configurable in Settings → Claude Code 'Worktree location'); a branch prefix can be set. Session isolation requires Git installed.", "To copy gitignored files (e.g. `.env`) into new worktrees, create a `.worktreeinclude` file in the project root.", "When context fills, Claude auto-summarizes and continues; type `/compact` to trigger summarization earlier. Context usage is per-session; plan usage is shared across all Claude Code surfaces.", "Preview/dev-server config lives in `.claude/launch.json` at the selected folder root (JSON-with-comments). Fields per configuration: `name`, `runtimeExecutable`+`runtimeArgs`, `port` (default 3000), `cwd`, `env`, `autoPort`, `program`+`args`. Use `program` to run a script with node; `runtimeExecutable` to start via a package manager.", "`autoPort`: true=pick a free port automatically (passes assigned port via `PORT` env var), false=fail on conflict (use for OAuth callbacks/CORS), unset=ask once and save the answer. Do not put secrets in `env` (the file is committed); set secrets in the local environment editor instead.", "`autoVerify` defaults to on (Claude screenshots/checks/verifies after each edit). Disable per-project with `\"autoVerify\": false` at top level of `.claude/launch.json` or via the Preview dropdown.", "On macOS, launching from Dock/Finder reads `~/.zshrc`/`~/.bashrc` only for PATH and a fixed set of Claude Code vars — other exported vars are NOT picked up. On Windows it inherits user/system env vars but does not read PowerShell profiles. Use the local environment editor (env dropdown → Local → gear) for vars that reach both sessions and dev servers; the `env` key in `~/.claude/settings.json` reaches Claude sessions only, not dev servers.", "Extended thinking is on by default. Set `MAX_THINKING_TOKENS=0` to disable (no effect on Fable 5, which always thinks; on third-party providers 0 omits the `thinking` param; ignored on adaptive-reasoning models). On Opus 4.6/Sonnet 4.6 set `CLAUDE_CODE_DISABLE_ADAPTIVE_THINKING=1` for a fixed budget; Opus 4.7+ always use adaptive reasoning with no fixed-budget mode.", "PR monitoring uses the GitHub CLI (`gh`), which must be installed and authenticated. Auto-merge uses squash merge and requires auto-merge enabled in GitHub repo settings. Auto-fix reads CI failure output and iterates.", "Terminal-dialog commands (`/permissions`, `/config`, `/agents`, `/doctor`) are NOT available in the Code tab and reply 'isn't available in this environment'; edit settings files directly or run them from the standalone CLI.", "Desktop is interactive only: `--print`/`--output-format` (scripting/headless) and the Agent SDK are not available. Agent teams (parallel sessions messaging each other) are CLI-only; for multi-agent inside one Desktop session use dynamic workflows.", "`--allowedTools`/`--disallowedTools` have no per-session Desktop equivalent, but permission rules in settings files still apply. `--add-dir` maps to adding repos via the + button in cloud sessions only.", "Run `/desktop` in the terminal CLI to migrate a session into Desktop (saves session, opens it, exits CLI). Available on macOS/Windows when signed in with a Claude subscription; NOT available with API key auth or on Bedrock/Vertex/Foundry. CLI and Desktop can run simultaneously on the same project.", "Desktop is not available on Linux (use the CLI). Computer use is a Pro/Max research preview on macOS/Windows, NOT available on Team or Enterprise plans. Dispatch also requires Pro/Max and is not on Team/Enterprise.", "Computer use app-control tiers are fixed by app category: browsers/trading=view only, terminals/IDEs=click only, everything else=full control. App approvals last the session (30 minutes in Dispatch-spawned sessions). Computer use is off by default; on macOS requires Accessibility + Screen Recording permissions.", "For managed-only settings including `allowManagedPermissionRulesOnly` and `allowManagedHooksOnly`, see the permissions managed-only settings reference.", "Cloud (Remote) sessions: only Accept edits/Plan/Auto modes (Accept edits corresponds to `default`); no Bypass permissions (already sandboxed), no @mention, no + button (no Connectors/Plugins UI), no terminal/file pane. Usage counts toward subscription plan limits with no separate compute charges. Support multiple repositories.", "Enterprise organizations can require SSO (SAML/OIDC) for all users. Plugins managed centrally by an org are available in Desktop the same as in the CLI; plugins are not available in cloud sessions.", "Claude Code requires a Pro, Max, Team, or Enterprise subscription; the Code tab prompts to upgrade if on a free plan.", "Desktop runs the same engine as the CLI and shares configuration with it: CLAUDE.md files, MCP servers, hooks, skills, and settings. CLI and Desktop can run simultaneously on the same project.", "The Code tab has three permission modes: Ask permissions (default, approval before every edit), Auto accept edits (auto-accepts file edits), and Plan mode (Claude maps an approach without touching files).", "Three environment options for Code sessions: Local (runs on your machine using your files), Remote (Anthropic cloud infra, same as Claude Code on the web, continues if app closed), and SSH (connects to remote machine; Desktop auto-installs Claude Code on the remote on first connect).", "Each session tracks its own context and changes; parallel sessions each run in their own Git worktree.", "On Windows, Git must be installed for local sessions to work. Desktop app is not available on Linux (use the CLI).", "The desktop app bundles Claude Code; Node.js and the CLI are not required separately. To use `claude` from the terminal you must install the CLI separately.", "Plugins (installed via the + button → Plugins) can add skills, agents, and MCP servers.", "Slash commands (typed with `/` or + → Slash commands) include built-in commands, custom skills, and plugin skills.", "Scheduled tasks can run Claude on a recurring cron-like basis (e.g. daily code review, weekly dependency audit).", "After a PR is opened, Claude Code monitors CI check results and can auto-fix failures or auto-merge once all checks pass.", "Long-running work can be sent to the cloud so it continues even if the app is closed; a session can be continued on the web or in an IDE.", "External tool connectors include GitHub, Slack, and Linear.", "The JetBrains plugin runs the `claude` command in the IDE's integrated terminal and connects to it; it does NOT bundle its own copy of the CLI, so both the CLI and the plugin must be installed separately.", "`Read` deny rules (from /en/permissions#read-and-edit) block the IDE's automatic sharing of the current selection/tab for matching files.", "IDE diagnostics (lint and syntax errors) are automatically shared with Claude as you work; the current selection or active tab is automatically shared with Claude Code.", "Configure diff display via `claude` → `/config` → set diff tool to `auto` (show diffs in IDE) or `terminal` (keep in terminal).", "Use `/ide` command in any external terminal to connect a running Claude Code session to the JetBrains IDE and activate integration features.", "Plugin settings live at Settings → Tools → Claude Code [Beta]; the 'Claude command' field sets a custom launch command/path (e.g. `claude`, `/usr/local/bin/claude`, or `npx @anthropic-ai/claude-code`).", "For WSL, set the Claude command to `wsl -d Ubuntu -- bash -lic \"claude\"` (replace Ubuntu with your distro name).", "For JetBrains Remote Development, the plugin MUST be installed on the remote host (Settings → Plugin (Host)), not on the local client machine.", "Insert file references like `@src/auth.ts#L1-99` via Cmd+Option+K (Mac) / Alt+Ctrl+K (Linux/Windows).", "Works with any paid Claude subscription (Pro, Max, Team, Enterprise) or a Claude Console account; no API key required.", "WSL2 'No available IDEs detected' is caused by WSL2 NAT networking or Windows Firewall blocking the WSL2↔IDE connection; WSL1 is unaffected. Fix via a Windows Firewall inbound rule for the WSL2 subnet, or switch to mirrored networking (`networkingMode=mirrored` in `.wslconfig`, requires Windows 11 22H2+).", "Remote Control connects claude.ai/code or the Claude mobile app (iOS/Android) to a Claude Code session running on your local machine; the session executes locally and the web/mobile UI is just a window into it. Nothing moves to the cloud (contrast with Claude Code on the web, which runs in Anthropic-managed cloud).", "Requires Claude Code v2.1.51 or later (check with `claude --version`). VS Code extension support requires v2.1.79+. Mobile push notifications require v2.1.110+.", "Available on Pro, Max, Team, and Enterprise plans. API keys are NOT supported. On Team and Enterprise it is OFF by default until an admin enables the Remote Control toggle at claude.ai/admin-settings/claude-code (a server-side org setting).", "Authentication: requires claude.ai OAuth via `/login` (or `claude auth login`). API-key auth and Console accounts cannot use Remote Control. Long-lived tokens from `claude setup-token` or `CLAUDE_CODE_OAUTH_TOKEN` are inference-only and cannot establish Remote Control sessions; a full-scope session token is required.", "If `ANTHROPIC_API_KEY` is set in the environment, it must be unset for Remote Control to work.", "Workspace trust required: run `claude` in the project directory at least once to accept the workspace trust dialog before using Remote Control.", "Three CLI invocation modes: (1) server mode `claude remote-control` — stays running, serves remote connections, supports multiple sessions; (2) interactive `claude --remote-control` (alias `--rc`), optionally `claude --remote-control \"My Project\"` — full local interactive session also controllable remotely; (3) `/remote-control` (alias `/rc`) inside an existing session — continues current conversation remotely. VS Code uses `/remote-control` or `/rc`.", "Server-mode flags: `--name \"My Project\"` (session title); `--remote-control-session-name-prefix <prefix>` (or env `CLAUDE_REMOTE_CONTROL_SESSION_NAME_PREFIX`, defaults to hostname); `--spawn <mode>` (`same-dir` default / `worktree` / `session`); `--capacity <N>` (max concurrent sessions, default 32, incompatible with `--spawn=session`); `--verbose`; `--sandbox` / `--no-sandbox` (sandboxing off by default).", "`--spawn=same-dir` (default): all sessions share the current working directory and can CONFLICT if editing the same files. `--spawn=worktree`: each on-demand session gets its own git worktree (requires a git repo). `--spawn=session`: single-session mode, rejects additional connections, set at startup only. Press `w` at runtime to toggle between same-dir and worktree.", "The `--verbose`, `--sandbox`, and `--no-sandbox` flags are NOT available with the `/remote-control` command (only with the CLI invocation).", "Connection security: the local session makes OUTBOUND HTTPS (port 443) only and never opens inbound ports. It registers with the Anthropic API and polls for work; all traffic is over TLS through the Anthropic API. Uses multiple short-lived credentials, each scoped to a single purpose and expiring independently.", "Enable for all sessions: run `/config` and set 'Enable Remote Control for all sessions' to true (or Desktop app Settings → Claude Code → Enable remote control by default). With it on, each interactive process registers one remote session; multiple processes each get their own session.", "Managed-settings override: an IT admin can disable Remote Control per-device via `disableRemoteControl` in managed settings files, independent of the org-wide admin toggle. The error message references `disableRemoteControl` when this is the cause.", "Mobile push notifications: configured via `/config` — 'Push when Claude decides' (proactive) and 'Push when actions required' (permission prompts/questions). Claude decides when to push; you can request one in-prompt (e.g. 'notify me when the tests finish'). No per-event configuration beyond the two toggles.", "Push notifications are skipped while you are typing in / focused on the connected terminal. As of v2.1.181, setting env `CLAUDE_CLIENT_PRESENCE_FILE` to a marker-file path extends this: pushes are skipped while that file exists (use a screen-lock listener to create on unlock, delete on lock).", "Commands available from mobile/web: `/compact`, `/clear`, `/context`, `/usage`, `/exit`, `/usage-credits`, `/recap`, `/reload-plugins`; `/mcp` (v2.1.166+, returns text summary plus `reconnect`/`enable`/`disable` subcommands — remote `/mcp reconnect` with no server name reconnects ALL failed/needs-auth servers); `/config` (v2.1.181+, pass `key=value` to set). Local-only (interactive picker) commands like `/plugin` and `/resume` work only from the local CLI.", "Session title precedence: (1) name passed to --name/--remote-control//remote-control, (2) `/rename` title, (3) last meaningful message in history, (4) auto-generated `<hostname-or-prefix>-graceful-unicorn`. As of v2.1.176 auto titles match conversation language or the `language` setting.", "Limitations: outside server mode, ONE remote session per interactive process. The local `claude` process must keep running — closing the terminal/VS Code ends the session. If the machine cannot reach the network for ~10 minutes, the session times out and the process exits. Starting an ultraplan session disconnects any active Remote Control session (both occupy the claude.ai/code interface, only one at a time).", "Admin toggle grayed out = org has a data-retention/compliance configuration incompatible with Remote Control; cannot be changed from the admin panel (contact Anthropic support).", "Voice dictation requires Claude Code v2.1.69+; tap mode requires v2.1.116+. Check with `claude --version`.", "Voice dictation is ONLY available when authenticated with a Claude.ai account. It is NOT available when Claude Code uses an Anthropic API key directly, Amazon Bedrock, Google Vertex AI, or Microsoft Foundry.", "Voice dictation is disabled entirely when the organization has HIPAA compliance enabled.", "Audio is streamed to Anthropic's servers for transcription (not processed locally). Transcription does not consume Claude messages/tokens and does not count toward `/usage` limits.", "Enable via `/voice` (toggle), `/voice hold`, `/voice tap`, or `/voice off`. Hold mode is the default.", "Voice dictation persists across sessions and can be set in the user settings file: {\"voice\": {\"enabled\": true, \"mode\": \"tap\"}}.", "`\"autoSubmit\": true` in the voice settings object auto-sends the prompt on key release (hold) when transcript is >=3 words. Tap mode auto-submits at >=3 words; shorter transcripts are inserted but not submitted.", "Tap-mode recording stops automatically after 15 seconds of silence or 2 minutes total.", "Dictation language uses the same `language` setting (BCP 47 code or language name) that controls Claude's response language; empty defaults to English. Set via `/config` or settings.", "Dictation key is bound to `voice:pushToTalk` in the `Chat` context (default `Space`), rebindable in ~/.claude/keybindings.json. Binding a custom key replaces the default Space binding (one key at a time).", "Voice dictation needs local microphone access; not available in Claude Code on the web, SSH sessions, or VS Code Remote (SSH, Dev Containers, Codespaces) because the mic is local while the extension runs remote.", "In WSL, voice dictation requires WSLg (included with WSL2 from Microsoft Store on Win 10/11); WSL1 is unsupported — run native Windows instead. WSLg routes audio via PulseAudio, so SoX needs `sudo apt install sox libsox-fmt-pulse` (plain `sox` pulls the ALSA backend which can't record on WSL).", "On Linux, if the native audio module can't load, Claude Code falls back to `arecord` (ALSA utils) or `rec` (SoX).", "Supported dictation languages: cs, da, nl, en, fr, de, el, hi, id, it, ja, ko, no, pl, pt, ru, es, sv, tr, uk.", "Claude Code settings shared between the VS Code extension and CLI live in ~/.claude/settings.json (allowed commands, environment variables, hooks, MCP servers); VS Code extension settings are separate and live in VS Code under Extensions → Claude Code.", "Add \"$schema\": \"https://json.schemastore.org/claude-code-settings.json\" to settings.json to get autocomplete and inline validation for all settings in VS Code.", "Plugin install scopes in VS Code: 'Install for you' (user scope, all projects), 'Install for this project' (project scope, shared with collaborators), 'Install locally' (local scope, only you, only this repo).", "Plugin/marketplace config is shared between extension and CLI (same CLI commands under the hood); /plugins opens the Manage plugins UI with Plugins and Marketplaces tabs. Restart Claude Code to apply plugin changes.", "MCP servers are added via the CLI 'claude mcp add' (extension cannot add servers); existing servers are managed in-panel with /mcp (enable/disable, reconnect, OAuth). Extension MCP support is 'Partial'.", "Example: claude mcp add --transport http github https://api.githubcopilot.com/mcp/ --header \"Authorization: Bearer YOUR_GITHUB_PAT\"", "The extension runs a built-in local MCP server named 'ide' that the CLI auto-connects to; it is hidden from /mcp. Relevant for PreToolUse hooks that allowlist MCP tools.", "The 'ide' MCP server exposes only two tools to the model: mcp__ide__getDiagnostics (read-only, returns Problems-panel diagnostics) and mcp__ide__executeCode (runs Python in active Jupyter kernel, writes). The other ~10 tools are internal RPC filtered out before reaching the model.", "mcp__ide__executeCode always shows a native Quick Pick (Execute/Cancel) per call; this is separate from PreToolUse hooks. An allowlist entry only lets Claude propose running a cell. It refuses when there is no active notebook, the ms-toolsai.jupyter extension is missing, or the kernel is not Python.", "The 'ide' MCP server binds to 127.0.0.1 on a random high port (not reachable from other machines); each activation generates a fresh random auth token stored in a lock file under ~/.claude/ide/ with 0600 perms in a 0700 dir.", "While the IDE MCP is connected, the CLI includes the current editor selection and active file path as context on each prompt (transcript shows '⧉ Selected N lines from <file>'). Adding a Read deny rule for a path (e.g. .env) excludes both the selected text and the open-file notice from reaching Claude.", "Extension setting claudeCode.initialPermissionMode (default 'default') sets default permission mode for new conversations: default, plan, acceptEdits, or bypassPermissions.", "Extension setting allowDangerouslySkipPermissions (default false) adds 'Bypass permissions' to the mode selector; documented for use only in sandboxes with no internet access.", "Extension setting respectGitIgnore (default true) excludes .gitignore patterns from file searches.", "Extension setting usePythonEnvironment (default true) activates the workspace's Python environment when running Claude (requires the Python extension).", "Extension setting environmentVariables (default []) sets env vars for the Claude process; docs say use Claude Code settings (settings.json) instead for shared config.", "Extension setting autosave (default true) auto-saves files before Claude reads or writes them.", "Extension setting disableLoginPrompt (default false) skips auth prompts; required step for third-party provider (Bedrock/Vertex/Foundry) setups, then configure provider in ~/.claude/settings.json.", "Extension setting claudeProcessWrapper sets the executable used to launch the Claude process; set it to a separately-installed claude binary if the extension build lacks one for your platform.", "Other extension settings: useTerminal (false), preferredLocation (panel; or sidebar), useCtrlEnterToSend (false), enableNewConversationShortcut (false), enableReopenClosedSessionShortcut (true), hideOnboarding (false).", "Extension and CLI share the same conversation history; continue an extension conversation in the CLI with 'claude --resume' (interactive picker).", "Installing the extension does NOT put 'claude' on PATH; the extension bundles a private CLI copy for its panel only. CLI-only features require the standalone CLI install.", "CLI-only features not in the extension: full command/skill set (extension has a subset), '!' bash shortcut, tab completion. MCP config is CLI-add-only. Checkpoints work in both.", "claude --worktree (-w) <name> starts Claude in an isolated git worktree with its own branch/files for parallel sessions without interference.", "Reference terminal output in prompts with @terminal:name where name is the terminal title; reference files/lines with @file#start-end (e.g. @app.ts#5-10).", "/usage opens Account & usage; flags behaviors accounting for >=10% of recent usage (cache misses, long context, subagent-heavy/highly-parallel sessions) with reduction tips, plus attribution tables per skill, subagent, plugin, MCP server. Requires Claude Code v2.1.174+. Figures are local-machine-only and approximate.", "Context indicator shows context-window usage; Claude auto-compacts when needed or you run /compact manually.", "Extension URI handler vscode://anthropic.claude-code/open accepts optional query params prompt (URL-encoded, pre-filled not submitted) and session (resume a session ID belonging to the open workspace).", "Resuming claude.ai cloud sessions in VS Code requires signing in with Claude.ai Subscription (not Anthropic Console); only web sessions started with a GitHub repo appear in the Remote tab; changes are not synced back to claude.ai.", "Editing proposed content directly in the diff view before accepting tells Claude you modified it, so it does not assume the file matches its original proposal.", "Browser automation uses @browser in the prompt and requires the Claude in Chrome extension v1.0.36+; Claude shares the browser's logged-in state.", "No API key required for any paid Claude subscription (Pro, Max, Team, Enterprise) or a Claude Console account; sign in on first open. VS Code 1.98.0+ required.", "/usage attribution and reduction-tip features require Claude Code v2.1.174 or later (as of this doc).", "Claude Code on the web is in research preview, available to Pro, Max, and Team users, and Enterprise users with premium seats or Chat + Claude Code seats.", "Cloud sessions run on Anthropic-managed cloud VMs (not your machine) and are driven from claude.ai/code in the browser or the Claude mobile app.", "Cloud sessions do NOT use your local config — only the repo is cloned. For work needing local config/tools, use local CLI or Remote Control.", "Cloud sessions require a GitHub repo (Claude GitHub App installed) OR you bundle a local repo via the --remote flag (no GitHub).", "An 'environment' controls per-session network access level and a setup script. Default network access level is 'Trusted', which allows common package registries (npm, PyPI, RubyGems) while blocking general internet; 'None' blocks all registries.", "Environment variables are set in .env format; do NOT wrap values in quotes (quotes are stored as part of the value). They are visible to anyone who can edit the environment.", "Setup script is an optional Bash script run before Claude Code launches (e.g. 'apt install -y gh'); its result is cached so it doesn't re-run every session.", "Cloud session setup-script build has a roughly five-minute time budget for building the environment cache; exceeding it causes sessions to hang/time out.", "Cloud permission modes available: Accept edits (default), Plan, Auto. Cloud sessions do NOT offer Ask permissions or Bypass permissions.", "/web-setup runs inside the Claude Code CLI (not the shell); it reads the local 'gh' token, links it to your Claude account, and creates a default cloud environment (Trusted access, no setup script) if none exists.", "/web-setup requires CLI v2.1.80 or newer and authentication with a claude.ai subscription (not an API key or third-party provider).", "Organizations with Zero Data Retention (ZDR) enabled cannot use /web-setup or other cloud session features.", "Enterprise orgs may need an admin to enable Claude Code on the web ('Not available for the selected organization' error); contact the Anthropic account team.", "Each task gets its own session and its own branch; multiple independent tasks can run in parallel without managing worktrees.", "Sessions persist across devices and keep running in the background after you close the tab/disconnect; they idle when the task finishes. Archive hides a session; delete removes it permanently.", "You can add multiple repositories to one cloud session to work across them.", "Sessions can be prefilled via claude.ai/code URL query params: prompt (alias q), prompt_url (cross-origin-allowed URL for long prompts, ignored if prompt set), repositories (alias repo, comma-separated owner/repo slugs), environment (name or ID). URL-encode each value.", "Inline diff comments queue until your next message and are bundled with it, giving Claude file:line context (e.g. 'at src/auth.ts:47').", "Auto-fix for a repo requires installing the Claude GitHub App on that repo (Settings → Applications → Claude → Configure → Repository access); but a cloud session can use any repo the connected GitHub account can see regardless of App install.", "From the CLI, --remote starts cloud sessions from the terminal and /schedule (Routines) sets up recurring tasks; /mobile shows a QR code to pair the mobile app.", "The '/web-setup creates cloud env automatically' fallback and 'No cloud environment available' error guidance are version-gated (auto-creation predates some CLIs; doc max-version markers ~2.1.100).", "`claude --worktree <name>` (alias `-w`) creates an isolated git worktree under `.claude/worktrees/<name>/` at the repo root, on a new branch named `worktree-<name>`, and starts Claude in it.", "Omitting the name (`claude --worktree`) auto-generates a name like `bright-running-fox`.", "Worktrees branch from the repo default branch `origin/HEAD` (clean tree matching remote). If no remote or fetch fails, they fall back to the current local `HEAD`.", "`worktree.baseRef` in settings accepts only `\"fresh\"` (default, branch from origin/HEAD) or `\"head\"` (branch from local HEAD, carrying unpushed commits/feature-branch state); arbitrary git refs are not accepted.", "`claude --worktree \"#1234\"` (PR number prefixed with `#`, or a full GitHub PR URL) fetches `pull/<number>/head` from origin and creates the worktree at `.claude/worktrees/pr-<number>`.", "A `.worktreeinclude` file at project root (using .gitignore syntax) copies matching files into new worktrees, but ONLY files that match a pattern AND are gitignored are copied (tracked files are never duplicated). Applies to --worktree, subagent worktrees, and desktop parallel sessions.", "Subagents can run in isolated worktrees via `isolation: worktree` in custom subagent frontmatter, or by asking Claude to 'use worktrees for your agents'. They use the same baseRef as --worktree.", "Claude can create a worktree mid-session via the `EnterWorktree` tool; once in a worktree it can switch to another under `.claude/worktrees/` by calling `EnterWorktree` with the target path. The previous worktree stays on disk untouched.", "Before first interactive `--worktree` use in a directory, you must accept the workspace trust dialog by running `claude` once there; otherwise `--worktree` exits with an error. Non-interactive `claude -p --worktree` skips the trust check and proceeds.", "Cleanup on exit: with no uncommitted changes, no untracked files, and no new commits, the worktree and branch are removed automatically (unless the session is named, in which case Claude prompts). If changes/untracked/commits exist, Claude prompts to keep or remove.", "Non-interactive runs (`--worktree` with `-p`) are NOT cleaned up automatically (no exit prompt); remove manually with `git worktree remove`.", "Subagent and background-session worktrees are auto-removed once older than the `cleanupPeriodDays` setting, provided no uncommitted changes, no untracked files, no unpushed commits. Worktrees created with `--worktree` are NEVER removed by this sweep.", "While an agent runs, Claude runs `git worktree lock` on its worktree to prevent concurrent cleanup; the lock releases when the agent finishes. To force-remove a kept worktree: `git worktree remove --force`.", "`WorktreeCreate` and `WorktreeRemove` hooks fully replace the default git worktree logic, enabling non-git VCS (SVN, Perforce, Mercurial). WorktreeCreate reads the worktree name from stdin (JSON `.name`) and must print the directory path to stdout.", "When a `WorktreeCreate` hook is configured, `.worktreeinclude` is NOT processed for `--worktree`; you must copy local config files inside the hook script yourself.", "The desktop app creates a worktree for every new session automatically.", "Manual git worktrees: `git worktree add ../dir -b branch` (new branch), `git worktree add ../dir branch` (existing branch), `git worktree list`, `git worktree remove ../dir`."]}, "Automation, CI & integrations": {"pages": ["chrome", "cli-reference", "code-review", "desktop-scheduled-tasks", "github-actions", "github-enterprise-server", "gitlab-ci-cd", "headless", "routines", "scheduled-tasks", "slack", "tools-reference"], "bestPractices": ["Do not enable Chrome by default if context budget matters; pass `--chrome` only for sessions that need the browser, since always-on browser tools consume context.", "When asking Claude to read console logs, tell it specific patterns/error types to look for rather than dumping all console output, because logs are verbose and burn context.", "Use `/chrome` -> 'Reconnect extension' as the first recovery step when browser tools stop responding after an idle period.", "Restrict what browser automation can touch by configuring site-level permissions in the Chrome extension settings (the only place these are controlled).", "If the extension isn't detected on first setup, restart Chrome so it picks up the newly-installed native messaging host config.", "For CI/scripting, use `claude setup-token` to mint a long-lived OAuth token rather than embedding interactive auth; use `claude auth login --console` when you want Console API billing instead of subscription billing.", "In headless pipelines, bound runaway cost and loops with `--max-turns` and `--max-budget-usd` (both print-mode only), and force machine-parseable output with `--output-format json` (or stream-json for streaming).", "For shared multi-user scripted workloads, add `--exclude-dynamic-system-prompt-sections` with `-p` so per-machine info doesn't break prompt-cache reuse across users/machines.", "Speed up scripted invocations with `--bare` to skip discovery of hooks/skills/plugins/MCP/auto-memory/CLAUDE.md when those aren't needed.", "Scope tool access deliberately: `--allowedTools` for auto-approved patterns, `--disallowedTools` to remove tools from context, and `--tools` to restrict the available built-in set; combine `--strict-mcp-config` with `--mcp-config` (or omit --mcp-config) to fully control MCP exposure.", "Pin MCP servers for a team via `--mcp-config <file>` plus `--strict-mcp-config` so only the intended servers load, ignoring stray user-level MCP config.", "Control team config composition with `--setting-sources user,project,local` and override per-run keys with `--settings` (inline JSON or file) without rewriting settings.json files.", "Use `--append-system-prompt`/`--append-system-prompt-file` to layer extra rules while preserving default tool guidance and safety instructions; only use `--system-prompt`/`--system-prompt-file` (full replace) for non-coding pipeline agents where you take responsibility for safety guidance.", "Persist team conventions in CLAUDE.md and shareable personas in output styles rather than relying on per-invocation system-prompt flags.", "Isolate parallel/agentic work with `--worktree` (git worktrees under <repo>/.claude/worktrees/) and run background jobs via `--bg`, managing them with `claude agents --json`, `claude logs`, `claude attach`, and `claude daemon status`.", "When a configuration appears broken, start with `--safe-mode` to confirm whether a customization is the cause; note managed policy still applies so it isolates user/project customizations specifically.", "Add a repo-root REVIEW.md to control review behavior — it lands more reliably than rules buried in a long CLAUDE.md because it's injected at highest priority.", "In REVIEW.md, redefine what 🔴 Important means for the repo type (docs/config/prototype want a narrower definition than production code) so severity calibration matches the repo.", "Cap nit volume in REVIEW.md (e.g. 'report at most five nits, mention the rest as a count') to keep reviews actionable on prose/config repos.", "List skip rules in REVIEW.md for generated code, lockfiles, vendored deps, machine-authored branches, and anything CI already enforces (lint, spellcheck); for partial-scrutiny paths set a higher bar instead ('in scripts/, only report if near-certain and severe').", "Add a verification bar in REVIEW.md (e.g. 'behavior claims need a file:line citation, not an inference from naming') to cut false positives.", "Add a re-review convergence rule (e.g. 'after the first review, suppress new nits and post Important only') to stop one-line fixes from triggering style-only review loops.", "Keep REVIEW.md short — length dilutes the rules that matter; put general project context in CLAUDE.md, review-behavior changes in REVIEW.md.", "Choose Review Behavior per repo by cost/traffic tradeoff: Manual for high-traffic repos to opt in specific ready PRs, every-push for evolving PRs where you want auto-resolving threads.", "Use '@claude review once' for long-running PRs with frequent pushes or one-off second opinions, to avoid subscribing the PR to per-push review cost.", "Set a monthly spend cap for the Claude Code Review service at claude.ai/admin-settings/usage to bound cost.", "To enforce a merge gate on findings, parse the check run's machine-readable severity JSON (normal/nit/pre_existing) with gh api + jq in your own CI, since Code Review's check is always neutral.", "Run the local '/code-review' command (with --fix or --comment) before opening a PR to catch issues without spending on a managed review.", "Click 👍/👎 on findings — reaction counts are collected post-merge to tune the reviewer (but won't re-review).", "For team unattended automation that must run reliably, prefer Cloud routines over Desktop tasks since Desktop tasks silently skip when the machine sleeps or the app is closed.", "Run a new Desktop task once with 'Run now' immediately after creating it, approve each permission prompt with 'always allow', so future scheduled runs don't stall in Ask mode.", "Add timing guardrails inside the task prompt because a catch-up run may fire far from the intended time (e.g. 'Only review today's commits; if it's after 5pm, just post a summary of what was missed').", "Enable the worktree toggle for tasks that edit code so each run is isolated from your live uncommitted working-directory state.", "Enable 'Keep computer awake' (Settings → Desktop app → General) for machine-local scheduled tasks that must not be skipped by idle-sleep.", "Use Cloud routines (not Desktop) when a task must trigger on API calls or GitHub events or run while the computer is off.", "Manage tasks (create/edit/pause/list/reschedule) conversationally in any Desktop session rather than only through the UI form; use the Edit form or chat for schedule/folder/model/enabled since those aren't in SKILL.md.", "Create a `CLAUDE.md` at repo root to define code style, review criteria, and project rules; keep it concise and focused. Claude follows it when creating PRs and responding.", "Always store the API key as the GitHub secret `ANTHROPIC_API_KEY`; never hardcode keys in workflow files.", "Limit workflow `permissions` to only what's necessary; review Claude's suggestions before merging.", "Control cost: set `--max-turns` in `claude_args` to cap iterations, set workflow-level `timeout` to avoid runaway jobs, and use GitHub concurrency controls to limit parallel runs.", "Use specific `@claude` commands rather than vague ones to reduce unnecessary API calls and token usage.", "Use issue templates to give Claude better context.", "For Bedrock/Vertex (enterprise), prefer a custom GitHub App + OIDC/Workload Identity Federation over static credentials; create a dedicated, repository-scoped service account/role with minimum permissions.", "For per-workflow behavior tuning use the `prompt` input; for project-wide standards use CLAUDE.md.", "Gate the job with an `if:` condition checking `contains(github.event.comment.body, '@claude')` across issue_comment, pull_request_review_comment, and issues events to avoid running on every event.", "For a team on GHES, have a Claude org admin run the one-time guided setup at claude.ai/admin-settings/claude-code; start by installing the GitHub App on a subset of repos and add more later.", "On GHES, do not rely on the GitHub MCP server. Pre-authenticate gh per developer with 'gh auth login --hostname <ghes-host>' so Claude can drive gh commands in sessions.", "To distribute internal plugins/tooling org-wide on GHES, host a plugin marketplace on GHES and pre-register it via extraKnownMarketplaces in managed settings so developers get it without manual add.", "When locking down marketplace sources with strictKnownMarketplaces, use a single hostPattern entry for your GHES host instead of enumerating every repo.", "Allowlist Anthropic API IP addresses on the GHES firewall up front to avoid web-session/code-review clone timeouts.", "If the guided redirect flow is blocked by network policy, use 'Add manually' and create the GitHub App with the documented permissions/events, then enter all app credentials.", "Use the 'Manual setup (recommended for production)' path rather than quick setup for enterprise: configure provider OIDC/WIF and explicit GitLab API credentials.", "Prefer provider-specific OIDC/WIF (Bedrock IAM role, Vertex WIF) over long-lived static keys; never commit API keys or cloud credentials — always use masked (and protected) CI/CD variables.", "Restrict the cloud trust policy to your specific GitLab project and protected refs, and attach least-privilege permissions (Bedrock invoke APIs / Vertex roles) to a dedicated service account.", "Keep CLAUDE.md at the repo root focused and concise to define coding standards/review criteria and reduce token cost.", "Write specific, clear issue/MR descriptions and specific `@claude` commands to reduce back-and-forth iterations (turns) and token cost.", "Set `max_turns` and a job `timeout_minutes` to prevent runaway runs and bound cost; limit job concurrency to control parallel runs.", "Cache npm/package installs in runners to reduce runner compute minutes.", "Limit job permissions and network egress; review Claude-generated MRs like any other contributor.", "Use different prompts per job type (review, implement, refactor) via prompt/prompt_file.", "Pick regional provider endpoints to reduce latency and meet data-sovereignty requirements.", "For CI and scripts, always add `--bare` so runs don't pick up whatever local context (teammate hooks, project `.mcp.json`) happens to be configured — guarantees the same result on every machine.", "Pipe data into Claude (e.g. `git diff main | claude -p ...`) instead of granting Bash permission to read it — reduces the permission surface and keeps the run from prompting.", "Track per-invocation spend in scripts by reading `total_cost_usd` (and the per-model breakdown) from `--output-format json` output, rather than the usage dashboard.", "For locked-down CI, use `--permission-mode dontAsk` to deny anything not explicitly allowed, or scope `--allowedTools` tightly with prefix rules like `Bash(git diff *)` (mind the space before `*`).", "Parse JSON output with `jq` — `.result` for text, `.structured_output` for schema output, `.session_id` to capture and `--resume` a specific conversation.", "For very large inputs, write content to a file and reference the path in the prompt instead of piping (stdin is capped at 10MB).", "In stream-json mode, inspect `system/init` `plugin_errors` to fail CI when a required plugin did not load.", "Run `--continue`/`--resume` commands from the same project directory, since session lookup is scoped to that directory and its git worktrees.", "Make the routine prompt fully self-contained and explicit about the task and success criteria, since runs are autonomous with no human in the loop.", "Scope each routine tightly: select only the repos, environment access, and connectors it actually needs, because included connectors can be used (including writes) without per-run approval.", "Remove unneeded connectors from the routine (all connected connectors are added by default) to minimize the tool surface Claude can act on.", "Keep the claude/-prefixed branch restriction on by default; only enable 'Allow unrestricted branch pushes' for repos that genuinely require pushing to existing branches.", "Do NOT trust the green run status as success — it only means the session started/exited without infra error; open the run transcript to confirm the task actually completed (blocked network requests, missing connector tools, and task failures surface only in the transcript).", "Store the API token immediately on generation (shown once, unretrievable); keep it in your alerting tool's secret store and rotate via Regenerate/Revoke.", "For API triggers, pass run-specific context (alert body, failing log) in the 'text' field, but remember it arrives as literal unparsed text — do not rely on JSON structure.", "When a routine must reach internal/private services, pre-edit the environment's Network access to Custom and add those domains before running, rather than expecting the Trusted default to allow them.", "To make an MCP server available cloud-side, commit it in .mcp.json in the repo (or add it as an account connector) — local 'claude mcp add' servers will not be present.", "Use regex filters carefully: '.*hotfix.*' for substring-style matching, or prefer the 'contains' operator for literal substrings, since 'matches regex' anchors to the whole field.", "For sub-hourly or other unsupported cadences, accept the 1-hour minimum (more frequent crons are rejected) and design around it.", "Team/Enterprise admins control routine availability centrally via the admin-settings Routines toggle — treat it as the governance lever rather than per-user config.", "For team automation that must run unattended/reliably, use Routines (cloud), GitHub Actions schedule triggers, or Desktop scheduled tasks — NOT /loop, which only fires while a session is open and idle.", "Define a project-level `.claude/loop.md` to give the whole team a shared default maintenance prompt for bare `/loop` (e.g. keep a release branch green); it overrides per-user `~/.claude/loop.md`.", "Keep loop.md concise — under 25,000 bytes or it gets truncated.", "When exact fire timing matters, schedule at a minute other than :00 or :30 (e.g. `3 9 * * *`) so jitter doesn't shift it up to 30 min late (recurring) or 90s early (one-shot).", "Prefer self-paced `/loop <prompt>` (no interval) for polling PRs/builds so Claude waits longer when quiet and shorter when active, saving tokens; it may use the Monitor tool to stream output instead of re-polling.", "Use Routines/Desktop tasks instead of /loop when a recurring task must outlive the 7-day expiry; otherwise cancel and recreate before expiry.", "Disable scheduling fleet-wide or in CI/managed environments with `CLAUDE_CODE_DISABLE_CRON=1`.", "Re-run saved commands/skills on a schedule by passing them as the loop prompt, e.g. `/loop 20m /review-pr 1234`.", "Set Routing Mode to 'Code only' for teams using Slack exclusively for dev tasks; use 'Code + Chat' for a single @Claude entry point across writing/analysis/coding.", "Gate Claude Code usage by controlling which channels Claude is invited to and who can access those channels — this is the team's de facto access-control layer on top of workspace install.", "Write specific requests: include file names, function names, and error messages; state the repo if not obvious; and define what 'done' means (tests? docs? PR?).", "Use Slack threads when discussing a bug/feature so Claude gathers full conversation context before starting; reply in-thread rather than posting fresh channel messages.", "Include the repository name in the request (or use 'Change Repo') to avoid wrong-repo auto-selection when multiple repos could apply.", "Use Slack to kick off async tasks where context already lives in the discussion and teammates need visibility; use the web directly for file uploads, real-time interaction, and longer/complex work.", "Each repo a user wants Claude to touch must be individually connected/authenticated at claude.ai/code beforehand — provision repo connections per user during onboarding.", "Disable a tool ecosystem-wide for the team by adding its exact name to the permissions `deny` array; this is the canonical kill switch referenced by CLI flags, subagent frontmatter, skills, and hooks.", "Restrict subagent blast radius by narrowing its `tools` frontmatter (leave Bash off the list) or using deny rules, rather than relying on prompts; remember disallowedTools wins when both are set.", "Use a single Edit(path) allow rule instead of separate Read+Edit rules since Edit grants matching read access.", "For deterministic env across Bash commands (which don't persist exports), set CLAUDE_ENV_FILE to a shell script or use a SessionStart hook; activate virtualenv/conda before launching Claude Code.", "Pre-approve trusted fetch domains with WebFetch(domain:example.com) allow rules to avoid first-touch prompts; use explicit WebFetch(domain:...) deny/ask to block or gate even preapproved doc domains.", "For OS-level file-access enforcement across all processes (not just recognized Bash commands), enable the sandbox — Read/Edit deny rules do not cover indirect file access by scripts.", "When Glob must respect .gitignore for the team, set CLAUDE_CODE_GLOB_NO_IGNORE=false; by default Glob surfaces gitignored files while Grep does not.", "For long-running processes (dev servers, watch builds) use Bash run_in_background:true and manage them with /tasks rather than blocking the session.", "Cap subagent cost/runaway by setting maxTurns in the subagent definition.", "On enterprise/Bedrock/Vertex/Foundry, account for unavailable tools (Monitor, PushNotification, RemoteTrigger, server-side WebSearch on Bedrock) when designing team workflows.", "For very large command outputs, rely on the file-spillover behavior (raise BASH_MAX_OUTPUT_LENGTH up to 150,000 chars) and have Claude search the saved file rather than dumping everything into context.", "Prefer the Task* tools (TaskCreate/Get/List/Update) over TodoWrite, which is disabled by default as of v2.1.142."], "gotchas": ["Always-on Chrome (enabled by default) silently increases context usage because browser tools are always loaded.", "Claude operates with your live browser login state, so it can act on any authenticated site you're signed into — a meaningful security/blast-radius concern, especially for shared or sensitive accounts.", "Not supported on WSL, Brave, or Arc — a common surprise for teams on those setups.", "Not available via Bedrock/Vertex/Foundry; third-party-provider-only users must have a separate claude.ai account.", "A blocking JavaScript modal dialog silently freezes browser automation until a human dismisses it.", "The extension service worker going idle during long sessions silently drops the connection.", "Site permissions live only in the Chrome extension, not in Claude Code settings.json — they are NOT managed by Claude Code's normal permission/managed-policy system.", "`claude --help` does NOT list every flag — absence from --help does not mean a flag is unavailable.", "--allowedTools only auto-approves; it does NOT restrict which tools are available. To limit the available set use --tools; the two are easy to confuse.", "--disallowedTools behavior depends on syntax: a bare name removes the tool from context entirely, while a scoped rule like Bash(rm *) leaves the tool available and only denies matching calls.", "--tools does NOT affect MCP tools; to deny MCP you must use --disallowedTools \"mcp__*\" or pass --strict-mcp-config without --mcp-config so no MCP servers load.", "--add-dir grants file read/edit access but does NOT discover most .claude/ configuration from those directories; persist dirs via permissions.additionalDirectories.", "Many flags are print-mode (-p) only: --max-turns, --max-budget-usd, --json-schema, --no-session-persistence, --init, --maintenance — they have no effect in interactive mode.", "--safe-mode still applies managed settings policy (policy hooks, status line, file-suggestion commands), so it does NOT fully disable everything; it differs from --bare in keeping auth/model/tools/permissions normal.", "--exclude-dynamic-system-prompt-sections is ignored when --system-prompt or --system-prompt-file is set (only applies with the default system prompt).", "Replacing the system prompt with --system-prompt/--system-prompt-file drops ALL default tool guidance and safety instructions — you become responsible for them.", "--enable-auto-mode was removed in v2.1.111; use --permission-mode auto instead.", "--settings overrides only the keys you set for the session; omitted keys keep their file-based values (it is not a full replacement of settings.json).", "Resuming by session ID searches only the current project directory and its git worktrees, whereas the picker/name search also includes sessions that added the dir via /add-dir — so an ID may not resolve from a different directory.", "Several CLI commands/flags are version-gated (e.g. claude mcp login/logout require v2.1.186+, --safe-mode v2.1.169+, --advisor v2.1.98+).", "Code Review is unavailable for orgs with Zero Data Retention enabled, and limited to Team/Enterprise plans.", "The 'Claude Code Review' check always completes neutral — it will NEVER block a merge via branch protection; you must build your own gating to enforce findings.", "REVIEW.md is pasted verbatim: @import syntax is NOT expanded and referenced files are NOT pulled in — inline all rules directly.", "GitHub's 'Re-run' button does NOT retrigger Code Review; failed/timed-out reviews do not auto-retry — re-trigger with '@claude review once' or a new push.", "Replying to an inline finding comment does nothing; to act on a finding you must fix code and push (or '@claude review once'). 👍/👎 don't trigger re-review either.", "'@claude review' silently subscribes the PR to per-push reviews, accruing cost on every subsequent push — use '@claude review once' if you don't want that.", "Manual trigger commands fail if posted as an inline diff comment, not at the start of the comment, or by someone without owner/member/collaborator access.", "Code Review usage is billed separately via usage credits and does NOT count against included plan usage; it bills to Anthropic even when other features use Bedrock/Vertex.", "If issues show in the check run but no inline comments appear (e.g. you pushed while a review ran), findings may only be in the check run Details table, Files-changed annotations, or an 'Additional findings' section of the review body.", "The /code-review command was renamed from /simplify at v2.1.147; from v2.1.154 /simplify is cleanup-only and no longer hunts bugs — scripts relying on /simplify for bug-finding must switch to '/code-review --fix'.", "Desktop scheduled tasks silently skip when the computer sleeps through the scheduled time — closing the laptop lid sleeps it even with the app open.", "Default behavior runs against uncommitted changes in the working directory; without the worktree toggle a scheduled run can act on dirty state.", "A task scheduled for 9am can run at an unexpected time (e.g. 11pm) via the catch-up mechanism after the machine wakes; the deterministic startup delay also offsets every run by a few minutes.", "Only ONE catch-up run fires for the most recently missed time within 7 days — older missed runs are silently discarded (a daily task missing six days runs once).", "A task in Ask mode that hits an un-permissioned tool stalls indefinitely until you manually approve in the sidebar session.", "Editing SKILL.md only changes the prompt/name/description; schedule, folder, model, and enabled state must be changed via the Edit form or by asking Claude.", "v1.0 has breaking changes from @beta: you must change `@beta`→`@v1`, delete `mode:`, rename `direct_prompt`→`prompt`, and move `max_turns`/`model`/`custom_instructions`/`allowed_tools` into `claude_args`. Old workflows break otherwise.", "Trigger must be exactly `@claude` (or your configured `trigger_phrase`) — `/claude` does NOT work.", "The `/install-github-app` quickstart only works for direct Claude API users; Bedrock and Vertex require full manual OIDC setup.", "CI may not run on Claude's commits unless you use the GitHub App (or a custom app) rather than the default Actions user — commits by the Actions user don't trigger downstream workflows.", "`id-token: write` permission is required for OIDC auth (Bedrock/Vertex); omitting it breaks cloud-provider authentication.", "Bedrock model IDs require a region prefix (e.g. `us.anthropic.claude-sonnet-4-6`), unlike direct API model IDs.", "You must run `actions/checkout` before the action step for repo-local skills in `.claude/skills/` to be available.", "`anthropic_api_key` is required only for direct Claude API; for Bedrock/Vertex you supply `github_token` and cloud credentials instead.", "GitHub MCP server silently does NOT work against GHES — must fall back to the gh CLI.", "'/install-github-app' is github.com-only and will not configure GHES; GitHub Actions on GHES requires manual workflow setup (no auto-install).", "Plugin marketplace 'owner/repo' shorthand ALWAYS resolves to github.com — using it for a GHES repo will fetch the wrong (or no) marketplace; full git URL is mandatory.", "If '/plugin marketplace add' fails with a policy error on a GHES URL, the org's strictKnownMarketplaces is blocking it — admin must add a hostPattern entry.", "Web-session clone failures usually mean either admin setup is incomplete, the GitHub App is not installed on that repo, or the registered hostname does not match the git remote hostname.", "Reviews/sessions timing out typically indicate the GHES instance is unreachable from Anthropic infrastructure (firewall not allowlisting Anthropic IPs).", "GHES sessions run on Anthropic infrastructure (cloud), not locally — the repo is cloned remotely and changes pushed back to a branch.", "The mention trigger must be `@claude`; `/claude` will not work.", "Claude does not auto-respond unless a pipeline trigger is wired up (manual run, merge_request_event rule, or a notes-webhook listener calling the trigger API) — there is no built-in comment listener; you must build/provide one.", "Mention-driven (@claude) flow depends on an external event listener/webhook that you supply; the doc's `/bin/gitlab-mcp-server` and AI_FLOW_* assume that scaffolding exists.", "If the job can't comment or open MRs: CI_JOB_TOKEN may lack permissions (use a PAT with `api` scope) and/or `mcp__gitlab` is missing from --allowedTools.", "Troubleshooting note says ensure CI/CD variables are 'present and unmasked' to be available — masked variables are still usable; this phrasing is a doc inconsistency, but verify the variable is actually exposed to the job's rules/refs (protected variables only run on protected refs).", "ANTHROPIC_API_KEY is ignored on Bedrock/Vertex paths; auth errors there stem from OIDC/WIF/role-impersonation/region/model-availability, not the API key.", "Two billing dimensions stack: GitLab Runner compute minutes AND Anthropic/Bedrock/Vertex token costs — both scale with codebase size and task complexity.", "`--permission-mode acceptEdits` in the examples auto-accepts edits; MR review/branch protection is the only human gate, so approval rules must be enforced.", "Without `--bare`, `claude -p` silently inherits local context — a teammate's hook in `~/.claude` or an MCP server in `.mcp.json` will run, making results non-reproducible across machines.", "`Bash(git diff*)` without a space before `*` also matches `git diff-index`; omit the space and your allow rule is broader than intended.", "Piped stdin over 10MB (since v2.1.128) aborts with a non-zero exit — not silently truncated.", "Background Bash tasks are killed ~5s after the final result; long-running watch/dev processes won't survive a `-p` run. Background subagents instead block the run up to a 10-minute cap (v2.1.182+).", "In bare mode, OAuth/keychain are skipped — auth must come from `ANTHROPIC_API_KEY` or an `apiKeyHelper` in `--settings`, or the call fails to authenticate.", "Interactive built-in commands like `/login` do not work in `-p` mode; only user-invoked skills/custom commands and `/config key=value` work.", "`acceptEdits` auto-approves file writes and basic fs commands (mkdir/touch/mv/cp) but NOT arbitrary shell or network — those still abort without an explicit allow rule.", "Routines are per-individual-account and NOT shared with teammates, despite Team/Enterprise plan gating — there is no team-shared routine.", "All routine actions appear as YOU (your GitHub user on commits/PRs, your linked accounts on connector actions) — no service-identity separation.", "No permission prompts during runs: any included connector tool, including destructive writes, can be invoked automatically.", "Green status in the run list does NOT mean the prompt's task succeeded — only that the session exited without an infra error.", "Locally-added MCP servers ('claude mcp add') do NOT appear as routine connectors because they live on your machine, not your claude.ai account.", "/web-setup grants clone access but does NOT install the Claude GitHub App or enable webhook delivery — GitHub triggers silently won't fire without the app.", "The /fire 'text' payload is never parsed: sending JSON delivers it to the routine as a literal string.", "'matches regex' tests the entire field value (anchored), so a bare 'hotfix' matches only an exact 'hotfix' field — easy to mis-author.", "Setting ANTHROPIC_API_KEY/ANTHROPIC_AUTH_TOKEN/apiKeyHelper or telemetry-disabling env vars (DISABLE_TELEMETRY, DO_NOT_TRACK, CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC, DISABLE_GROWTHBOOK) makes /schedule disappear as 'Unknown command'.", "GitHub webhook events exceeding per-routine/per-account hourly caps are silently dropped until the window resets.", "Each GitHub event spawns a fresh session (no reuse), so rapid PR updates can fan out into many independent sessions and consume usage.", "Scheduled runs can start a few minutes after the wall-clock time due to a per-routine stagger offset.", "One-off scheduled runs auto-disable after firing and must be re-edited with a new time to run again.", "Starting a fresh conversation silently clears ALL session-scoped scheduled tasks; only --resume/--continue restores unexpired ones.", "Background Bash and Monitor tasks are never restored on resume even when other tasks are.", "No catch-up: if scheduled time passes while Claude is busy, the task fires only once when idle, not once per missed interval — and never fires if the terminal/session is closed.", "Recurring tasks die after 7 days (fire one last time then self-delete) — easy to forget a 'permanent' loop actually has a hard expiry.", "Jitter means a job at `:00` can fire anywhere up to `:30`; cron times are local timezone not UTC, which can surprise distributed teams.", "`Esc` only stops a waiting /loop; tasks created by asking Claude directly survive Esc and must be deleted explicitly via CronDelete/natural language.", "Bedrock/Vertex/Foundry behave differently: no-interval prompts force a fixed 10-min schedule, loop.md is ignored, and bare /loop just prints usage.", "Extended cron syntax (L, W, ?, MON/JAN name aliases) is unsupported — only the basic 5-field forms work.", "vixie-cron OR semantics: when both day-of-month and day-of-week are set, the task fires if either matches, not only when both do.", "Cloud routines run with no permission prompts and a fresh clone — they have no access to local working-tree files.", "Claude follows directions from OTHER messages in the gathered Slack context (thread/channel), so a malicious or careless message in-context can steer Claude — only use it in trusted conversations (prompt-injection surface).", "No DM support — Claude Code in Slack only works in channels.", "Repo access is strictly per-user (personally connected repos only); a teammate's connected repo is not usable by others, which can confuse shared-channel workflows.", "Sessions consume the invoking individual's plan rate limits, not a team pool — heavy Slack usage can exhaust a single user's limits.", "Only one PR per session — multi-PR work requires multiple sessions.", "GitHub-only; repos on other hosts are unsupported.", "On Enterprise/Team plans, Slack-initiated sessions are automatically org-visible — not private to the user.", "Users lacking Claude Code on the web access silently get only chat responses instead of coding sessions, which can look like the integration 'not working'.", "Read/Edit deny rules apply only to recognized Bash file commands (cat/head/tail/sed/grep) — a Python or Node script that opens files bypasses them; only the sandbox enforces at OS level.", "The read-before-edit command set and the deny-rule command set differ: egrep/fgrep satisfy read-before-edit but are NOT checked against Read deny rules.", "Bash exports/env vars do NOT persist between commands; only aliases/functions sourced at session start carry. Easy to assume an export sticks.", "Glob does not respect .gitignore by default (opposite of Grep), so it can surface gitignored/secret files unless CLAUDE_CODE_GLOB_NO_IGNORE=false.", "Grep uses ripgrep regex, not POSIX grep — metacharacters like {} need escaping (interface\\{\\}).", "WebFetch is lossy: a negative answer may only mean the extraction prompt didn't ask; re-fetch with a sharper prompt or use curl for raw content.", "WebFetch cross-host redirects are not followed automatically — a second WebFetch call with the redirect URL is required.", "WebFetch sandbox access is separate from permission rules: an allowed WebFetch domain still needs an explicit sandbox network rule for sandboxed processes.", "Before v2.1.186, background subagents silently auto-denied prompting tool calls and continued without the tool — work could fail quietly on older versions.", "cd outside the project/additional dirs silently resets cwd to the project directory (with a 'Shell cwd was reset' note); subagents never inherit cwd changes at all.", "PowerShell process-scope -ExecutionPolicy Bypass does not override Group Policy MachinePolicy/UserPolicy, and PowerShell profiles are not loaded in preview; Windows sandboxing unsupported.", "Glob caps at 100 files (sorted by mtime) and Read line/token limits mean large reads silently return PARTIAL views — narrow patterns / use offset+limit.", "Monitor silently unavailable when DISABLE_TELEMETRY or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set, or on Bedrock/Vertex/Foundry.", "WebSearch allowed_domains and blocked_domains cannot be combined in a single call."], "claims": ["Chrome integration is enabled per-session with the `claude --chrome` flag, or with `/chrome` inside a running session.", "`/chrome` checks connection status, manages permissions, reconnects the extension, and selects which connected browser to use; if multiple browsers are connected it prompts to pick one.", "To avoid passing `--chrome` each session, run `/chrome` and select 'Enabled by default'.", "Enabling Chrome by default increases context usage because browser tools are always loaded; disable it and use `--chrome` only when needed if context consumption rises.", "Requires Claude in Chrome extension v1.0.36+, Claude Code v2.0.73+, and a direct Anthropic plan (Pro, Max, Team, or Enterprise).", "Chrome integration is NOT available through third-party providers (Amazon Bedrock, Google Cloud Vertex AI, Microsoft Foundry); a separate claude.ai account is required if you access Claude only via those.", "Currently works only with Google Chrome and Microsoft Edge; NOT supported on Brave, Arc, other Chromium browsers, or WSL.", "Claude shares the browser's existing login state, so it can access any site you are already signed into (Gmail, Google Docs, Notion, internal apps) without API connectors.", "On login pages or CAPTCHAs Claude pauses and asks the user to handle it manually.", "Site-level permissions are inherited from the Chrome extension and managed in the Chrome extension settings, controlling which sites Claude can browse, click, and type on.", "Browser tools are exposed as an MCP server named `claude-in-chrome`; run `/mcp` and select it to see the full browser tool list.", "First-time enablement installs a native messaging host config file (`com.anthropic.claude_code_browser_extension.json`) read by Chrome at startup; restart Chrome if the extension is not detected on first attempt.", "JavaScript dialogs (alert/confirm/prompt) block browser events and prevent Claude from receiving commands until dismissed manually.", "The Chrome extension service worker can go idle during long/inactive sessions, breaking the connection; recover with `/chrome` -> 'Reconnect extension'.", "On Windows, named-pipe conflicts (EADDRINUSE) occur when another process uses the same pipe; close other Claude Code sessions using Chrome and restart.", "Browser actions run in a visible Chrome window in real time, and Claude opens new tabs for browser tasks.", "`claude -p \"query\"` (--print) runs a query via SDK then exits (headless/non-interactive mode); many flags are print-mode-only.", "`claude -c` / `--continue` loads the most recent conversation in the current directory; includes sessions that added the dir via /add-dir.", "`claude -r \"<session>\"` / `--resume` resumes a session by ID or name, or shows an interactive picker. Passing a session ID searches only the current project dir and its git worktrees; the picker/name search includes /add-dir sessions.", "`--fork-session` (with --resume/--continue) creates a new session ID instead of reusing the original.", "`--model` sets session model via alias (sonnet, opus, haiku, fable) or full name; overrides the `model` setting and ANTHROPIC_MODEL env var.", "`--fallback-model` accepts a comma-separated chain tried in order when primary is overloaded/unavailable; overrides the `fallbackModel` setting.", "`--effort` sets effort level (low, medium, high, xhigh, max; availability depends on model); overrides `effortLevel` setting and does not persist.", "`--output-format` for print mode accepts text, json, stream-json. `--input-format` accepts text, stream-json.", "`--max-turns N` limits agentic turns (print mode only); exits with error when limit reached; no limit by default.", "`--max-budget-usd N` caps dollar spend on API calls before stopping (print mode only).", "`--json-schema '<schema>'` returns validated JSON output matching a JSON Schema after the agent completes (print mode only).", "`--allowedTools`/`--allowed-tools` lists tools that execute without prompting; uses permission rule pattern syntax e.g. \"Bash(git log *)\". To restrict which tools are AVAILABLE use `--tools` instead.", "`--disallowedTools`/`--disallowed-tools`: a bare tool name removes the tool from the model's context (\"Edit\" removes Edit, \"*\" removes all, \"mcp__*\" removes all MCP tools); a scoped rule like Bash(rm *) leaves the tool available but denies matching calls.", "`--tools` restricts available built-in tools: \"\" disables all, \"default\" enables all, or names like \"Bash,Edit,Read\". MCP tools are not affected by --tools.", "`--permission-mode` accepts default, acceptEdits, plan, auto, dontAsk, bypassPermissions; overrides `defaultMode` from settings files.", "`--dangerously-skip-permissions` equals `--permission-mode bypassPermissions` (skips permission prompts).", "`--allow-dangerously-skip-permissions` adds bypassPermissions to the Shift+Tab mode cycle without starting in it (lets you start in plan and switch later).", "`--permission-prompt-tool` specifies an MCP tool to handle permission prompts in non-interactive mode.", "`--mcp-config` loads MCP servers from JSON files or strings (space-separated). `--strict-mcp-config` uses ONLY servers from --mcp-config, ignoring all other MCP configs.", "`claude mcp login <name>` / `logout <name>` run/clear a configured MCP server's OAuth flow from the CLI (HTTP/SSE/connector servers); `--no-browser` prints the auth URL for SSH. Requires v2.1.186+.", "`--settings` takes a settings JSON file path or inline JSON string; values override the same keys in settings.json files for the session; omitted keys keep file values.", "`--setting-sources` is a comma-separated list of setting sources to load: user, project, local.", "`--add-dir` adds working directories for read/edit, but most .claude/ configuration is NOT discovered from these dirs. Persist via permissions.additionalDirectories in settings.", "Four system-prompt flags: `--system-prompt` (replace), `--system-prompt-file` (replace from file), `--append-system-prompt` (append), `--append-system-prompt-file` (append from file). --system-prompt and --system-prompt-file are mutually exclusive; append flags combine with either.", "`--exclude-dynamic-system-prompt-sections` moves per-machine sections (cwd, env info, memory paths, git-repo flag) into the first user message to improve prompt-cache reuse across users/machines; only applies with default system prompt; ignored when --system-prompt/--system-prompt-file set. Use with -p for multi-user workloads.", "`--bare` skips auto-discovery of hooks, skills, plugins, MCP servers, auto memory, and CLAUDE.md for faster scripted starts; Claude retains Bash, file read, file edit. Sets CLAUDE_CODE_SIMPLE.", "`--safe-mode` (v2.1.169+) disables all customizations (CLAUDE.md, skills, plugins, hooks, MCP, custom commands/agents, etc.) for troubleshooting, but auth/model/built-in tools/permissions work normally. Managed settings policy STILL applies (policy hooks, status line, file-suggestion); managed plugins/skills/CLAUDE.md and policy MCP servers do NOT load. Sets CLAUDE_CODE_SAFE_MODE.", "`claude setup-token` generates a long-lived OAuth token for CI/scripts, printed to terminal without saving; requires a Claude subscription.", "`claude auth login` supports --email (pre-fill), --sso (force SSO), --console (Console API billing instead of subscription). `claude auth status` outputs JSON (--text for human-readable); exits 0 if logged in, 1 if not.", "`--no-session-persistence` (print mode only) prevents sessions being saved/resumed; CLAUDE_CODE_SKIP_PROMPT_HISTORY env var does the same in any mode.", "`--session-id` requires a valid UUID; `--name`/`-n` sets a resumable display name.", "`--plugin-dir <path>` loads a plugin from a dir or .zip for the session only (repeat per plugin); `--plugin-url` fetches a plugin .zip from a URL for the session only.", "`--worktree`/`-w` starts in an isolated git worktree at <repo>/.claude/worktrees/<name>; can pass #<number> or a GitHub PR URL to branch from a PR.", "`claude project purge [path]` deletes all local Claude Code state for a project (transcripts, task lists, debug logs, file-edit history, prompt history, ~/.claude.json entry); flags --dry-run, -y/--yes, -i/--interactive, --all.", "`--bg` starts a session as a background agent and returns immediately; combine with --exec to run a shell command as a background job, or --agent for a specific subagent. Manage via claude attach/logs/respawn/rm/stop/stop kill, claude agents (--json, --cwd, --all), claude daemon status/stop.", "`--agents '<json>'` defines custom subagents dynamically via JSON (same field names as subagent frontmatter plus a `prompt` field).", "`--debug` enables debug mode with category filtering (e.g. \"api,hooks\" or \"!statsig,!file\"); `--debug-file <path>` writes logs to a file and takes precedence over CLAUDE_CODE_DEBUG_LOGS_DIR.", "`claude auth login --console` signs in with Anthropic Console for API usage billing instead of a Claude subscription; `claude setup-token` requires a Claude subscription.", "Code Review is a research-preview feature available only to Team and Enterprise subscriptions.", "Code Review is NOT available for organizations with Zero Data Retention (ZDR) enabled.", "An admin enables Code Review once for the org at claude.ai/admin-settings/claude-code; requires admin access to the Claude org and permission to install GitHub Apps in the GitHub org.", "Setup installs the Claude GitHub App, which requests repo permissions: Contents read+write, Issues read+write, Pull requests read+write. Code Review itself uses Contents read and Pull requests write; broader perms also support GitHub Actions.", "Per-repo Review Behavior dropdown has three modes: 'Once after PR creation', 'After every push', and 'Manual'.", "'After every push' auto-resolves threads when flagged issues are fixed, runs the most reviews, and costs the most.", "Manual mode runs reviews only when someone comments '@claude review' or '@claude review once' on a PR.", "'@claude review' starts a review AND subscribes the PR to push-triggered reviews going forward; '@claude review once' starts a single review without subscribing.", "Manual trigger commands must be a top-level PR comment (not inline on a diff line), with the command at the start of the comment and 'once' on the same line for one-shot form.", "To trigger a manual review you must have owner, member, or collaborator access to the repo, and the PR must be open.", "Manual triggers run on draft PRs; automatic triggers do not run on drafts.", "Findings have three severity markers: 🔴 Important (bug to fix before merge), 🟡 Nit (minor, non-blocking), 🟣 Pre-existing (bug already in codebase, not introduced by PR).", "Code Review posts inline comments and never approves or blocks a PR; the 'Claude Code Review' check run always completes with a neutral conclusion so it never blocks merge via branch protection.", "To gate merges on findings, parse the machine-readable last line of the check run Details: gh api repos/OWNER/REPO/check-runs/CHECK_RUN_ID --jq '.output.text | split(\"bughunter-severity: \")[1] | split(\" -->\")[0] | fromjson' returns e.g. {\"normal\":2,\"nit\":1,\"pre_existing\":0}; 'normal' = count of Important findings.", "REVIEW.md is a repo-root file injected verbatim into the system prompt of every review-pipeline agent as highest-priority instructions, overriding default review guidance; @ import syntax is NOT expanded and referenced files are NOT read in.", "CLAUDE.md is read by Code Review as project context; newly introduced violations are flagged as nit-level findings (bidirectional: PRs that make a CLAUDE.md statement outdated get flagged to update docs).", "CLAUDE.md files are read at every directory level; subdirectory rules apply only to files under that path.", "By default Code Review focuses on correctness (production-breaking bugs), not formatting or missing test coverage.", "Each review averages $15-25, scaling with PR size/complexity/issues-requiring-verification; completes in ~20 minutes on average.", "Code Review is billed via usage credits separately and does NOT count against the plan's included usage; costs appear on the Anthropic bill even if the org uses Bedrock or Vertex AI for other features.", "Set a monthly spend cap at claude.ai/admin-settings/usage for the 'Claude Code Review' service; when the cap is reached, reviews are skipped with a PR comment and resume next billing period or when an admin raises the cap.", "Usage dashboard at claude.ai/analytics/code-review shows PRs reviewed, weekly cost, auto-resolved feedback count, and per-repo breakdown; dashboard cost figures are estimates, not invoice-accurate.", "The '/code-review' local command reviews a diff in any Claude Code session without the GitHub App; default scope is branch commits ahead of upstream plus uncommitted working-tree changes.", "/code-review flags: --comment posts findings as inline PR comments; --fix applies findings to the working tree after review.", "/code-review accepts a target: a file path, PR number, branch name, or ref range (e.g. main...my-feature); the ref-range form reviews the committed diff a PR from my-feature into main would contain, regardless of upstream config.", "/code-review effort levels: lower effort returns fewer high-confidence findings; high through max give broader coverage and may include uncertain findings; no effort arg uses the session's current effort.", "'/code-review ultra --fix' runs the deeper cloud ultrareview (scope: current branch vs repo default branch, plus uncommitted and staged changes) then applies findings to the working tree.", "The /code-review command was named /simplify before v2.1.147 (which applied fixes by default). From v2.1.154, /simplify is a separate cleanup-only review that applies fixes without bug-hunting. Scripts using /simplify for bug-finding should switch to '/code-review --fix'.", "Reuse/simplification/efficiency cleanups in local /code-review require min-version 2.1.151.", "👍/👎 reactions on findings are collected after PR merge to tune the reviewer; they do NOT trigger re-review. Replying to an inline comment does NOT prompt Claude to respond or update the PR.", "If a review is already running on a PR, a new request is queued until the in-progress review completes.", "GitHub's 'Re-run' button in the Checks tab does NOT retrigger Code Review; use '@claude review once' or a new push instead.", "For self-hosted CI instead of the managed service, use GitHub Actions, GitLab CI/CD, or GitHub Enterprise Server integrations.", "Three scheduling mechanisms exist: Cloud routines (Anthropic infra, machine-off OK, min interval 1 hour), Desktop scheduled tasks (your machine, min interval 1 minute), and /loop (session-scoped, your machine, min interval 1 minute).", "Desktop scheduled tasks only run while the Desktop app is open AND the computer is awake; if the computer sleeps through a scheduled time the run is skipped (closing the laptop lid still sleeps it).", "Cloud routines run autonomously with no permission prompts and use a fresh clone (no local file access); Desktop tasks have configurable-per-task permissions and local file access.", "Allow rules from ~/.claude/settings.json also apply to scheduled task sessions (in addition to the per-task permission mode).", "If a task runs in Ask mode and lacks permission for a tool, the run stalls until you approve it; the session stays open in the sidebar to answer later.", "Selecting 'always allow' on a tool during a Run now makes future runs of that task auto-approve the same tools; approvals are reviewable/revocable from the task detail page 'Always allowed' panel.", "Desktop checks the schedule every minute while the app is open; each task gets a small deterministic delay of a few minutes after the scheduled time to stagger API traffic (same task always starts at same offset).", "Missed-run catch-up: on app start or wake, Desktop checks for missed runs in the last 7 days and starts exactly ONE catch-up run for the most recently missed time, discarding older ones.", "Each Desktop task's prompt lives on disk at ~/.claude/scheduled-tasks/<task-name>/SKILL.md (or under CLAUDE_CONFIG_DIR if set), with YAML frontmatter for name and description and the prompt as the body; changes take effect next run.", "Schedule, folder, model, and enabled state are NOT stored in SKILL.md — change them via the Edit form or by asking Claude.", "Task Name is converted to lowercase kebab-case and used as the on-disk folder name; must be unique across tasks.", "Desktop tasks use MCP via config files (/en/mcp) and connectors; Cloud routines configure connectors per task; /loop inherits MCP from the session.", "A worktree toggle gives each task run its own isolated Git worktree; by default tasks run against the working directory's current state INCLUDING uncommitted changes.", "A running task can modify its own schedule or prompt via the update_scheduled_task MCP tool (e.g. reschedule based on findings).", "Schedule presets: Manual (Run now only), Hourly, Daily (default 9:00 AM local), Weekdays (Daily minus weekends), Weekly. Other intervals (every 15 min, monthly, one-time future) are set by asking Claude in plain language.", "A folder must be set/trusted before a task can be saved; Desktop prompts to trust an untrusted folder.", "Deleting a task archives its sessions; an 'Also delete files on disk' checkbox additionally removes the SKILL.md and data from ~/.claude/scheduled-tasks/.", "Cloud-routine minimum interval is 1 hour; Desktop and /loop minimum interval is 1 minute (as documented 2026).", "The action is `anthropics/claude-code-action@v1`; v1.0 is GA and introduces breaking changes from the `@beta` version.", "Quick setup: run `/install-github-app` in the Claude Code terminal; requires repository admin rights. This quickstart is only available for direct Claude API users (not Bedrock/Vertex).", "The Claude GitHub app (https://github.com/apps/claude) requires repository permissions: Contents Read & Write, Issues Read & Write, Pull requests Read & Write.", "API key is stored as a GitHub repository secret named `ANTHROPIC_API_KEY`, referenced as `anthropic_api_key: ${{ secrets.ANTHROPIC_API_KEY }}`.", "Workflow file goes in `.github/workflows/`; example template at examples/claude.yml in anthropics/claude-code-action.", "Default trigger phrase is `@claude` (must be `@claude`, not `/claude`); override with the `trigger_phrase` input.", "v1 auto-detects interactive mode (responds to @claude mentions) vs automation mode (runs immediately with a prompt) based on configuration; the beta `mode:` input is removed.", "v1 action inputs: `prompt` (optional; plain text or a skill name), `claude_args` (CLI passthrough), `plugin_marketplaces` (newline-separated Git URLs), `plugins` (newline-separated plugin names), `anthropic_api_key` (required for direct API), `github_token`, `trigger_phrase`, `use_bedrock`, `use_vertex`.", "Beta→v1 input migration: `direct_prompt`→`prompt`; `custom_instructions`→`claude_args: --append-system-prompt`; `max_turns`→`claude_args: --max-turns`; `model`→`claude_args: --model`; `allowed_tools`→`claude_args: --allowedTools`; `disallowed_tools`→`claude_args: --disallowedTools`; `claude_env`→`settings` JSON format; `override_prompt`→`prompt` with GitHub variables.", "`claude_args` accepts any Claude Code CLI args: `--max-turns` (default 10), `--model` (e.g. claude-sonnet-4-6), `--mcp-config /path/to/config.json`, `--allowedTools` (comma-separated; `--allowed-tools` alias also works), `--disallowedTools`, `--append-system-prompt`, `--debug`.", "Skills: for a repo skill in `.claude/skills/`, run `actions/checkout` before the action step and pass `/skill-name` as prompt. For a plugin skill, install via `plugin_marketplaces` + `plugins` inputs and pass namespaced `/plugin-name:skill-name`.", "Example plugin install: `plugin_marketplaces: \"https://github.com/anthropics/claude-code.git\"` with `plugins: \"code-review@claude-code-plugins\"`, then prompt `/code-review:code-review ...`.", "Required workflow `permissions` for PR-creating workflows: contents: write, pull-requests: write, issues: write, and id-token: write (the last required for OIDC with Bedrock/Vertex).", "Bedrock/Vertex use OIDC (no static keys): Bedrock OIDC provider URL `https://token.actions.githubusercontent.com`, audience `sts.amazonaws.com`; secret `AWS_ROLE_TO_ASSUME`; input `use_bedrock: \"true\"`. Bedrock model IDs include a region prefix e.g. `us.anthropic.claude-sonnet-4-6`.", "Vertex AI uses Workload Identity Federation; secrets `GCP_WORKLOAD_IDENTITY_PROVIDER` and `GCP_SERVICE_ACCOUNT` (service account needs only `Vertex AI User` role); input `use_vertex: \"true\"`; env `ANTHROPIC_VERTEX_PROJECT_ID`, `CLOUD_ML_REGION`, `VERTEX_REGION_CLAUDE_4_5_SONNET`.", "Custom GitHub App auth uses `actions/create-github-app-token@v2` with secrets `APP_ID` and `APP_PRIVATE_KEY` (.pem contents); pass `github_token: ${{ steps.app-token.outputs.token }}` to the action.", "Claude Code Action is built on the Claude Agent SDK; code runs on GitHub-hosted runners (GitHub's infrastructure).", "GitHub Actions costs consume GitHub Actions minutes; API costs consume Claude API tokens scaling with prompt/response length, task complexity, and codebase size.", "GitHub Enterprise Server (GHES) support is available only on Team and Enterprise plans.", "An admin connects the GHES instance to Claude Code once; after that developers use GHES repositories with no per-repository or developer-side configuration.", "GHES features supported: Claude Code on the web, Code Review, Claude Security (Enterprise public beta), Teleport sessions, Plugin marketplaces, Contribution metrics, and GitHub Actions (manual workflow setup).", "The GitHub MCP server does NOT work with GHES instances; workaround is the gh CLI authenticated with 'gh auth login --hostname github.example.com', then Claude uses gh commands.", "/install-github-app is github.com only; for GHES use the admin setup flow on claude.ai and adapt the claude-code-action example workflow (examples/claude.yml) manually for GitHub Actions.", "Admin setup lives at claude.ai/admin-settings/claude-code; requires admin access to the Claude org plus permission to create GitHub Apps on the GHES instance.", "Guided setup generates a GitHub App manifest and redirects to GHES to create the app in one click; an 'Add manually' alternative exists if the redirect is blocked.", "Manual setup requires entering: hostname, OAuth client ID and secret, GitHub App ID, client ID, client secret, webhook secret, and private key.", "Self-signed/private CA: paste the CA certificate into the optional field during guided setup when entering the GHES hostname (e.g. github.example.com).", "GitHub App permissions configured by the manifest: Contents (read/write), Pull requests (read/write), Issues (read/write), Checks (read/write), Actions (read), Repository hooks (read/write), Metadata (read).", "The GitHub App subscribes to events: pull_request, issue_comment, pull_request_review_comment, pull_request_review, check_run.", "Claude Code detects the GHES hostname automatically from the git remote in the working directory; no developer config needed. Start a session with 'claude --remote \"<task>\"'.", "Teleport a web session into the local terminal with 'claude --teleport'; it verifies you are in a checkout of the same GHES repository before fetching the branch and loading session history.", "Plugin marketplace 'owner/repo' shorthand always resolves to github.com; for GHES marketplaces you must use the full git URL, e.g. '/plugin marketplace add git@github.example.com:platform/claude-plugins.git' (HTTPS URLs also work).", "Managed settings strictKnownMarketplaces supports a 'hostPattern' source type to allow all marketplaces from a GHES host without enumerating each repo, e.g. {\"source\":\"hostPattern\",\"hostPattern\":\"^github\\\\.example\\\\.com$\"}.", "extraKnownMarketplaces in managed settings pre-registers marketplaces org-wide so they appear without manual developer setup; entry uses {\"source\":{\"source\":\"git\",\"url\":\"git@github.example.com:...\"}}.", "GHES instance must be reachable from Anthropic infrastructure (to clone repos and post review comments); if behind a firewall, allowlist the Anthropic API IP addresses.", "Contribution metrics on GHES are delivered via webhooks to the analytics dashboard (requires Repository hooks read/write permission).", "Claude Security on GHES is in public beta for Enterprise plans at claude.ai/security.", "Claude Code for GitLab CI/CD is in beta and is maintained by GitLab (not Anthropic); support is via a GitLab issue tracker (gitlab.com/gitlab-org/gitlab/-/issues/573776).", "The integration is built on the Claude Code CLI and Agent SDK, enabling programmatic use in CI/CD jobs.", "Setup requires adding a masked CI/CD variable ANTHROPIC_API_KEY (Settings -> CI/CD -> Variables) and a `claude` job in `.gitlab-ci.yml`.", "The Claude CLI is installed in-job via `curl -fsSL https://claude.ai/install.sh | bash` (example uses image node:24-alpine3.21).", "In CI the CLI is invoked headless: `claude -p \"<prompt>\" --permission-mode acceptEdits --allowedTools \"Bash Read Edit Write mcp__gitlab\" --debug`.", "Context/trigger payloads are passed via AI_FLOW_* variables: AI_FLOW_INPUT (the prompt), AI_FLOW_CONTEXT, AI_FLOW_EVENT. AI_FLOW_INPUT is read by `claude -p`.", "Mention-driven triggers require a project webhook for 'Comments (notes)' plus a listener that calls the pipeline trigger API with AI_FLOW_INPUT/AI_FLOW_CONTEXT when a comment contains `@claude`.", "The trigger mention is `@claude` (literally), NOT `/claude`.", "Example job rules trigger on `$CI_PIPELINE_SOURCE == \"web\"` (manual/API) and `$CI_PIPELINE_SOURCE == \"merge_request_event\"`; uses GIT_STRATEGY: fetch.", "For GitLab API operations (writing comments, opening MRs) the job uses CI_JOB_TOKEN by default, or a Project Access Token with `api` scope stored as masked GITLAB_ACCESS_TOKEN.", "The `mcp__gitlab` tool must be listed in --allowedTools for Claude to comment/open MRs; an optional GitLab MCP server is started via `/bin/gitlab-mcp-server || true`.", "Three providers supported: Claude API (uses ANTHROPIC_API_KEY), Amazon Bedrock (OIDC IAM role, no static keys), Google Vertex AI (Workload Identity Federation, no service-account keys). ANTHROPIC_API_KEY is NOT used for Bedrock/Vertex.", "Bedrock requires CI/CD variables AWS_ROLE_TO_ASSUME (role ARN) and AWS_REGION; credentials obtained via `aws sts assume-role-with-web-identity` using GitLab OIDC token (CI_JOB_JWT_V2 / CI_JOB_JWT_FILE), default session duration 3600s.", "Bedrock model IDs include region-specific prefixes, e.g. `us.anthropic.claude-sonnet-4-6`.", "Vertex AI requires CI/CD variables GCP_WORKLOAD_IDENTITY_PROVIDER (full provider resource name), GCP_SERVICE_ACCOUNT (service account email), and CLOUD_ML_REGION (e.g. us-east5); auth via `gcloud auth login --cred-file` with an external_account config (no downloaded keys).", "Claude reads CLAUDE.md at the repository root during CI runs and follows its conventions when proposing changes.", "Common CLI inputs: `prompt`/`prompt_file` (-p inline or via file), `max_turns` (limit iterations), `timeout_minutes`/job timeout (limit execution time).", "Exact flags vary by `@anthropic-ai/claude-code` version; run `claude --help` in the job to see supported options.", "Each interaction runs in an isolated container with strict network and filesystem rules; Claude Code enforces workspace-scoped permissions to constrain writes; all changes flow through MRs subject to branch protection and approval rules.", "Bedrock model example references claude-sonnet-4-6 (current as of this beta doc); model IDs evolve.", "`-p` (alias `--print`) runs Claude Code non-interactively; all CLI options work with it, e.g. `claude -p \"...\" --allowedTools \"Read,Edit,Bash\"`.", "`--bare` reduces startup time by skipping auto-discovery of hooks, skills, plugins, MCP servers, auto memory, and CLAUDE.md; only explicitly passed flags take effect.", "Without `--bare`, `claude -p` loads the same context an interactive session would, including anything configured in the working directory or `~/.claude` (e.g. a teammate's hook in `~/.claude` or a project `.mcp.json` MCP server).", "In bare mode Claude has access only to Bash, file read, and file edit tools; other context must be passed via flags: `--append-system-prompt`/`--append-system-prompt-file`, `--settings <file-or-json>`, `--mcp-config <file-or-json>`, `--agents <json>`, `--plugin-dir <path>`/`--plugin-url <url>`.", "Bare mode skips OAuth and keychain reads; Anthropic auth must come from `ANTHROPIC_API_KEY` or an `apiKeyHelper` in the JSON passed to `--settings`. Bedrock/Vertex/Foundry use their usual provider credentials.", "`--bare` is documented as recommended for scripted/SDK calls and will become the default for `-p` in a future release.", "A background Bash task started during `claude -p` is terminated about 5 seconds after Claude returns its final result and stdin closes (grace period). Before v2.1.163, a never-exiting background process held the invocation open indefinitely.", "Background subagents and workflows are exempt from the 5-second grace; `claude -p` waits for them. From v2.1.182 that wait is capped at 10 minutes by default; adjust with `CLAUDE_CODE_PRINT_BG_WAIT_CEILING_MS`, or set to `0` to wait with no limit.", "`--output-format` accepts `text` (default), `json` (structured JSON with result, session ID, metadata), and `stream-json` (newline-delimited JSON for real-time streaming).", "With `--output-format json`, the response payload includes `total_cost_usd` and a per-model cost breakdown for tracking spend per invocation.", "`--output-format json` combined with `--json-schema '<JSON Schema>'` returns schema-conforming output in the `structured_output` field alongside request metadata (session ID, usage).", "Real-time token streaming requires `--output-format stream-json` together with `--verbose` and `--include-partial-messages`; each line is a JSON event object.", "Piped stdin is capped at 10MB as of Claude Code v2.1.128; exceeding it exits with a clear error and non-zero status. For larger inputs, write to a file and reference its path in the prompt.", "On retryable API failures Claude Code emits a `system/api_retry` stream event (fields: attempt, max_retries, retry_delay_ms, error_status, error category, uuid, session_id) before retrying.", "The `system/init` event is the first stream event (reports model, tools, MCP servers, loaded plugins) unless `CLAUDE_CODE_SYNC_PLUGIN_INSTALL` is set, in which case `plugin_install` events precede it. `init` includes `plugins` (loaded) and `plugin_errors` arrays.", "`--allowedTools \"Bash,Read,Edit\"` auto-approves listed tools without prompting; it uses permission rule syntax. Prefix matching like `Bash(git diff *)` needs a space before `*` — `Bash(git diff*)` would also match `git diff-index`.", "Permission mode `dontAsk` denies anything not in `permissions.allow` rules or the read-only command set (good for locked-down CI). `acceptEdits` lets Claude write files without prompting and auto-approves `mkdir`, `touch`, `mv`, `cp`; other shell/network still needs `--allowedTools` or a `permissions.allow` rule, else the run aborts.", "User-invoked skills and custom commands work in `-p` mode by including `/skill-name` in the prompt string (expanded before running). Interactive-dialog built-ins like `/login` are not available in `-p` mode.", "From v2.1.181, you can change a setting from a `-p` invocation by passing `key=value` to `/config` in the prompt, e.g. `/config thinking=false`.", "`--append-system-prompt` adds to the default system prompt; `--system-prompt` fully replaces it (`--append-system-prompt-file` reads from a file).", "`--continue` continues the most recent conversation; `--resume <session_id>` continues a specific one. Session ID lookup is scoped to the current project directory and its git worktrees, so resume commands must run from the same directory.", "This headless CLI is the Agent SDK accessed via the CLI; Python and TypeScript SDK packages add structured outputs, tool approval callbacks, and native message objects.", "A routine is a saved Claude Code config (prompt + one or more repos + connectors) that runs autonomously on Anthropic-managed cloud infrastructure, even with the laptop closed.", "Routines are available only on Pro, Max, Team, and Enterprise plans with Claude Code on the web enabled.", "Three trigger types exist and can be combined on one routine: Scheduled (recurring or one-off future time), API (HTTP POST with bearer token), and GitHub (repo events).", "Team and Enterprise admins can disable routines org-wide via the Routines toggle at claude.ai/admin-settings/claude-code; when disabled, existing routines stop running and members cannot create new ones. This is a server-side setting and cannot be overridden locally.", "Routines belong to your individual claude.ai account, are NOT shared with teammates, and count against your account's daily run allowance.", "Anything a routine does appears as YOU: commits/PRs carry your GitHub user; Slack/Linear/connector actions use your linked accounts.", "Routines run as full Claude Code cloud sessions with NO permission-mode picker and NO approval prompts during a run; Claude can use every tool from an included connector, including writes, without asking.", "Create/manage routines at claude.ai/code/routines, in the Desktop app (Routines > New routine > Remote; Local instead creates a Desktop scheduled task), or via CLI /schedule. All three surfaces write to the same cloud account and sync immediately.", "CLI /schedule creates SCHEDULED routines only. Adding API or GitHub triggers requires editing the routine on the web. /schedule list, /schedule update, /schedule run manage existing routines.", "Each repo is cloned at the start of every run from its default branch. Claude creates claude/-prefixed branches for changes. By default Claude can only push to claude/-prefixed branches; enable 'Allow unrestricted branch pushes' per-repo to push to existing branches.", "Schedule presets: hourly, daily, weekdays, weekly. Times entered in local zone, converted to UTC. Runs may start a few minutes late due to a consistent per-routine stagger offset.", "Custom cron intervals are set via 'closest preset in form' then '/schedule update' in CLI. Minimum interval is one hour; more-frequent expressions are rejected.", "One-off scheduled runs auto-disable after firing (UI marks 'Ran'); they do NOT count against the daily routine run cap but DO draw down regular subscription usage.", "API trigger: POST to the routine's /fire endpoint (https://api.anthropic.com/v1/claude_code/routines/{trig_id}/fire) with 'Authorization: Bearer' token; returns claude_code_session_id and session URL.", "The /fire request body accepts an optional 'text' field passed alongside the saved prompt. It is freeform and NOT parsed: JSON/structured payloads are received as a literal string.", "The /fire endpoint requires headers: anthropic-beta: experimental-cc-routine-2026-04-01, anthropic-version: 2023-06-01, Content-Type: application/json. It is available to claude.ai users only, not part of the Claude Platform API surface.", "The /fire endpoint is in research preview behind the experimental-cc-routine-2026-04-01 beta header; shapes/limits/token semantics may change. Breaking changes ship behind new dated beta headers, with the two most recent previous versions still working for migration.", "Each routine has its own API token scoped to triggering that routine only. Token is shown ONCE on generation and cannot be retrieved later; rotate/revoke via Regenerate/Revoke in the same modal. CLI cannot create or revoke tokens.", "GitHub triggers require installing the Claude GitHub App on the repo (which also enables webhook delivery). Running /web-setup grants clone access but does NOT install the app or enable webhooks.", "Supported GitHub events: Pull request (opened/closed/assigned/labeled/synchronized/etc.) and Release (created/published/edited/deleted). You can pick a specific action or react to all in the category.", "PR filter fields: Author, Title, Body, Base branch, Head branch, Labels, Is draft, Is merged. Operators: equals, contains, starts with, is one of, is not one of, matches regex. ALL conditions must match.", "The 'matches regex' operator tests the ENTIRE field value, not a substring; to match 'hotfix' anywhere use '.*hotfix.*'. Use 'contains' for literal substring matching.", "During research preview, GitHub webhook events have per-routine and per-account hourly caps; events beyond the limit are dropped until the window resets.", "Each matching GitHub event starts its own independent session; session reuse across events is not available, so two PR updates produce two sessions.", "Connectors are claude.ai integrations on your account. MCP servers added locally via 'claude mcp add' are stored on your machine, NOT your claude.ai account, so they do NOT appear in the connectors list.", "To use a local MCP server in a routine, add it as a connector at claude.ai/customize/connectors, or declare it in a committed .mcp.json so it ships with the cloned repo.", "All currently connected connectors are included by default when creating a routine; remove unneeded ones to limit tool access. Connector traffic is routed through Anthropic's servers, so connector hosts need NOT be added to Allowed domains.", "The Default environment uses Trusted network access: a default allowlist (package registries, cloud provider APIs, container registries, common dev domains) is reachable; other hosts fail with 403 and header x-deny-reason: host_not_allowed.", "To allow more domains: edit environment > Network access > Custom, enter domains in Allowed domains (optionally check 'Also include default list of common package managers'), or choose Full for unrestricted. New policy applies from next run.", "Environment setup script results are cached so the script does not re-run every session.", "Routines draw down subscription usage like interactive sessions, plus a per-account daily cap on runs started. Without usage credits, runs are rejected once the cap/limit is hit; with usage credits on (Settings > Billing) runs continue on metered overage.", "/schedule is hidden ('Unknown command') if: authenticated with a Console API key or Bedrock/Vertex/Foundry (ANTHROPIC_API_KEY, ANTHROPIC_AUTH_TOKEN, or apiKeyHelper in settings.json take precedence over claude.ai login and must be removed); DISABLE_TELEMETRY/DO_NOT_TRACK/CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC/DISABLE_GROWTHBOOK is set; you're inside a web session; or CLI is older than v2.1.81 (run 'claude update').", "Scheduled tasks require Claude Code v2.1.72 or later; check with `claude --version`.", "Scheduled tasks (/loop and cron) are session-scoped: they live in the current conversation and stop when you start a new conversation.", "`claude --resume`/`claude --continue` restores unexpired tasks: recurring tasks created within the last 7 days, and one-shots whose fire time hasn't passed. Background Bash and Monitor tasks are NEVER restored on resume.", "Three scheduling options: Cloud (Routines, Anthropic infra, min interval 1 hour, no local files, runs without open session), Desktop scheduled tasks (local machine, min interval 1 minute, needs machine on), and /loop (local, min interval 1 minute, needs open session).", "Cloud/Routines minimum interval is 1 hour; Desktop and /loop minimum interval is 1 minute.", "Cloud routines run autonomously with NO permission prompts and use a fresh clone (no local file access); Desktop tasks have configurable per-task permissions; /loop inherits permissions and MCP servers from the session.", "/loop is a bundled skill. `/loop 5m <prompt>` runs on fixed interval; `/loop <prompt>` lets Claude pick the interval each iteration; bare `/loop` runs the built-in maintenance prompt (or loop.md) at a dynamically chosen interval.", "You can pass a command as the /loop prompt, e.g. `/loop 20m /review-pr 1234`, to re-run a saved skill/command each iteration.", "Interval units: `s` seconds, `m` minutes, `h` hours, `d` days. Seconds round up to nearest minute (cron is 1-minute granularity). Non-clean intervals (7m, 90m) round to nearest valid cron step and Claude reports what it picked.", "Self-paced /loop (no interval) picks a delay between 1 minute and 1 hour after each iteration based on observed activity; prints chosen delay and reason.", "loop.md replaces the built-in maintenance prompt for bare /loop. Lookup precedence: `.claude/loop.md` (project, takes precedence) then `~/.claude/loop.md` (user). loop.md is ignored when you supply a prompt on the command line.", "loop.md content beyond 25,000 bytes is truncated. Edits take effect on the next iteration.", "Stop a waiting /loop with `Esc`, which clears the pending wakeup. Tasks scheduled by asking Claude directly are NOT affected by Esc; delete them explicitly.", "One-time reminders: describe in natural language (e.g. 'remind me at 3pm to push the release branch'); Claude schedules a single-fire task that deletes itself after running.", "Cron tools: `CronCreate` (5-field cron expr + prompt + recurs/once), `CronList` (IDs, schedules, prompts), `CronDelete` (cancel by ID). Each task has an 8-character ID.", "A session can hold up to 50 scheduled tasks at once.", "Scheduler checks every second for due tasks, enqueues at low priority. A scheduled prompt fires between turns, not mid-response; if Claude is busy the prompt waits until the current turn ends.", "All cron times are interpreted in local timezone, not UTC. `0 9 * * *` = 9am local.", "Jitter: recurring tasks fire up to 30 min after scheduled time (or up to half the interval for sub-hourly tasks); one-shots at top/bottom of hour fire up to 90 seconds early. Offset is deterministic from task ID. Avoid jitter by picking a minute that isn't :00 or :30 (e.g. `3 9 * * *`).", "Recurring tasks expire 7 days after creation: fire one final time then self-delete. Self-paced /loops also end 7 days after start.", "CronCreate accepts standard 5-field cron (minute hour day-of-month month day-of-week). Supports `*`, single values, steps `*/15`, ranges `1-5`, lists `1,15,30`. Day-of-week 0 or 7 = Sunday, 6 = Saturday. Extended syntax (L, W, ?, MON, JAN aliases) NOT supported.", "When both day-of-month and day-of-week are constrained, a date matches if EITHER field matches (standard vixie-cron semantics).", "Set `CLAUDE_CODE_DISABLE_CRON=1` to disable the scheduler entirely: cron tools and /loop become unavailable and already-scheduled tasks stop firing.", "No catch-up for missed fires: if a task's time passes while Claude is busy, it fires once when idle, not once per missed interval. Tasks only fire while Claude Code is running and idle.", "On Bedrock, Vertex AI, and Microsoft Foundry: a prompt with no interval runs on a fixed 10-minute schedule; bare `/loop` (no prompt) prints usage instead of running the maintenance prompt; loop.md is not read.", "Dynamic/self-paced /loop may use the Monitor tool to run a background script and stream output lines, avoiding polling — more token-efficient and responsive than re-running a prompt on an interval.", "Claude Code in Slack requires a Pro, Max, Team, or Enterprise plan with Claude Code access (premium seats or Chat + Claude Code seats).", "Prerequisites: Claude Code on the web enabled, a GitHub account connected with at least one authenticated repository, and the Slack account linked to the Claude account.", "A Slack workspace administrator must install the Claude app from the Slack App Marketplace (app id A08SF47R6P4); individual users then connect their Claude account via the App Home tab.", "Claude is NOT auto-added to channels; you must run /invite @Claude in each channel, and Claude only responds to @mentions in channels it has been added to.", "Claude Code in Slack works only in public or private channels, NOT in direct messages (DMs).", "Routing Mode is set in the Claude App Home: 'Code only' routes all @mentions to Claude Code; 'Code + Chat' routes intelligently between Claude Code and Claude Chat.", "In Code + Chat mode, 'Retry as Code' converts a chat-routed message to a Claude Code session (and the reverse is also available in-thread).", "Each user runs sessions under their own Claude account; sessions count against the individual user's plan rate limits.", "Users can only access repositories they have personally connected in Claude Code on the web; repo access is not shared across the team.", "Removing the Claude app from a workspace immediately revokes access for all users in that workspace.", "For Enterprise Grid organizations, organization admins can control which workspaces have access to the Claude app.", "For Enterprise and Team accounts, sessions created from Claude in Slack are automatically visible to the organization (see Claude Code on the Web sharing).", "Limitation: GitHub only (no other Git hosts supported).", "Limitation: each session can create only one pull request.", "Users without Claude Code on the web access get only standard Claude chat responses, not coding sessions.", "When mentioned in a thread, Claude gathers context from all messages in that thread; when mentioned directly in a channel, it uses recent channel messages.", "Action buttons after completion: View Session, Create PR, Retry as Code, Change Repo.", "Tool names are the exact strings used in permission rules, subagent tool lists, and hook matchers. To disable a tool entirely, add its name to the `deny` array in permission settings.", "Tools requiring permission (Permission Required = Yes): Artifact, Bash, Edit, ExitPlanMode, Monitor, NotebookEdit, PowerShell, ShareOnboardingGuide, Skill, WebFetch, WebSearch, Workflow, Write.", "Tools NOT requiring permission (No): Agent, AskUserQuestion, CronCreate, CronDelete, CronList, EnterPlanMode, EnterWorktree, ExitWorktree, Glob, Grep, ListMcpResourcesTool, LSP, PushNotification, Read, ReadMcpResourceTool, RemoteTrigger, ScheduleWakeup, SendMessage, TaskCreate/Get/List/Stop/Update, TaskOutput, TodoWrite, ToolSearch, WaitForMcpServers.", "Permission rule format is `ToolName(specifier)`, shared across settings permissions.allow/deny, --allowedTools/--disallowedTools CLI flags, Agent SDK allowedTools/disallowedTools, subagent tools/disallowedTools frontmatter, skill allowed-tools frontmatter, and hook `if` conditions.", "Specifier groupings: `Bash(npm run *)` applies to Bash and Monitor; `PowerShell(Get-ChildItem *)` to PowerShell; `Read(~/secrets/**)` to Read, Grep, Glob, LSP; `Edit(/src/**)` to Edit, Write, NotebookEdit; `Skill(deploy *)`; `Agent(Explore)`; `WebFetch(domain:example.com)`; `WebSearch` (no specifier, allow/deny whole tool).", "An `Edit(...)` allow rule also grants read access to the same path, so a matching `Read(...)` rule is not needed.", "Hook `matcher` fields use bare tool names, NOT the parenthesized rule format. Tools like ExitPlanMode or ShareOnboardingGuide accept only the bare tool name with no specifier.", "Subagent tool resolution: neither tools nor disallowedTools set => inherits all parent tools; tools only => only listed tools; disallowedTools only => all parent tools except listed; both set => disallowedTools takes precedence (a tool in both is removed).", "Launching a subagent does not prompt for permission; the subagent's own tool calls are checked against permission rules as it runs. Cap subagent turns with `maxTurns` in the subagent definition.", "As of v2.1.186, background subagents surface permission prompts in the main session (naming which subagent asks; Esc denies that one call without stopping the subagent). Before v2.1.186, background subagents auto-denied any prompting tool call and continued without it.", "Bash: `cd` in the main session carries working directory to later Bash commands only while inside the project dir or an additional working directory added via --add-dir, /add-dir, or additionalDirectories. cd outside resets to project dir and appends 'Shell cwd was reset to <dir>'. Subagent sessions never carry over cwd changes.", "Set CLAUDE_BASH_MAINTAIN_PROJECT_WORKING_DIR=1 to disable cd carry-over so every Bash command starts in the project directory.", "Bash environment variables do not persist across commands (export does not carry). Aliases/functions/shell options from ~/.zshrc, ~/.bashrc, or ~/.profile are sourced at session start and applied to every Bash command.", "To persist env vars across Bash commands, set CLAUDE_ENV_FILE to a shell script before launching, or populate it via a SessionStart hook. Activate virtualenv/conda before launching Claude Code.", "Bash timeout: 2 minutes default, up to 10 minutes per command via the timeout parameter. Override with BASH_DEFAULT_TIMEOUT_MS and BASH_MAX_TIMEOUT_MS env vars.", "Bash output length: 30,000 characters default; overflow saved to a file in the session directory with path + preview given to Claude. Raise with BASH_MAX_OUTPUT_LENGTH up to a hard ceiling of 150,000 characters.", "Bash run_in_background:true starts a command as a background task; list/stop background tasks with /tasks.", "Edit requires three checks: read-before-edit (file read in current conversation and unchanged on disk since the read), exact match of old_string, and uniqueness (one occurrence, else longer context or replace_all:true). Edit does exact string replacement, no regex/fuzzy.", "Viewing a file with Bash satisfies read-before-edit ONLY for cat, head, tail, sed -n 'X,Yp', grep, egrep, or fgrep on a single file with no pipes or redirects. Piped output and other commands do not count.", "Read/Edit deny rules apply to recognized file commands in Bash (cat, head, tail, sed, grep) but NOT to arbitrary subprocesses (e.g. a Python/Node script opening files). The read-before-edit command set differs from the deny-rule command set (egrep/fgrep count for read-before-edit but are not checked against Read deny rules).", "For OS-level enforcement covering every process, enable the sandbox (/en/sandboxing).", "Glob results are sorted by modification time and capped at 100 files; truncation is flagged. Glob does NOT respect .gitignore by default (finds gitignored files). Set CLAUDE_CODE_GLOB_NO_IGNORE=false to make Glob respect .gitignore.", "Grep is built on ripgrep (ripgrep regex syntax, not POSIX); metacharacters need escaping (e.g. interface\\{\\}). Default output mode is files_with_matches; other modes are content and count. Grep respects .gitignore (skips gitignored files unless path passed directly).", "NotebookEdit targets cells by cell_id with modes replace (default), insert (after target; no cell_id => start; requires cell_type code/markdown), delete. Permission rules use Edit(...) path format, e.g. Edit(notebooks/**).", "Write: overwriting an existing path requires the file to have been read at least once in the current conversation; Write to an unread existing file fails. Constraint does not apply to new files. Write does not append/merge; use Edit for partial changes.", "WebFetch converts HTML to Markdown and runs the prompt against content via a small fast model; Claude receives that model's answer, not the raw page (lossy by design; conversion not configurable). HTTP upgraded to HTTPS; large pages truncated to a fixed char limit; responses cached 15 minutes; cross-host redirects returned as text (not followed) for a second fetch.", "WebFetch in default and acceptEdits modes prompts the first time it reaches a new domain, except a built-in preapproved set of documentation domains. Add WebFetch(domain:example.com) to allow in advance. auto and bypassPermissions modes skip the prompt. An explicit WebFetch(domain:...) in deny/ask/allow overrides the preapproved set.", "WebFetch sets a User-Agent starting with Claude-User and an Accept header preferring Markdown. Sandbox network rules are separate; a domain still needs an explicit sandbox permission rule for a sandboxed process.", "WebSearch uses Anthropic's web search backend (not configurable), returns titles+URLs only (no page fetch), may issue up to 8 backend searches per call. Scope with allowed_domains or blocked_domains (cannot combine both in one call). Permission rules take no specifier (bare WebSearch in allow/deny only).", "WebSearch availability: Claude API and Microsoft Foundry; Vertex AI with Claude 4 models (Opus/Sonnet/Haiku); Amazon Bedrock does NOT expose server-side web search.", "Read returns contents with line numbers; always pass absolute paths. Whole-file read over token limit returns first page with PARTIAL view notice + offset/limit guidance; a read with explicit offset/limit still over limit returns an error. PDFs over 10 pages read in ranges via pages param (e.g. '1-5'), up to 20 pages at a time. Read does not read directories (use ls via Bash).", "Monitor uses the same permission rules as Bash. Not available on Amazon Bedrock, Google Vertex AI, or Microsoft Foundry, nor when DISABLE_TELEMETRY or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set. Requires v2.1.98+. Plugins can declare auto-starting monitors.", "PowerShell tool enabled via CLAUDE_CODE_USE_POWERSHELL_TOOL=1 (env or settings.json). On Windows without Git Bash it auto-enables; with Git Bash it rolls out progressively (set to 0 to opt out). On Linux/macOS/WSL it is opt-in and requires PowerShell 7+ (pwsh on PATH).", "PowerShell spawns with -ExecutionPolicy Bypass at process scope only; does not override Group Policy MachinePolicy/UserPolicy (enterprise lockdowns still apply). Set CLAUDE_CODE_POWERSHELL_RESPECT_EXECUTION_POLICY=1 to respect the machine's effective policy. Preview limits: profiles not loaded; Windows sandboxing not supported.", "Shell selection settings: defaultShell:powershell routes interactive ! commands through PowerShell (requires tool enabled); shell:powershell on a command hook runs that hook in PowerShell (works regardless of the env var, hooks spawn directly); shell:powershell in skill frontmatter runs !`command` blocks in PowerShell (requires tool enabled).", "TodoWrite is disabled by default as of v2.1.142 in favor of TaskCreate/TaskGet/TaskList/TaskUpdate; re-enable with CLAUDE_CODE_ENABLE_TASKS=0. TaskOutput is deprecated; prefer Read on the task's output file path.", "ToolSearch loads deferred tools when tool search is enabled; WaitForMcpServers only appears when tool search is disabled (ToolSearch handles the wait otherwise). Both min-version notes: WaitForMcpServers requires v2.1.142+.", "Custom tools are added by connecting an MCP server; reusable prompt-based workflows are written as skills, which run through the existing Skill tool rather than adding a new tool entry.", "Artifact tool requires a Team or Enterprise plan plus /login authentication.", "PushNotification, RemoteTrigger (Routines), and ScheduleWakeup run through Anthropic-hosted infrastructure and are NOT accessible from Amazon Bedrock, Google Vertex AI, or Microsoft Foundry. RemoteTrigger/Routines require Pro/Max/Team/Enterprise.", "LSP tool is inactive until a code intelligence plugin is installed for the language (plugin bundles language server config; server binary installed separately).", "To verify the loaded tool set in a running session, ask Claude 'What tools do you have access to?'; for exact MCP tool names run /mcp. The advisor tool is a server tool run by the API with no referenceable name in permission rules or hook matchers."]}, "Plugins & distribution": {"pages": ["discover-plugins", "plugin-dependencies", "plugin-hints", "plugin-marketplaces", "plugin-relevance", "plugins", "plugins-reference"], "bestPractices": ["For team distribution, commit `extraKnownMarketplaces` (and `enabledPlugins`) to the project `.claude/settings.json` so collaborators are auto-prompted to install the org marketplace/plugins on folder-trust, rather than each member adding it manually.", "Use Project scope to share a plugin with all repo collaborators; use User scope for personal cross-project tools; use Local scope for yourself in one repo only.", "Review a plugin's 'Will install' inventory and 'Context cost' estimate in the detail pane before installing, to avoid silently adding per-turn token overhead.", "Pin/distribute plugins via your own Git-based marketplace (not URL-based) to avoid relative-path install failures; use `#<ref>` to pin to a tag for reproducible team installs.", "For org governance, combine managed marketplace restrictions (allowlist who can add what) with `pluginSuggestionMarketplaces` to surface approved plugins by directory.", "On large repos, disable memory-heavy LSP plugins (rust-analyzer, pyright) with `/plugin disable <name>` if you hit memory issues and fall back to built-in search.", "Set `DISABLE_AUTOUPDATER=1` + `FORCE_AUTOUPDATE_PLUGINS=1` when you manage Claude Code version centrally but still want plugins to auto-update.", "For internal/team marketplaces where multiple teams publish interdependent plugins, declare version constraints (e.g. `{ \"name\": \"secrets-vault\", \"version\": \"~2.1.0\" }`) on cross-team dependencies so an upstream breaking release does not auto-update and break dependents for every engineer.", "Upgrade a pinned dependency on your own schedule by publishing a new version of the dependent plugin with a wider constraint — don't loosen by editing the upstream.", "Tag every plugin release with `claude plugin tag --push` (or `git tag {name}--v{version}`) so version constraints can resolve; without matching tags dependents get `no-matching-tag` and are disabled. Use `--dry-run` first.", "Keep `plugin.json` `version` and the marketplace entry version in agreement — `claude plugin tag` validates this and refuses otherwise.", "In CI or scripts, check dependency health with `claude plugin list --json` and inspect each plugin's `errors` field rather than parsing human output.", "Use one marketplace repo to host multiple plugins with independent version lines — the `{plugin-name}--v` tag prefix keeps their releases separate.", "When disabling a depended-on plugin, copy the chained `disable A && disable B` command from the error to tear down the set in the correct order.", "Run `claude plugin uninstall <plugin> --prune` (or periodic `claude plugin prune`) to clean up auto-installed dependencies and avoid orphan accumulation; use `-y` in non-interactive contexts since prune otherwise exits without removing.", "To detect whether a script/CLI/hook is running inside Claude Code, check the CLAUDECODE env var (set to 1); prefer CLAUDE_CODE_CHILD_SESSION (v2.1.172+) when you must avoid false positives in human-run tmux or IDE terminals.", "When gating CLI behavior on CLAUDECODE, remember it is also set in tmux panes, stdio MCP subprocesses, and IDE integrated terminals where a human may actually be at the keyboard — do not assume CLAUDECODE means 'no human present.'", "To distribute plugins to a team, host marketplace.json on GitHub and have users add `owner/repo`; commit `extraKnownMarketplaces` (and optionally `enabledPlugins`) to the repo's `.claude/settings.json` so members are auto-prompted on folder trust.", "For shared-team marketplace declarations, add with `claude plugin marketplace add <repo> --scope project` so it lands in `.claude/settings.json` instead of user scope.", "Bump `version` on every plugin release, or omit `version` entirely on git sources so each commit is a new version — otherwise existing users keep the stale cached copy.", "Never set `version` in both plugin.json and the marketplace entry; plugin.json wins silently and can mask the marketplace value.", "For org control, set `strictKnownMarketplaces` in managed-settings.json and pair with `extraKnownMarketplaces` (an allowlist alone registers nothing). Prefer `hostPattern` regex over literal URLs so all clone-URL forms match (no URL normalization).", "Pin production plugins to an exact commit via `sha`; installs survive deletion of the named branch/tag on GitHub/GitLab/Bitbucket.", "For monorepos use `git-subdir` source or `--sparse <paths>` on add to fetch only the plugin directory and save bandwidth.", "For private marketplaces that auto-update, export `GITHUB_TOKEN`/`GITLAB_TOKEN`/`BITBUCKET_TOKEN` in the environment — credential helpers are not used during startup auto-update.", "For containers/CI, pre-populate plugins at build time via `CLAUDE_CODE_PLUGIN_SEED_DIR` (build with `CLAUDE_CODE_PLUGIN_CACHE_DIR`) so no runtime cloning is needed; works with `-p`.", "Run `claude plugin validate .` against the marketplace dir and against each plugin dir before sharing; the two targets check different things (marketplace schema vs plugin frontmatter/hooks).", "For airgapped/offline deployments set `CLAUDE_CODE_PLUGIN_KEEP_MARKETPLACE_ON_FAILURE=1` to avoid a failed git pull wiping the cache, and prefer seed dirs for fully offline.", "Implement stable/latest release channels with two marketplaces on different refs assigned per user group via managed settings, ensuring each ref resolves to a distinct version string.", "To distribute org-recommended plugins via session signals, add a `relevance` block to each plugin in marketplace.json, then in managed-settings.json add the marketplace to `pluginSuggestionMarketplaces` AND register its source in `extraKnownMarketplaces`/`strictKnownMarketplaces` (source registration is mandatory for non-official marketplaces).", "In `manifestDeps.file` regexes, end-anchor and use `[/\\\\]` for cross-platform path separators (e.g. `[/\\\\]package\\.json$`); a start-anchored pattern never matches an absolute path. Double each backslash in JSON.", "Don't rely on `cli` for compound commands: `cd infra && terraform plan` records only `cd`. Declare the literal leading command you expect, or use a different signal (filesRead/manifestDeps/hosts).", "Use `cwd` signals for the strongest UX since it is the only signal that fires at session start before the first turn.", "Run `claude plugin validate ./my-marketplace` before publishing to catch unknown keys, non-object `relevance`, and malformed `hosts` entries.", "To disable all plugin suggestion tips org-wide or per-project, set `spinnerTipsEnabled` to `false` (also disables the one built-in suggestion).", "Start with standalone `.claude/` config for fast iteration, then convert to a plugin when ready to share with the team (mkdir `.claude-plugin/`, add plugin.json, copy `commands/`/`agents/`/`skills/`, move hooks into `hooks/hooks.json`).", "Set an explicit `version` in plugin.json for team plugins so consumers only update on intentional bumps, rather than relying on the git-SHA-per-commit behavior.", "Keep plugins internal by hosting the marketplace in a private repository; team members install via `/plugin install` from that marketplace.", "Use `skills/<name>/SKILL.md` layout (not the legacy flat `commands/`) for any plugin that might grow beyond one skill.", "Develop with `claude --plugin-dir ./plugin` and iterate using `/reload-plugins` instead of restarting; verify skills via `/plugin:skill`, agents via `/agents`, and hook firing.", "Run `claude plugin validate` locally before distributing or submitting — it mirrors the marketplace review check.", "After converting standalone config to a plugin, delete the original `.claude/` files to avoid duplicate skills and so plugin agents actually take effect (project/user agents override plugin agents of the same name).", "Add a `description` to every SKILL.md frontmatter so Claude knows when to model-invoke the skill; set `disable-model-invocation: true` for skills that should only run when explicitly called.", "Distribute team plugins via project scope: 'claude plugin install <plugin>@<marketplace> --scope project' writes enabledPlugins to .claude/settings.json, which is checked into VCS and reaches everyone who clones.", "For internal/team plugins under active development, leave 'version' unset in plugin.json so the git commit SHA is the version and users get every new commit; set an explicit semver only for stable published releases (and bump it on every change).", "Use 'claude plugin validate ./plugin --strict' in CI to catch misspelled or leftover manifest fields before publishing, since unrecognized fields only warn at runtime.", "Run 'claude plugin details <name>' before adopting a plugin team-wide to see its always-on token cost (added to every session) and budget context accordingly.", "Always reference bundled scripts/binaries via ${CLAUDE_PLUGIN_ROOT} (never absolute paths) and persist installed deps (node_modules, venvs) under ${CLAUDE_PLUGIN_DATA} since CLAUDE_PLUGIN_ROOT changes on every update.", "Set frontmatter 'name' on root SKILL.md / single-skill plugins so the invocation name is stable; otherwise it defaults to the install-dir version string that changes on every marketplace update.", "Ship plugin-shipped instructions as a skill, not a CLAUDE.md at plugin root (which is not loaded as context).", "Use 'defaultEnabled: false' (v2.1.154+) for plugins that add cost or connect to external services so they install opt-in.", "Launch Claude Code from the repo root (or run /reload-plugins after cd) when using project-scope @skills-dir plugins, since they do not walk up to the repo root.", "Govern @skills-dir plugins fleet-wide via managed settings: strictKnownMarketplaces or blockedMarketplaces {\"source\":\"skills-dir\"} blocks them and makes 'plugin init' fail before writing.", "Mark secrets in userConfig with sensitive:true so they go to the keychain instead of settings.json; keep them small (~2KB keychain budget shared with OAuth)."], "gotchas": ["Removing a marketplace uninstalls every plugin you installed from it.", "Plugins run arbitrary code with your user privileges; Anthropic does not control or verify bundled MCP servers/files even on the community marketplace (which only passes automated screening).", "In-app submission forms go to the community marketplace, not the official one — you cannot self-submit to the official catalog.", "Plugins are copied to a cache, so paths referencing files outside the plugin directory won't work after install.", "`/reload-plugins` of a plugin with non-deferred MCP servers invalidates the prompt cache and forces a full re-read on the next request (extra cost); v2.1.163+ blocks it unless you pass `--force`.", "LSP plugins fail silently-ish: 'Executable not found in $PATH' shows in the /plugin Errors tab if the required language-server binary isn't installed.", "URL-based marketplaces have limitations vs Git-based ones and can produce 'path not found' errors for plugins using relative paths.", "Managed-scope plugins (installed by admins via managed settings) cannot be modified or removed by users.", "Without a version constraint, background auto-update silently moves a dependency to the marketplace's latest version, which can break a dependent if upstream renames an MCP tool or otherwise breaks compatibility.", "Dependencies whose marketplace you have not added are left unresolved and the dependent stays disabled until you `claude plugin marketplace add` it.", "Cross-marketplace dependencies are default-DENIED; install fails with a `cross-marketplace` error unless the ROOT marketplace lists the target in `allowCrossMarketplaceDependenciesOn`. Trust does not chain through intermediate marketplaces.", "Enabling a plugin force-writes `true` for its dependencies even if a dependency declares `defaultEnabled: false` — its own default is overridden by being pulled in.", "For `npm`-sourced plugins the version constraint does NOT pick the fetched version (tag resolution is git-only); the constraint is only enforced at load time and a mismatch disables the plugin with `dependency-version-unsatisfied`.", "Incompatible constraint ranges across plugins (e.g. `~2.1` vs `~3.0`) cause the second install to fail with `range-conflict`; the existing plugin and dependency are left unchanged.", "If no tag satisfies all installed ranges, auto-update is silently skipped — only visible in `/doctor` and the `/plugin` Errors tab.", "Pre-release tags are excluded from resolution unless the range explicitly opts in with a pre-release suffix like `^2.0.0-0`.", "Pre-v2.1.143 Claude Code does NOT cascade enable/disable across dependencies; it only acts on the named plugin and surfaces `dependency-unsatisfied` on next load.", "Enable fails (not warns) if a dependency is set to `false` at a higher-precedence scope than your target scope — you must enable it at that scope or pass `--scope` to write there.", "`claude plugin prune` only removes auto-installed dependencies; plugins you installed yourself are never pruned. In non-TTY contexts it lists orphans and exits without removing unless `-y` is passed.", "CLAUDECODE leaks beyond pure tool subprocesses: it is set in tmux sessions, stdio MCP server subprocesses, and IDE-extension integrated terminals, so a human running a CLI directly can see it set.", "CLAUDE_CODE_CHILD_SESSION is captured by long-lived processes (e.g. a tmux server) started inside a Claude Code session, so shells later launched from that process still see it set even outside the original session.", "Plugin install hints only fire for the curated claude-plugins-official marketplace; the in-app submission forms route plugins to the community marketplace, which the hint protocol ignores.", "An install prompt unanswered for 30 seconds auto-dismisses as No, and a plugin is only ever prompted once (per plugin, ever) and at most once per session across all CLIs.", "Relative-path plugin sources only resolve when the marketplace is added via git (GitHub/GitLab/git URL). Adding via a direct URL to marketplace.json downloads ONLY that file, so `./plugins/...` sources fail with 'path not found' — use github/npm/git-url sources for URL-distributed marketplaces.", "Setting `version` pins the plugin: pushing new commits without bumping the version string does nothing for existing users (same version = cached copy kept).", "version in plugin.json silently overrides version in the marketplace entry, so a stale manifest can mask your intended release version.", "Removing a marketplace from its LAST scope uninstalls all plugins installed from it; use `marketplace update` to refresh without losing plugins.", "Plugins run from a cache copy, not in place — `../` references outside the plugin dir break; only symlinks or restructuring fix it.", "Default 120s git timeout causes 'Git clone/pull timed out' on large repos or slow networks; raise CLAUDE_CODE_PLUGIN_GIT_TIMEOUT_MS.", "On a failed `git pull`, Claude wipes and re-clones by default; in offline/airgapped environments the re-clone fails too and the marketplace goes empty unless CLAUDE_CODE_PLUGIN_KEEP_MARKETPLACE_ON_FAILURE=1 is set.", "strictKnownMarketplaces matching is exact and unnormalized — trailing slash, `.git` suffix, and ssh vs https are treated as different; a literal-URL allowlist can silently reject valid clones.", "Two release channels that resolve to the same version string are treated as identical and the update is skipped — each channel must resolve to a distinct version/SHA.", "Seed-managed (CLAUDE_CODE_PLUGIN_SEED_DIR) marketplaces are read-only: `/plugin marketplace remove` and `update` fail against them; opt out of a seed plugin with `/plugin disable`, and seed entries overwrite matching user config on every startup.", "Plugin names that aren't strict kebab-case load in Claude Code but are rejected by Claude.ai marketplace sync.", "`allowCrossMarketplaceDependenciesOn` must list other marketplaces a plugin depends on, or those dependencies are blocked at install time.", "$schema in marketplace.json is for editor tooling only — Claude Code ignores it at load time.", "Allowlisting alone is insufficient for non-official marketplaces: you must also declare the marketplace source, or the allowlisted name is ignored — and if the registered marketplace came from a different source than declared, suggestions are suppressed (anti name-squatting).", "`manifestDeps` paths are NOT separator-normalized (unlike cwd/filesRead), so Windows paths use backslashes; a naive forward-slash-only `file` regex will silently fail to match on Windows.", "`cli` only captures the leading token after env assignments/sudo per shell invocation; commands buried after `&&`, in pipes, or as args are never recorded.", "Even the official Anthropic marketplace produces no relevance suggestions until explicitly allowlisted in `pluginSuggestionMarketplaces` (one built-in suggestion is the sole exception).", "`filesRead`/`manifestDeps` match against ALL recorded session file state — including files Claude wrote/edited and auto-loaded CLAUDE.md files — not just files the user explicitly opened.", "Manifest files over 512 KB are silently skipped for `manifestDeps` matching.", "Suggestions are heavily rate-limited (once per 3 sessions across tip+session-start; session-start caps at 2 total shows), so absence of a suggestion does not mean misconfiguration.", "Component directories (`commands/`, `agents/`, `skills/`, `hooks/`) must NOT be placed inside `.claude-plugin/` — only `plugin.json` goes there. Misplacing them silently breaks the plugin.", "Omitting `version` in plugin.json means every git commit is treated as a new version (SHA-based), causing constant 'updates' for consumers.", "Project/user `.claude/agents/` definitions override same-named plugin agents — after migrating, leftover originals shadow the plugin version.", "`--plugin-dir` local copy overrides an installed plugin of the same name, but CANNOT override plugins force-enabled/force-disabled by managed (enterprise) settings.", "Plugin `settings.json` silently ignores unknown keys and currently honors only `agent` and `subagentStatusLine` — other settings you add there have no effect.", "`.zip` plugin support for `--plugin-dir` requires Claude Code v2.1.128 or later; older versions won't load zipped plugins.", "In non-interactive scripts that run before the first interactive launch, `claude-plugins-official` is NOT auto-registered — you must add it explicitly.", "Community-marketplace approval does not make a plugin immediately installable: the catalog syncs nightly, so there is a delay before it appears in marketplace.json.", "LSP/monitor plugins depend on external binaries (e.g. `gopls`) being installed on each user's machine; the plugin does not bundle them.", "Components placed inside .claude-plugin/ are silently ignored — only plugin.json belongs there; all component dirs must be at the plugin root (symptom: plugin loads but skills/agents/hooks missing).", "If you set 'version' in plugin.json, pushing new commits does NOT deliver updates — you must bump the version; /plugin update reports 'already at the latest version' otherwise.", "For SECURITY, plugin-shipped agents cannot use hooks, mcpServers, or permissionMode frontmatter (silently unsupported).", "Project-scope @skills-dir plugins load only from .claude/skills/ of the directory you launch from — they do NOT walk up to repo root, so launching from a subdirectory misses a repo-root plugin.", "Paths traversing outside the plugin root (../shared-utils) break after install because external files aren't copied to the cache; share within a marketplace via symlinks instead.", "Symlinks outside the marketplace are skipped on cache copy (security); for --plugin-dir/local installs only symlinks within the plugin's own dir survive.", "${CLAUDE_PLUGIN_ROOT} changes on every plugin update and the old dir is cleaned up ~7 days later — never write persistent state there; use ${CLAUDE_PLUGIN_DATA}.", "After a mid-session plugin update, hooks/monitors/MCP/LSP keep using the OLD version path until /reload-plugins (and monitors need a full session restart).", "Disabling a plugin mid-session does NOT stop monitors already running; they only stop at session end.", "Project-scope plugins are more restricted than personal ones: their background monitors don't load at all, and their MCP/LSP servers require trust/approval gates.", "settings.json inside a plugin only honors the 'agent' and 'subagentStatusLine' keys — other settings there are ignored.", "Hook event names are case-sensitive (PostToolUse, not postToolUse); non-executable hook scripts silently fail to fire (chmod +x)."], "claims": ["A plugin marketplace is a catalog of plugins; using one is two steps: (1) add the marketplace (registers catalog, installs nothing), (2) install individual plugins from it.", "The official Anthropic marketplace `claude-plugins-official` is automatically available on startup. Browse via `/plugin` Discover tab or claude.com/plugins. Install with `/plugin install <name>@claude-plugins-official`.", "If a plugin is 'not found in any marketplace', the marketplace is missing/outdated: run `/plugin marketplace update claude-plugins-official` to refresh, or `/plugin marketplace add anthropics/claude-plugins-official` if never added.", "In-app submission forms add plugins to the community marketplace, NOT the official one. The official marketplace is curated by Anthropic at its discretion.", "Community marketplace lives at `anthropics/claude-plugins-community`; added manually via `/plugin marketplace add anthropics/claude-plugins-community`; install with `<plugin-name>@claude-community`. Plugins pass automated validation/safety screening and each is pinned to a specific commit SHA.", "Demo marketplace `claude-code-plugins` is added via `/plugin marketplace add anthropics/claude-code` (not auto-added).", "`/plugin` opens a 4-tab interface (cycle with Tab / Shift+Tab): Discover, Installed, Marketplaces, Errors.", "`/plugin marketplace add` accepts: GitHub `owner/repo`; full Git URLs (GitLab/Bitbucket/self-hosted, include `.git` suffix so it clones rather than treating URL as direct marketplace.json); local directory or path to marketplace.json; remote URL to a hosted marketplace.json.", "Append `#<ref>` to a Git URL to add a specific branch/tag, e.g. `/plugin marketplace add https://gitlab.com/company/plugins.git#v1.0.0`.", "A GitHub/Git marketplace repo must contain a `.claude-plugin/marketplace.json` file.", "Shortcuts: `/plugin market` for `/plugin marketplace`, and `rm` for `remove`.", "`/plugin install plugin-name@marketplace-name` installs to user scope by default.", "Installation scopes: User (all projects, yourself), Project (all repo collaborators, adds to `.claude/settings.json`), Local (yourself, this repo only, not shared), and Managed (installed by admins via managed settings, cannot be modified).", "CLI `--scope` targets a scope, e.g. `claude plugin install formatter@your-org --scope project`.", "After install/enable/disable during a session, run `/reload-plugins` to apply changes without restarting; it reports counts for plugins, skills, agents, hooks, MCP and LSP servers.", "Plugin skills are namespaced by plugin name, e.g. commit-commands provides `/commit-commands:commit`.", "Plugin management commands: `/plugin list` (with `--enabled`/`--disabled`), `/plugin disable name@marketplace`, `/plugin enable name@marketplace`, `/plugin uninstall name@marketplace`. `claude plugin details` shows the component inventory.", "Marketplace management: `/plugin marketplace list`, `/plugin marketplace update <name>`, `/plugin marketplace remove <name>`. Removing a marketplace uninstalls any plugins installed from it.", "Team admins enable auto marketplace install by adding `extraKnownMarketplaces` to project `.claude/settings.json` (e.g. source type `github`, repo `your-org/claude-plugins`); members are prompted to install only when they trust the repository folder.", "Admins can set `\"autoUpdate\": true` per `extraKnownMarketplaces` entry in managed settings to force org-marketplace auto-update without each user toggling.", "Official Anthropic marketplaces auto-update by default; third-party and local-dev marketplaces have auto-update disabled by default.", "`DISABLE_AUTOUPDATER` env var disables all auto-updates (Claude Code + plugins). Set `FORCE_AUTOUPDATE_PLUGINS=1` alongside it to keep plugin auto-updates while disabling Claude Code auto-updates.", "Organizations can restrict which marketplaces users may add via managed marketplace restrictions; plugins/marketplaces run arbitrary code with user privileges.", "Managed setting `pluginSuggestionMarketplaces` (min-version 2.1.154): when an admin allowlists a marketplace, directory-relevant plugins are pinned atop Discover with a 'suggested for this directory' label.", "Plugin detail pane shows a 'Context cost' token estimate (v2.1.143+), 'Last updated' date (v2.1.144+), and a 'Will install' inventory of commands/agents/skills/hooks/MCP/LSP servers (v2.1.145+).", "Code intelligence plugins (e.g. `pyright-lsp`, `typescript-lsp`, `rust-analyzer-lsp`, `gopls-lsp`) enable the built-in LSP tool, giving auto-diagnostics after each edit and code navigation; each requires its language-server binary in $PATH.", "`/reload-plugins` has a token cost next request; a plugin providing MCP servers whose tools aren't deferred by tool search invalidates the prompt cache (next request re-reads whole conversation). Min-version 2.1.163 shows a warning and refuses; pass `--force` to apply anyway.", "Fix for plugin skills not appearing: `rm -rf ~/.claude/plugins/cache`, restart Claude Code, reinstall the plugin.", "A plugin declares dependencies in the `dependencies` array of its `.claude-plugin/plugin.json`. Each entry is either a bare plugin-name string or an object `{ \"name\": ..., \"version\": ..., \"marketplace\": ... }`.", "By default a plugin dependency tracks the latest available version; an upstream release can change the dependency under your plugin without warning unless you set a version constraint.", "Dependency version constraints require Claude Code v2.1.110 or later.", "The `version` field accepts any Node `semver` range: caret (`^2.0`), tilde (`~2.1.0`), hyphen, comparator (`>=1.4`), and exact (`=2.1.0`). The dependency is fetched at the highest tagged version satisfying the range.", "Pre-release versions (e.g. `2.0.0-beta.1`) are excluded unless the range opts in with a pre-release suffix like `^2.0.0-0`.", "The `name` field of a dependency resolves within the same marketplace as the declaring plugin by default; `name` is required.", "Cross-marketplace dependencies are blocked by default. To allow, the ROOT marketplace (the one hosting the plugin being installed) must list the target marketplace name in `allowCrossMarketplaceDependenciesOn` in its `.claude-plugin/marketplace.json`. Trust does not chain through intermediate marketplaces — only the root marketplace's allowlist is consulted.", "If `allowCrossMarketplaceDependenciesOn` is missing or omits the target marketplace, install fails with a `cross-marketplace` error. Users can still install the dependency manually first to satisfy the constraint without changing the allowlist.", "Version constraints resolve against git tags on the marketplace repo. Each release must be tagged `{plugin-name}--v{version}` where `{version}` matches the `version` in that commit's `plugin.json`. The `--v` separator is parsed as a prefix match on the full plugin name (so hyphenated names work).", "`claude plugin tag --push` derives the tag from the manifest + marketplace entry, validates plugin contents, checks `plugin.json` and the marketplace entry agree on version, requires a clean working tree under the plugin directory, and refuses if the tag already exists. `--dry-run` previews. `git tag secrets-vault--v2.1.0` is equivalent if you keep manifest and entry in sync.", "Installing a plugin with dependencies auto-resolves and installs them; the install output lists which dependencies were added. Dependencies from a marketplace you have not added are left unresolved.", "A missing dependency is reinstalled by `/reload-plugins`, by background plugin auto-update, by re-running `claude plugin install` on the dependent, or by `claude plugin marketplace add` — provided the dependency's marketplace is configured.", "When multiple installed plugins constrain the same dependency, Claude Code intersects their ranges and resolves to the highest version satisfying all. `^2.0` + `>=2.1` → highest 2.x at/above 2.1.0 (both load); `~2.1` + `~3.0` → install of the second fails with `range-conflict`; `=2.1.0` pins and makes auto-update skip newer versions while that plugin is installed.", "Auto-update fetches a constrained dependency at the highest git tag satisfying every installed plugin's range, not the marketplace latest. If no tag satisfies all ranges the update is skipped, and the skip appears in `/doctor` and the `/plugin` Errors tab, naming the constraining plugin.", "Uninstalling the last plugin that constrains a dependency releases the hold; the dependency resumes tracking its marketplace entry on the next update.", "Enabling a plugin also enables its (transitive) dependencies at the same scope; disabling is blocked if another enabled plugin still needs it. Both behaviors require Claude Code v2.1.143+. Earlier versions enable/disable only the named plugin and surface a `dependency-unsatisfied` error on next load.", "Enabling writes an explicit `true` for each dependency even if the dependency's manifest sets `defaultEnabled: false`. The same applies at install: a dependency pulled in to satisfy an active plugin installs with `true` regardless of its own default.", "Enable fails if: a dependency is not installed (prints the `claude plugin install` command for each), a dependency is blocked by org plugin policy (names it), or a dependency is set to `false` at a higher-precedence scope than the target (fix: enable at that scope or pass `--scope` to write there).", "Disabling a plugin that others depend on fails with an error naming the dependents and a chained command, e.g. `claude plugin disable deploy-kit@acme-tools && claude plugin disable secrets-vault@acme-tools`, that disables them in the correct order.", "`claude plugin prune` lists and removes auto-installed dependencies no longer required by any installed plugin (confirmation prompt). Requires Claude Code v2.1.121+. Defaults to user scope; `--scope project|local` targets another scope; `--dry-run` previews; `-y` skips confirmation. When stdin/stdout is not a terminal it lists orphans and exits without removing unless `-y` is passed.", "`claude plugin uninstall <plugin> --prune` removes the plugin then scans for and removes now-orphaned auto-installed dependencies. Plugins you installed yourself are never pruned — only ones auto-installed via another plugin's `dependencies` array.", "Dependency errors disable the affected plugin until resolved and surface in `claude plugin list`, the `/plugin` interface, and `/doctor`. Programmatic check: `claude plugin list --json` and read the `errors` field on each plugin.", "Error types and fixes: `dependency-unsatisfied` (dep not installed or disabled), `range-conflict` (ranges cannot combine / invalid semver / too-complex intersection), `dependency-version-unsatisfied` (installed version outside declared range; fix via `claude plugin install <dependency>@<marketplace>`), `no-matching-tag` (no `{name}--v*` tag satisfies range).", "For `npm` marketplace sources, the version constraint does NOT control which version is fetched (tag-based resolution is git-only). The constraint is still checked at load time and the dependent is disabled with `dependency-version-unsatisfied` if the installed version does not satisfy it.", "The resolved tag's semver is recorded separately from `plugin.json`'s `version`, so constraint checks use the actually-fetched tag even if that commit's `plugin.json` has a stale value. A tag-resolved install's cache dir name includes a 12-char commit-SHA suffix, so force-moving a tag yields a fresh cache dir instead of reusing stale content.", "Claude Code sets the CLAUDECODE environment variable to 1 for every command it runs through the Bash and PowerShell tools, and for hook commands.", "From v2.1.172 Claude Code also sets CLAUDE_CODE_CHILD_SESSION to 1 in subprocesses it spawns (tool calls, hook commands, status line commands).", "CLAUDECODE is also set in tmux sessions, stdio MCP server subprocesses Claude Code starts, and IDE-extension integrated terminals — so a human may see it set even when running a CLI directly.", "CLAUDE_CODE_CHILD_SESSION is set only in subprocesses Claude Code itself spawns, so it does not normally reach a human terminal — except a long-lived process (e.g. a tmux server) started inside a session captures the variable, so later shells launched from it still see it set.", "A CLI emits an install hint by writing a self-closing tag on its own line to stderr: <claude-code-hint v=\"1\" type=\"plugin\" value=\"name@marketplace\" />. Required attributes: v (only 1), type (only plugin), value (name@marketplace form).", "Claude Code scans both stdout and stderr for hint lines; stderr is recommended only to keep the tag out of shell pipelines, but stdout also works.", "Hint lines are always stripped from command output before it reaches the model, even when version/type is unrecognized, so the marker is never counted toward token usage.", "The hint tag must occupy its own line (leading/trailing whitespace allowed); a tag embedded mid-line (e.g. inside a log statement) is ignored.", "Hints are only acted on if value references a plugin in an Anthropic-controlled official marketplace such as claude-plugins-official; hints pointing to other marketplaces are silently dropped.", "Claude Code never installs a plugin automatically; the user always confirms. Selecting Yes installs the plugin to user scope.", "Install prompt frequency is bounded: once per plugin (recorded and never prompted again regardless of answer) and at most once per Claude Code session across all CLIs on the machine.", "If the user does not respond to the install prompt within 30 seconds, it dismisses as No.", "The in-app plugin submission forms add plugins to the community marketplace, which the hint protocol does NOT check; only the curated claude-plugins-official marketplace triggers hints.", "A marketplace is defined by a `.claude-plugin/marketplace.json` file at the repository root. Required fields: `name` (kebab-case string, public-facing, no spaces), `owner` (object with required `name`, optional `email`), and `plugins` (array).", "Each plugin entry in `plugins` requires `name` (kebab-case) and `source`. `source` is a string (relative path starting with `./`) or an object with a `source` type field.", "Plugin source types: relative path string (`\"./my-plugin\"`, must start with `./`, resolved relative to marketplace root not `.claude-plugin/`); `github` (object: `repo` required `owner/repo`, optional `ref`, `sha`); `url` (git URL: `url`, optional `ref`, `sha`); `git-subdir` (`url`, `path` required, optional `ref`, `sha`; uses sparse partial clone for monorepos); `npm` (`package` required, optional `version`, `registry`).", "When both `ref` and `sha` are set on a git source, `sha` is the effective pin; install succeeds even if the branch/tag is deleted upstream as long as the commit is reachable (except servers like AWS CodeCommit that cannot fetch by SHA).", "Marketplace source (where marketplace.json is fetched, set via `/plugin marketplace add` or `extraKnownMarketplaces`) supports `ref` but NOT `sha`. Plugin source (inside marketplace.json) supports both `ref` and `sha`. They point to independently-pinned repos.", "Optional marketplace-level fields: `$schema` (ignored at load), `description`, `version`, `metadata.pluginRoot` (base dir prepended to relative plugin sources), `allowCrossMarketplaceDependenciesOn` (array; cross-marketplace deps not listed here are blocked at install). `description`/`version` also accepted under `metadata` for backward compat.", "Add a marketplace: `/plugin marketplace add <source>` or CLI `claude plugin marketplace add <source> [options]`. Source can be GitHub `owner/repo`, git URL, remote URL to marketplace.json, or local path. Pin with `@ref` for GitHub shorthand or `#ref` for git URL.", "`claude plugin marketplace add` options: `--scope <user|project|local>` (default `user`); `--sparse <paths...>` (limit checkout to dirs for monorepos). Use `--scope project` to share via `.claude/settings.json`.", "Install a plugin: `/plugin install <plugin-name>@<marketplace-name>`. Plugin skills are namespaced and invoked as `/<plugin-name>:<skill-name>`.", "CLI marketplace subcommands: `claude plugin marketplace add|list|remove|update`. `list` supports `--json`. `remove` (alias `rm`) takes the marketplace `name` (from marketplace.json, not the add source) and optional `--scope`. `update [name]` refreshes from sources; updates all if name omitted.", "Team auto-prompt setup: add to project `.claude/settings.json` an `extraKnownMarketplaces` object keyed by marketplace name with a `source`; team members are prompted to install when they trust the folder. `enabledPlugins` maps `plugin@marketplace` to boolean to enable by default.", "Marketplace state is stored once per user in `~/.claude/plugins/known_marketplaces.json`, not per-project. Worktrees share the same marketplace location (relative local/file sources resolve against the main checkout).", "Org governance: `strictKnownMarketplaces` in managed settings (`managed-settings.json`) restricts which marketplaces users may add. Undefined = no restriction; empty array `[]` = total lockdown; list of sources = allowlist with exact matching. Cannot be overridden by user or project config.", "`strictKnownMarketplaces` allowlist entries support source types `github` (repo, optional ref/path must match), `url` (full URL exact match), `hostPattern` (regex on host, recommended for GHES/self-hosted GitLab), and `pathPattern` (regex on filesystem path). Use `pathPattern: \".*\"` to allow any path.", "`strictKnownMarketplaces` restricts what users can ADD but does not register marketplaces; pair with `extraKnownMarketplaces` in the same managed-settings.json to make allowed marketplaces available automatically. Enforcement runs before any network/filesystem op, on add and on install/update/refresh/auto-update; pre-existing non-matching marketplaces are refused. Same enforcement applies to `blockedMarketplaces`.", "`strictKnownMarketplaces` exact matching does NOT normalize URLs: trailing slash, `.git` suffix, `ssh://` vs `https://` are different values. Prefer `hostPattern` when a marketplace is cloneable via multiple URL forms.", "Version resolution precedence: (1) `version` in plugin's `plugin.json`, (2) `version` in marketplace entry, (3) git commit SHA of source. If resolved version matches what user has, update/auto-update skip the plugin. For git sources you can omit `version` so every commit is a new version.", "`defaultEnabled` (boolean, v2.1.154+) in marketplace entry controls whether plugin is enabled after install (default true); takes precedence over the same field in plugin.json. `displayName` (v2.1.143+) is UI-only, not used for namespacing/lookup. `relevance` (v2.1.152+) suggests plugins but only for marketplaces an admin allowlists in managed settings.", "`strict` field (default true): when true, `plugin.json` is authority and marketplace entry supplements/merges; when false, marketplace entry is the entire definition and a plugin.json declaring components is a conflict that fails to load (lets marketplace operator curate without plugin.json).", "Installed plugins are copied to versioned cache `~/.claude/plugins/cache/<marketplace>/<plugin>/<version>/`. Plugins cannot reference files outside their directory (e.g. `../shared-utils`) since those aren't copied; use symlinks for shared files. Use `${CLAUDE_PLUGIN_ROOT}` in hooks/MCP configs and `${CLAUDE_PLUGIN_DATA}` for data surviving updates.", "Container/CI pre-population: set `CLAUDE_CODE_PLUGIN_SEED_DIR` to a directory mirroring `~/.claude/plugins` (known_marketplaces.json, marketplaces/<name>/, cache/<mp>/<plugin>/<version>/). Layer multiple with `:` (Unix) or `;` (Windows), first match wins. Build by running Claude once with `CLAUDE_CODE_PLUGIN_CACHE_DIR` set to the target. Seed is read-only, auto-updates disabled, seed entries override user config each startup; works with `-p` non-interactive mode.", "Validate marketplace: `claude plugin validate .` or `/plugin validate .`. Pointed at a marketplace dir, it checks marketplace.json only (schema, duplicate names, source path traversal `..`, version mismatches vs plugin.json). Point at a plugin dir to validate its plugin.json plus skill/agent/command/hook frontmatter.", "Refresh local copy of marketplace: `/plugin marketplace update`. Removing a marketplace from its last scope uninstalls plugins from it; use `update` instead to refresh without losing plugins.", "Private repo auto-update auth via env tokens: GitHub `GITHUB_TOKEN`/`GH_TOKEN`, GitLab `GITLAB_TOKEN`/`GL_TOKEN`, Bitbucket `BITBUCKET_TOKEN`. Manual install/update uses existing git credential helpers and ssh-agent. Background auto-updates at startup do NOT use credential helpers (interactive prompts would block startup), so env tokens are required for private-marketplace auto-update.", "Git operation timeout default is 120s; raise via `CLAUDE_CODE_PLUGIN_GIT_TIMEOUT_MS` (milliseconds). Offline: `CLAUDE_CODE_PLUGIN_KEEP_MARKETPLACE_ON_FAILURE=1` keeps stale cache on `git pull` failure instead of wiping and re-cloning.", "Reserved marketplace names (cannot be used by third parties): claude-code-marketplace, claude-code-plugins, claude-plugins-official, claude-plugins-community, claude-community, anthropic-marketplace, anthropic-plugins, agent-skills, anthropic-agent-skills, knowledge-work-plugins, life-sciences, claude-for-legal, claude-for-financial-services, financial-services-plugins. Impersonating names (e.g. official-claude-plugins) are also blocked.", "Each user can register only one marketplace per name; adding a second with the same name replaces the first. Publish multiple plugins under one name by listing them all in a single marketplace.json.", "Release channels: create two marketplaces pointing to different refs/SHAs of the same plugin repo (e.g. stable-tools at ref `stable`, latest-tools at ref `latest`) and assign each to a different user group via managed settings `extraKnownMarketplaces`. Each channel must resolve to a DIFFERENT version string or Claude treats them as identical and skips the update.", "A plugin entry in marketplace.json can carry a `relevance` object with a `topic` (string) and a `signals` object; at least one signal is required for the plugin to be suggestible.", "Relevance suggestions are opt-in: no marketplace's `relevance` declarations produce suggestions until an administrator allowlists the marketplace in managed settings, including the official Anthropic marketplace.", "Enable suggestions by adding the marketplace name to `pluginSuggestionMarketplaces` in managed-settings.json.", "For any marketplace other than the official Anthropic one, you must also declare its source in the same managed settings, either via `extraKnownMarketplaces` or `strictKnownMarketplaces`; the allowlisted name is ignored if the registered marketplace came from a different source (prevents name-squatting).", "The official marketplace `claude-plugins-official` is exempt from the source-declaration requirement; allowlisting the name alone in `pluginSuggestionMarketplaces` suffices.", "Signal matching happens locally on the user's machine; it adds no network traffic and does not report which signals matched or their values to Anthropic or the marketplace operator.", "Claude Code never auto-installs a plugin; the user always confirms via `/plugin install <name>@<marketplace>`.", "Supported signals under `relevance.signals`: `cwd` (globs vs working dir), `cli` (command names run), `hosts` (hostnames in URLs in Bash commands), `filesRead` (globs vs files read), `manifestDeps` (regex file+pattern against package manifests read).", "`cwd` is the only signal that can match at session start (before the first turn); `cli`, `hosts`, `filesRead`, and `manifestDeps` require session history so they only match on the spinner tip and Discover tab.", "`cwd` globs are matched as absolute path and (in a git repo) relative to repo root; forward-slash normalized, case-insensitive; every pattern matches the dir itself and everything under it, so `infra`, `infra/`, and `infra/**` are identical. Max 10 patterns of 256 chars.", "`cli` records one command name per shell tool invocation: the first token after leading env-var assignments and `sudo`. Compound commands contribute only the leading command, so `cd infra && terraform plan` records `cd`, not `terraform`. Exact match. Max 10 entries of 64 chars.", "`hosts` is the bare lowercase hostname only (no scheme, port, or path); exact case-insensitive match; max 20 entries of 128 chars. The validator rejects a `signals.hosts` entry that includes a scheme, port, or path.", "`filesRead` globs are forward-slash normalized, case-insensitive; max 10 patterns of 256 chars. Recorded file state also includes files Claude wrote/edited and auto-loaded CLAUDE.md memory files.", "`manifestDeps` entries are `{\"file\": regex, \"pattern\": regex}`; `file` is matched against the manifest path (typically absolute, NOT separator-normalized so Windows uses backslashes) and must be end-anchored (e.g. `[/\\\\]package\\.json$`); `pattern` matched against file contents. `file` is case-insensitive, `pattern` is case-sensitive. Manifest files larger than 512 KB are skipped. Both are RegExp source strings of at most 256 chars. Max 10 entries.", "Three surfaces show suggestions: spinner tip (\"Working with <topic>? Install the <plugin> plugin\"), session-start one-line notification (`plugin suggestion: <name>@<marketplace> · /plugin`, cwd-match only), and the `/plugin` Discover tab pin with annotation (e.g. \"suggested for this directory\").", "Spinner tip and session-start notification are part of the spinner-tips system and are disabled when `spinnerTipsEnabled` is `false`, or when a custom `spinnerTipsOverride` is set with `excludeDefault`. The Discover-tab pin is independent of tip settings.", "A given plugin's suggestion appears at most once every three sessions across spinner tip and session-start notification combined; neither repeats once installed; the session-start notification additionally stops after being shown twice. The Discover tab pins a plugin once, then lists normally.", "`topic` defaults to the plugin name with each hyphen segment capitalized; max 64 characters; the session-start notification does not use `topic`.", "Unknown fields under `relevance` and `relevance.signals` are ignored at load time (forward-compat for older clients); `claude plugin validate ./my-marketplace` surfaces them as warnings and rejects a non-object `relevance`.", "Feature requires Claude Code v2.1.152+; older clients ignore `relevance`. Session-start `cwd` notification needs v2.1.153+; Discover-tab pin needs v2.1.154+.", "A plugin is a self-contained directory containing skills, agents, hooks, MCP servers, LSP servers, and/or background monitors, optionally with a `.claude-plugin/plugin.json` manifest.", "The plugin manifest lives at `<plugin>/.claude-plugin/plugin.json` and defines `name` (required, also the skill namespace), `description`, `version` (optional), `author` (optional), plus `homepage`/`repository`/`license`.", "Plugin skills are ALWAYS namespaced as `/plugin-name:skill-name` to prevent conflicts; the namespace prefix is the manifest `name` field. Standalone `.claude/` skills use bare names like `/hello`.", "If `version` is set in plugin.json, users only receive updates when you bump it. If omitted and distributed via git, the commit SHA is used and every commit counts as a new version.", "Plugin root directories: `skills/` (each `<name>/SKILL.md`), `commands/` (flat Markdown, legacy — use skills/ for new plugins), `agents/`, `hooks/` (with `hooks.json`), `.mcp.json` (MCP servers), `.lsp.json` (LSP servers), `monitors/monitors.json` (background monitors), `bin/` (executables added to Bash PATH while enabled), `settings.json` (default settings when enabled), and `.claude-plugin/` (holds only plugin.json).", "Only `plugin.json` goes inside `.claude-plugin/`. Putting `commands/`, `agents/`, `skills/`, or `hooks/` inside `.claude-plugin/` is a documented common mistake — all component dirs must be at plugin root.", "A single-skill plugin can place `SKILL.md` directly at the plugin root (no `skills/` dir); the frontmatter `name` field becomes the invocation name.", "`claude --plugin-dir ./my-plugin` loads a plugin for the session without installing. The flag can be repeated to load multiple plugins. It also accepts a `.zip` archive (requires Claude Code v2.1.128+).", "`claude --plugin-url https://.../my-plugin.zip` fetches and loads a zipped plugin for that session only; repeat the flag or pass space-separated quoted URLs for multiple. If fetch fails or archive is invalid, Claude Code reports a load error and starts without it.", "`/reload-plugins` reloads plugins, skills, agents, hooks, plugin MCP servers, and plugin LSP servers without restarting — used to pick up edits during development.", "`claude plugin init my-tool` scaffolds a plugin at `~/.claude/skills/my-tool/` with a `.claude-plugin/plugin.json` and starter `SKILL.md`; it auto-loads next session as `my-tool@skills-dir` with no marketplace or install step.", "When a `--plugin-dir` plugin has the same name as an installed marketplace plugin, the local copy takes precedence for that session — EXCEPT plugins that managed settings force-enable or force-disable, which `--plugin-dir` cannot override.", "Project and user `.claude/agents/` definitions override same-named plugin agents; the plugin agent only takes effect once the originals are removed.", "Plugin `settings.json` currently supports only `agent` and `subagentStatusLine` keys; `agent` activates one of the plugin's custom agents as the main thread (its system prompt, tool restrictions, model). Unknown keys are silently ignored. `settings.json` takes priority over `settings` declared in `plugin.json`.", "Hooks in a plugin go in `hooks/hooks.json`; the `hooks` object format is identical to `.claude/settings.json`/`settings.local.json`, so you can copy it directly. Hook commands receive hook input as JSON on stdin (use `jq` to extract e.g. `.tool_input.file_path`).", "`monitors/monitors.json` holds an array of background monitors; each `command` runs automatically when the plugin is active and every stdout line is delivered to Claude as a notification.", "`.lsp.json` configures LSP servers (command, args, extensionToLanguage map); users must have the language-server binary installed. Pre-built LSP plugins exist on the official marketplace for TypeScript, Python, Rust.", "`bin/` executables are added to the Bash tool's PATH while the plugin is enabled.", "Anthropic maintains two public marketplaces: `claude-plugins-official` (curated, auto-registered on first interactive launch; add explicitly in non-interactive scripts with `claude plugin marketplace add anthropics/claude-plugins-official`) and `claude-community` (public submissions after review, added via `/plugin marketplace add anthropics/claude-plugins-community`, install as `@claude-community`).", "`claude plugin validate` runs locally and is the same check the community-marketplace review pipeline runs. Community submission requires a Team/Enterprise org with directory management access (Owners have it by default); individuals use the Console form at platform.claude.com/plugins/submit.", "Approved community plugins are pinned to a specific commit SHA in `anthropics/claude-plugins-community`; CI bumps the pin as you push. The catalog syncs nightly, so approval-to-availability has a delay.", "The claude.ai plugin submission form requires a Team or Enterprise organization and directory management access; individual authors without such an org must use the Console form.", "A plugin is a directory whose components are: skills, agents, hooks, MCP servers, LSP servers, monitors, themes, output-styles, and bin/ executables.", "Plugin manifest lives at .claude-plugin/plugin.json. The manifest is optional; if omitted, components are auto-discovered in default locations and the plugin name is derived from the directory name.", "name is the only required manifest field (kebab-case, no spaces). It namespaces components: agent 'agent-creator' in plugin 'plugin-dev' appears as 'plugin-dev:agent-creator'.", "WARNING: All component directories (commands/, agents/, skills/, output-styles/, themes/, monitors/, hooks/) must be at the plugin ROOT, not inside .claude-plugin/. Only plugin.json goes in .claude-plugin/.", "Default component locations: skills/ (<name>/SKILL.md), commands/ (flat .md), agents/ (.md), output-styles/, themes/, hooks/hooks.json, .mcp.json, .lsp.json, monitors/monitors.json, bin/ (added to Bash PATH), settings.json (default plugin settings, only 'agent' and 'subagentStatusLine' keys supported).", "Installation scopes: user (~/.claude/settings.json, default), project (.claude/settings.json, team-shared via VCS), local (.claude/settings.local.json, gitignored), managed (managed settings, read-only/update-only). Written to enabledPlugins in the scope's settings file.", "claude plugin install <plugin>@<marketplace> --scope project writes to enabledPlugins in .claude/settings.json, making the plugin available to everyone who clones the repo.", "Version resolution order: (1) version in plugin.json, (2) version in marketplace.json entry, (3) git commit SHA for github/url/git-subdir/relative-path git sources, (4) 'unknown' for npm sources or non-git local dirs. plugin.json wins over marketplace entry.", "If version is SET in plugin.json, you MUST bump it for users to get updates; pushing new commits alone does nothing (/plugin update reports 'already at the latest version'). Leave version UNSET to update on every commit (commit-SHA versioning) — best for internal/team plugins under active development.", "defaultEnabled:false (requires v2.1.154+) ships a plugin installed-but-disabled; user enables via 'claude plugin enable' or /plugin. Precedence: user's enabledPlugins setting > dependency requirement > defaultEnabled. Earlier versions ignore the field and enable on install.", "Plugin agents support frontmatter: name, description, model, effort, maxTurns, tools, disallowedTools, skills, memory, background, isolation (only valid value 'worktree'). For SECURITY, hooks, mcpServers, and permissionMode are NOT supported for plugin-shipped agents.", "userConfig manifest field prompts user for values at enable time (types: string/number/boolean/directory/file). sensitive:true masks input and stores in system keychain (or ~/.claude/.credentials.json), NOT settings.json. Substituted as ${user_config.KEY}; exported as CLAUDE_PLUGIN_OPTION_<KEY> env vars. Non-sensitive values stored under pluginConfigs[<plugin-id>].options in settings.json.", "Keychain storage (sensitive userConfig + OAuth tokens) has ~2KB total limit; keep sensitive values small.", "Environment vars: ${CLAUDE_PLUGIN_ROOT} (absolute install dir, CHANGES on update), ${CLAUDE_PLUGIN_DATA} (persistent state dir surviving updates, at ~/.claude/plugins/data/{id}/), ${CLAUDE_PROJECT_DIR} (project root). All substituted in skill/agent content, hook/monitor commands, MCP/LSP configs; also exported to subprocesses.", "Marketplace plugins are COPIED to local plugin cache ~/.claude/plugins/cache (not used in-place). Each version is a separate directory; old versions marked orphaned and removed 7 days after update/uninstall (grace period for concurrent sessions). Glob/Grep skip orphaned dirs.", "Installed plugins CANNOT reference files outside their directory; paths like ../shared-utils fail post-install because external files aren't copied to cache. All component paths must be relative and start with ./.", "Symlink handling on cache copy: within plugin dir = preserved as relative symlink; elsewhere in same marketplace = dereferenced (content copied); outside marketplace = SKIPPED for security. For --plugin-dir/local installs, only symlinks resolving within the plugin's own dir are preserved.", "Path field behavior: commands/agents/outputStyles/experimental.themes/experimental.monitors REPLACE the default directory (list it explicitly to keep it). skills ADDS to default skills/ scan. hooks/mcpServers/lspServers have own merge rules.", "Skills-directory plugins: any folder under a skills dir with .claude-plugin/plugin.json loads as <name>@skills-dir next session, no marketplace/install, discovered in-place (not copied). ~/.claude/skills/ = personal (every project); <cwd>/.claude/skills/ = project scope, loads only after workspace trust dialog.", "Project-scope @skills-dir plugins load ONLY from .claude/skills/ of the launch directory; they do NOT walk up to repo root like plain skills. Launch from repo root or run /reload-plugins after cd.", "Project-scope plugin code restrictions: MCP servers go through per-server approval (like project .mcp.json), LSP servers start only after workspace trust, background monitors do NOT load. Personal-scope plugins have none of these restrictions.", "Hook types: command (shell), http (POST event JSON to URL), mcp_tool (call MCP server tool), prompt (LLM eval with $ARGUMENTS), agent (agentic verifier with tools).", "Plugin monitors require v2.1.105+; run only in interactive CLI sessions, unsandboxed at hooks trust level, skipped where Monitor tool unavailable. Each delivers stdout lines to Claude as notifications. Disabling plugin mid-session does NOT stop running monitors; they stop at session end.", "plugin init <name> scaffolds at ~/.claude/skills/<name>/, loads as <name>@skills-dir. Flags: --description, --author (default git config user.name), --author-email, --with <components...> (skills/agents/hooks/mcp/lsp/output-style/channel), -f/--force. Alias: new.", "claude plugin validate ./plugin checks manifest/frontmatter/hooks.json. Unrecognized top-level fields are WARNINGS (plugin still loads); wrong-type fields are ERRORS. --strict treats warnings as errors (use in CI).", "claude plugin uninstall: --keep-data preserves persistent data dir (deleted by default from last scope), --prune removes orphaned auto-installed deps, -y/--yes skips prompt (required for non-TTY). Aliases remove/rm.", "claude plugin prune (v2.1.121+, alias autoremove) removes auto-installed dependency plugins no longer required; never touches directly-installed plugins. --dry-run lists without removing.", "claude plugin enable/disable: enable pulls in declared dependencies transitively at same scope (fails if a dependency not installed); disable fails when another enabled plugin depends on the target (error gives a chained command to disable dependents first).", "claude plugin details <name> shows component inventory + projected token cost: Always-on (tokens added to every session by listing text regardless of firing) and On-invoke (per-component, paid each fire). Always-on computed via count_tokens API for active model.", "claude plugin list --json; --available (requires --json) includes marketplace plugins. Interactive /plugin list accepts --enabled/--disabled; alias ls.", "dependencies manifest field: array of plugin names or {name, version} with semver constraints e.g. {\"name\":\"secrets-vault\",\"version\":\"~2.1.0\"}. claude plugin tag creates a release git tag (--push, --dry-run, -f/--force) for version resolution.", "displayName (v2.1.143+) is human-readable UI name (may have spaces/casing), falls back to name, NOT used for namespacing/lookup. $schema field is ignored at load time (editor autocomplete only).", "Single-skill plugin: SKILL.md at plugin root with no skills/ dir and no skills manifest field auto-loads as one skill (v2.1.142+). Set frontmatter name to control invocation name, else it falls back to install dir name (a version string that changes every update for marketplace plugins).", "A CLAUDE.md at the plugin root is NOT loaded as project context. Plugins contribute context via skills/agents/hooks only; ship instructions as a skill.", "Admins can block @skills-dir plugin source via strictKnownMarketplaces or by adding {\"source\":\"skills-dir\"} to blockedMarketplaces in managed settings; when blocked, plugin init fails before writing.", "When a plugin updates mid-session, hooks/monitors/MCP/LSP keep using the previous version's path; /reload-plugins switches hooks/MCP/LSP to the new path but monitors require a session restart."]}, "Subagents & agent teams": {"pages": ["agent-teams", "agent-view", "agents", "sub-agents"], "bestPractices": ["Start with 3-5 teammates for most workflows; scale up only when work genuinely parallelizes. Three focused teammates often outperform five scattered ones.", "Size for ~5-6 tasks per teammate to keep everyone productive without excessive context switching (e.g. 15 independent tasks → 3 teammates).", "Size each task as a self-contained unit with a clear deliverable (a function, a test file, a review) — too small wastes coordination overhead, too large risks long unchecked work.", "Avoid file conflicts: assign each teammate a distinct set of files; two teammates editing the same file causes overwrites.", "Put task-specific detail in the spawn prompt (teammates don't inherit lead conversation history) — name files, scope, tech context, and required output format (e.g. severity ratings).", "Use CLAUDE.md in the working directory to give all teammates project-specific guidance — it is read normally by every teammate.", "For parallel code review, give each teammate a distinct, non-overlapping lens (security / performance / test coverage) so coverage doesn't collapse to one issue type.", "For unclear bugs, spawn adversarial investigators told to disprove each other's hypotheses (scientific-debate structure) to beat anchoring on the first plausible cause.", "Pre-approve common operations in permission settings before spawning teammates, since teammate permission prompts bubble up to the lead.", "Use agent teams only for parallelizable work (research, review, independent modules, cross-layer changes); for sequential tasks, same-file edits, or heavy dependencies use a single session or subagents.", "If the lead starts doing work itself, instruct it to 'Wait for your teammates to complete their tasks before proceeding'.", "Beginners should start with non-code tasks (PR review, library research, bug investigation) to see parallel value before parallel implementation.", "Define reusable teammate roles as subagent definitions (security-reviewer, test-runner) and reference them by name when spawning, instead of hand-authoring team config.", "Use TeammateIdle/TaskCreated/TaskCompleted hooks (exit code 2) to enforce quality gates that keep teammates working or block premature task completion.", "Monitor and steer actively — redirect failing approaches and synthesize findings as they arrive; don't let a team run unattended for long.", "Use agent view for several independent tasks Claude can run unattended (e.g. a bug fix, a PR review, a flaky-test investigation as three rows); check back only when a row needs you or shows a result. Pick up results at the PR column — merge when the PR number turns green.", "Use `claude agents` as your primary entry point: dispatch tasks, press Enter/→ to attach for the full conversation, press ← on an empty prompt to detach back to the table.", "Cap parallel dispatch deliberately — each session consumes subscription quota independently, so N parallel agents burn quota ~N times faster.", "Pin long-lived or latency-sensitive sessions with `Ctrl+T` so the supervisor doesn't stop their process after ~1 hour idle (avoids the slow-to-respond restart on reattach).", "Commit or push a session's work before deleting it in agent view — deletion removes the Claude-created worktree and its uncommitted changes. Prefer `claude rm` (keeps dirty worktrees) when unsure.", "Package a recurring multi-agent task as a skill so you can dispatch it from the agent view input by typing `/skill` instead of retyping the prompt.", "Pass shared config once at the agent-view level (`claude agents --settings ./ci-settings.json --add-dir ../shared-lib --mcp-config ... --plugin-dir ...`) since these flags propagate to every dispatched session; repeat each flag per value.", "Scope agent view to a single project with `claude agents --cwd <path>` when you have sessions across many repos (v2.1.141+).", "For scripting/automation around background sessions, use `claude agents --json` (add `--all`) and the `claude attach/logs/stop/respawn/rm` commands instead of the TUI.", "Set the dispatch default model/mode/effort for a whole agent-view session with `claude agents --permission-mode plan --model opus --effort high`; override per-session with `claude --bg --model ...` or `/model` `s` while attached.", "Recover a stalled supervisor without losing work: `claude daemon stop --any --keep-workers`, then reopen agent view so a fresh supervisor reconnects.", "To disable background agents fleet-wide (governance), enforce `disableAgentView: true` via managed settings or set `CLAUDE_CODE_DISABLE_AGENT_VIEW`.", "Use a subagent when a side task would flood the main conversation with search results, logs, or file contents you won't reference again — it runs in its own context and returns only a summary.", "Use agent view (`claude agents`) when you have several independent tasks: hand them off, check status at a glance, step in only when one needs you.", "Use dynamic workflows (not a handful of subagents) when a job outgrows manual coordination or needs cross-verification: codebase-wide audits, large migrations (e.g. 500 files), cross-checked research, or multi-angle planning.", "Isolate parallel work with worktrees whenever tasks touch the same files; for agent teams (which don't use worktrees) partition the work so each teammate owns a distinct file set.", "Use a forked subagent when the side task needs your full conversation context rather than a fresh start.", "Choose the approach by: who coordinates (Claude in one conversation = subagents; you = agent view; Claude supervising a group = agent teams; a script = workflows) and whether workers must talk to each other.", "Budget tokens/rate limits before fanning out — parallel agents multiply usage.", "Check project subagents (`.claude/agents/`) into version control so the whole team shares and improves them; this is the recommended way to distribute codebase-specific subagents.", "Use a subagent to isolate high-volume operations (test runs, doc fetches, log processing) so verbose output stays in the subagent's context and only a summary returns to main — e.g. 'run the test suite and report only failing tests with their error messages'.", "Limit each subagent's tool access to the minimum needed (e.g. no Edit/Write for reviewers) for security and focus; use `disallowedTools: Write, Edit` to inherit everything except writes.", "Write detailed `description` fields and include phrases like 'use proactively' to encourage Claude to auto-delegate at the right time.", "Design focused single-task subagents rather than broad ones; Claude routes by description, so overlap causes mis-delegation.", "Route cheap/verbose work to Haiku via `model: haiku` to control cost; use `model: sonnet`/`opus` only where analysis quality matters.", "To keep an MCP server's tool descriptions out of the main conversation context, define it inline in a subagent's `mcpServers` rather than in `.mcp.json` — only the subagent pays the context cost.", "Use `memory: project` (default) to accumulate cross-session institutional knowledge sharable via VC; add explicit instructions in the subagent body to consult/update MEMORY.md before and after tasks.", "Use `@\"name (agent)\"` mention to guarantee a specific subagent runs; use natural-language naming when you want Claude to decide.", "Use a fork (`/fork <directive>`) instead of a named subagent when the side task needs too much context to re-explain, or to try several approaches in parallel from the same starting point — it reuses the prompt cache and is cheaper.", "Use `PreToolUse` hooks (exit code 2 to block) for conditional tool gating finer than the `tools` field allows, e.g. allowing read-only SQL while blocking INSERT/UPDATE/DELETE.", "Restate critical rules (e.g. 'ignore vendor/') in the delegation prompt when delegating to Explore/Plan, since those agents skip CLAUDE.md.", "For org-wide standard subagents, deploy them via managed settings `.claude/agents/` so they take precedence over project/user definitions.", "Use the main conversation (not a subagent) when the task needs iterative back-and-forth, shares significant context across phases, is a quick targeted change, or when latency matters."], "gotchas": ["Disabled by default — without CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS set, no team forms and Claude silently won't spawn teammates.", "No session resumption for in-process teammates: /resume and /rewind do NOT restore them; after resuming, the lead may try to message teammates that no longer exist — tell it to spawn new ones.", "Task status can lag: teammates sometimes fail to mark tasks completed, blocking dependent tasks; you may need to update status manually or nudge the teammate.", "The lead may shut down the team before all work is actually done, or start implementing tasks itself instead of delegating — tell it to keep going / wait for teammates.", "--dangerously-skip-permissions on the lead silently propagates to ALL teammates.", "Subagent skills and mcpServers frontmatter are ignored when the definition runs as a teammate (only tools and model carry over; body is appended to system prompt).", "Editing or pre-authoring ~/.claude/teams/{team-name}/config.json is futile — it's overwritten on next state update; there is no project-level team config file.", "team_name on the Agent tool and in hook payloads is accepted-but-ignored/deprecated since v2.1.178; TeamCreate/TeamDelete tools were removed.", "Idle teammate rows vanish from the panel after 30 seconds (hidden, not stopped) — can look like the teammate disappeared; message by name to bring it back.", "Split panes silently won't work in VS Code integrated terminal, Windows Terminal, or Ghostty; 'auto' falls back to in-process there.", "Orphaned tmux sessions can persist after Claude Code exits — clean up with tmux ls then tmux kill-session -t <name>.", "Limitations: exactly one team per session, no nested teams (teammates can't spawn teammates), lead is fixed and cannot transfer leadership, shutdown is slow (teammate finishes current request/tool call first).", "No message broadcast — reaching all teammates requires one message per recipient.", "Agent teams cost significantly more tokens than a single session (linear in active teammates) — overkill and wasteful for routine/sequential tasks.", "Each prompt typed in the agent view input starts a NEW session — typing again does not send a follow-up to the previous one. Use the peek panel or attach to reply to an existing session.", "Background sessions consume subscription quota independently; 10 parallel agents burn quota ~10x faster than one.", "Machine shutdown stops background sessions and they appear as `failed`; sleep does NOT (sessions are preserved and reconnect on wake). Recover failed-after-shutdown sessions by attaching/peeking/replying.", "Deleting a session in agent view (`Ctrl+X` twice) removes the Claude-created worktree and its uncommitted changes — push/commit first. `claude rm` keeps dirty worktrees but you must clean them up yourself with `git worktree remove`.", "A prompt that begins with one of your subagent names silently dispatches that subagent instead of treating the word as text; use explicit `@` or a different leading word.", "`claude agents` does NOT support the space-separated multi-value form (`--add-dir a b c`); repeat the flag per value.", "`bypassPermissions`/`auto` are refused for unattended dispatch until you've accepted that mode once interactively, even if you carry `--allow-dangerously-skip-permissions` through `/bg`.", "After an auto-update, the running supervisor may be on a different version than the `claude` you invoked; `claude daemon status`/`/doctor` warn and tell you to run `claude daemon stop --any` to pick up the new version.", "If `claude agents` just prints a count and lists your subagents then exits, agent view is unavailable in that environment (older versions, or Bedrock/Vertex/Foundry) — run `claude update`.", "On macOS the background host is a separate process and needs its own Files-and-Folders / Full Disk Access grants to read ~/Desktop, ~/Documents, ~/Downloads (`Operation not permitted` otherwise); with non-native installers the grant may need re-applying after updates.", "`.claude/worktrees/` can accumulate leftover worktrees; list with `git worktree list` and remove with `git worktree remove <path>`.", "Older completed sessions collapse into a `… N more` row (failures and open-PR sessions always stay visible), so a finished session may not be immediately visible.", "Backgrounding from an interactive session starts a fresh process from the saved conversation: running subagents, monitors, and background commands do NOT transfer (Claude asks to confirm if any are running).", "`/agents` and `claude agents` are different surfaces despite the similar name: `/agents` manages subagents within the current session; `claude agents` opens agent view for background sessions.", "Agent teams are disabled by default and experimental — not available without enabling.", "Agent teams provide no worktree isolation, so unpartitioned teammates can clobber each other's files.", "Routines run in Anthropic's cloud on a schedule — they are not a way to run agents in parallel on your machine.", "Parallel sessions/subagents multiply token consumption and can hit rate limits faster.", "The detailed subagent configuration (frontmatter fields, file paths like .claude/agents/, project vs user precedence, per-agent tool/model restrictions) lives on the separate /en/sub-agents page, not this overview page.", "Two subagent files in the same scope with the same `name` cause one to be silently discarded with no warning — keep `name` unique across the whole tree, including subfolders.", "Plugin subagents silently ignore `hooks`, `mcpServers`, and `permissionMode` frontmatter; these only work if you copy the file into `.claude/agents/` or `~/.claude/agents/`.", "Explore and Plan built-in subagents skip CLAUDE.md and git status — your project rules do NOT reach them, and there is no setting to change this.", "`permissionMode` in a subagent is silently overridden when the parent is in `bypassPermissions`/`acceptEdits` (takes precedence) or `auto` mode (ignored entirely).", "`--strict-mcp-config` does NOT filter MCP servers passed inline via `--agents` or the SDK `agents` option, since those are treated as explicit caller input — a managed-policy gap for CLI/SDK-injected agents.", "Editing a subagent file on disk does not hot-reload — you must restart the session (only the `/agents` interface applies changes immediately).", "Running many parallel subagents that each return detailed results can flood the main conversation context — the isolation benefit is lost on the return path.", "Git status given to subagents is a snapshot from the start of the parent session, not live — it can be stale.", "Built-in Explore/Plan return no agent ID and cannot be resumed; if you need to continue exploration work, use general-purpose or a custom subagent instead.", "With `CLAUDE_CODE_FORK_SUBAGENT=1`, ALL subagent spawns (not just forks) become background tasks, changing permission-prompt behavior unexpectedly.", "Within a subagent, `cd` does not persist between Bash calls — multi-step shell workflows relying on a changed directory will break.", "`bypassPermissions` is not fully safe: it permits writes to sensitive dot-directories like `.git` and `.claude`.", "The nested-subagent depth limit of 5 is fixed and not configurable; a depth-5 subagent silently loses the ability to spawn further."], "claims": ["Agent teams are experimental and disabled by default; enable by setting env var CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=\"1\" in settings.json env block or shell environment. Without it, no team is set up, no team directories are written, and Claude won't spawn teammates.", "Set teammate display mode via teammateMode in ~/.claude/settings.json (values: \"in-process\" default, \"auto\", \"tmux\", and as of v2.1.186 \"iterm2\"). Per-session override: claude --teammate-mode auto.", "Default display mode is \"in-process\" (any terminal, no setup). Before v2.1.179 the default was \"auto\"; upgraded sessions now stay single-terminal unless mode is set explicitly.", "\"auto\" enables split panes only when already inside tmux or terminal is iTerm2, else falls back to in-process. \"tmux\" forces split-pane and auto-detects tmux vs iTerm2. \"iterm2\" (v2.1.186+) requires the it2 CLI.", "Split-pane mode requires tmux or iTerm2 with the it2 CLI; it is NOT supported in VS Code's integrated terminal, Windows Terminal, or Ghostty. iTerm2 needs Python API enabled (Settings → General → Magic → Enable Python API).", "Team config stored at ~/.claude/teams/{team-name}/config.json; task list at ~/.claude/tasks/{team-name}/. team-name is \"session-\" + first 8 chars of session ID. Team config dir is removed when session ends; task list dir persists locally (never uploaded). Retention governed by cleanupPeriodDays setting.", "Do not hand-edit or pre-author team config.json — it holds runtime state (session IDs, tmux pane IDs) and is overwritten on next state update. There is NO project-level team config; .claude/teams/teams.json is treated as an ordinary file, not config.", "Teammates start with the lead's permission settings; if lead runs --dangerously-skip-permissions, all teammates do too. Individual teammate modes can be changed after spawning but cannot be set per-teammate at spawn time.", "Teammate permission requests bubble up to the lead. Pre-approve common operations in permission settings before spawning to reduce interruption friction.", "Teammates load the same project context as a regular session (CLAUDE.md, MCP servers, skills) plus the spawn prompt; the lead's conversation history does NOT carry over.", "Teammates can use subagent definitions from any scope (project, user, plugin, CLI) by name; teammate honors that definition's tools allowlist and model, and the body is appended to (not replacing) the teammate's system prompt. SendMessage and task-management tools are always available regardless of tools restriction.", "A subagent definition's skills and mcpServers frontmatter fields are NOT applied when run as a teammate; teammates load skills/MCP from project and user settings instead.", "Teammates don't inherit the lead's /model selection. Set Default teammate model in /config; choose \"Default (leader's model)\" to follow the lead. Model can also be specified per-spawn in the prompt (e.g. \"Use Sonnet for each teammate\").", "Plan approval gating: ask the lead to \"Require plan approval before they make any changes\"; teammate works read-only in plan mode until the lead approves. Lead approves autonomously; influence it via prompt criteria (e.g. \"only approve plans that include test coverage\").", "Quality-gate hooks: TeammateIdle (runs before teammate goes idle; exit code 2 sends feedback and keeps it working), TaskCreated (exit 2 prevents creation), TaskCompleted (exit 2 prevents completion). All use exit code 2 to block-and-feedback.", "Task states: pending, in progress, completed. Tasks can depend on other tasks; a pending task with unresolved dependencies cannot be claimed until dependencies complete. Task claiming uses file locking to prevent race conditions.", "In-process agent panel controls: up/down arrows select a teammate, Enter opens its transcript to message it, Escape interrupts its current turn, x stops a selected teammate, Ctrl+T toggles the task list.", "As of v2.1.181 an idle teammate's row hides after 30 seconds and reappears on its next turn; the teammate stays running and addressable while hidden (message it by name to bring it back).", "To reach all teammates you must send one message per recipient; there is no broadcast. Lead assigns teammate names at spawn; tell the lead what to name each teammate for predictable references.", "As of v2.1.178, spawning a teammate needs no setup step and cleanup is automatic on session exit. TeamCreate and TeamDelete tools no longer exist; the Agent tool's team_name input is accepted but ignored, and team_name in hook payloads is deprecated/session-derived.", "Token usage: each teammate is a separate Claude instance with its own context window; agent teams use significantly more tokens than a single session and scale linearly with active teammates (see /en/costs#agent-team-token-costs).", "Page reflects agent teams as of v2.1.178; specific behaviors gated to v2.1.179 (default in-process), v2.1.181 (idle row hides after 30s), v2.1.186 (iterm2 mode).", "Agent view opens with `claude agents`; it shows all background sessions grouped by state on one screen.", "Agent view is in research preview and requires Claude Code v2.1.139 or later (check with `claude --version`).", "`claude agents --cwd <path>` scopes the list to sessions started under that directory; requires v2.1.141 or later.", "Each background session uses your subscription quota independently — running 10 agents in parallel consumes quota roughly 10x as fast.", "Background sessions run locally on your machine, hosted by a per-user supervisor (daemon) process separate from the terminal; they survive closing the terminal/agent view and survive sleep, but stop on machine shutdown (showing as failed; recoverable by attach/peek/reply which restarts from where it left off).", "Row one-line summaries are generated by a Haiku-class model, refreshed at most once every 15 seconds plus once per turn end; each refresh is a billed short request under the same data-usage terms as the session.", "On third-party providers (Bedrock, Vertex AI, Microsoft Foundry, custom gateways) summaries fall back to the session's main model unless `ANTHROPIC_DEFAULT_HAIKU_MODEL` is set.", "Before editing files, a background session moves into an isolated git worktree under `.claude/worktrees/` so parallel sessions write to their own copy.", "Worktree isolation is skipped when: the session is already inside a linked worktree; the working dir isn't a git repo and no `WorktreeCreate` hook is configured; or the write is outside the working directory.", "Set `worktree.bgIsolation` to `\"none\"` in `.claude/settings.json` to disable background worktree isolation for a repo (requires v2.1.143 or later).", "Deleting a session in agent view (`Ctrl+X` twice within 2 seconds) deletes the Claude-created worktree including uncommitted changes; `claude rm <id>` keeps a worktree with uncommitted changes and prints its path; a worktree you created yourself is always left in place.", "Dispatch flags for `claude agents`: `--permission-mode`, `--model`, `--effort`, `--dangerously-skip-permissions` require v2.1.142; `--allow-dangerously-skip-permissions` requires v2.1.143; `--agent` (and honoring the `agent` setting) requires v2.1.157.", "`bypassPermissions` and `auto` modes are refused for background dispatch until accepted once by running `claude` interactively with that mode; carrying `--allow-dangerously-skip-permissions` through `/bg` does not bypass this one-time acceptance.", "Config flags `--settings`, `--add-dir`, `--plugin-dir`, `--mcp-config`, `--strict-mcp-config` are accepted by `claude agents` (require v2.1.142) and pass through to every dispatched session; repeat the flag once per value — space-separated multi-value form is NOT supported with `claude agents`.", "Flags carried through when backgrounding with `/bg`: `--mcp-config`, `--strict-mcp-config`, `--settings`, `--add-dir`, `--plugin-dir`, `--fallback-model`, `--allow-dangerously-skip-permissions`, plus directories added via `/add-dir`.", "Shell dispatch: `claude --bg \"<prompt>\"` backgrounds immediately; `--agent <name>` sets main agent; `--name` sets display name; `--exec '<cmd>'` runs a shell command as a PTY-backed job (no model invoked, output not written to disk, row+output auto-cleanup ~5 min after exit).", "Shell management commands: `claude attach <id>`, `claude logs <id>`, `claude stop <id>` (alias `claude kill`), `claude respawn <id>` / `--all`, `claude rm <id>`, `claude daemon status`, `claude daemon stop --any` (`--keep-workers` to preserve sessions). `claude agents --json` (add `--all`) prints sessions as JSON for scripting.", "Session short ID is the directory name under `~/.claude/jobs/`. State paths: `~/.claude/daemon.log`, `~/.claude/daemon/roster.json`, `~/.claude/jobs/<id>/state.json`, `~/.claude/jobs/<id>/tmp/` (writes here don't prompt for permission). Each session has `CLAUDE_JOB_DIR` env var set to its job dir.", "Setting `CLAUDE_CONFIG_DIR` makes the supervisor use that directory instead of `~/.claude` and run as a separate instance with its own sessions.", "Disable agent view via the `disableAgentView` setting set to `true` or the `CLAUDE_CODE_DISABLE_AGENT_VIEW` env var; administrators can enforce this through managed settings.", "A finished, unattached session has its process stopped after ~1 hour to free resources (restarts on next attach/peek/reply); pin with `Ctrl+T` to keep the process running while idle. Under low memory the supervisor stops idle non-pinned sessions first, pinned only if that frees nothing.", "The supervisor watches the on-disk binary and restarts into a new version after the auto-updater replaces it (local file watch, not a network check); `claude respawn --all` moves all sessions onto an updated binary at once.", "Dispatch input prefixes/mentions: `<agent-name> <prompt>` or `@<agent-name>` runs a subagent as main agent; `@<repo>` runs in a sibling repo; `/<command>` dispatches a skill/command; `! <command>` runs a shell job; `#<number>` or PR URL selects an existing PR session. `/exit`,`/quit`,`/logout` run in agent view itself; all other commands dispatch as a new session's first prompt.", "When an `@name` matches both a subagent and a sibling repo, the subagent wins; the bare first-word match also fires, so a prompt beginning with a subagent name dispatches that subagent — use a different leading word or explicit `@` to control it.", "`--cwd` and `--agent` defaults: `--agent` defaults to the `agent` setting if set, otherwise the built-in catch-all `claude` agent; before v2.1.157 agent view ignores the `agent` setting.", "Doc references Claude Code v2.1.140 in screenshots and feature gates up to v2.1.161 (parallel work-item `done/total` counts) and v2.1.145 (voice dictation in reply input); the feature is a research preview whose UI/shortcuts may change.", "Dispatch input rejects prompts shorter than 4 characters with a `Too short` hint.", "`claude agents` (CLI) opens agent view: one screen showing every background session, its state, and which need input.", "`/agents` opens a panel with a Running tab (live subagents) and a Library tab (create/edit custom subagents). This is separate from `claude agents` despite the similar name.", "`/tasks` lists anything running in the background of the current session and lets you check on, attach to, or stop it.", "`/workflows` lists running and completed dynamic-workflow runs, the phase each is in, and how many agents have finished.", "Agent teams are experimental and disabled by default.", "Agent view is a research preview.", "Subagents report results back to the conversation that spawned them; agent view sessions report only to you; agent team teammates share a task list and message each other directly.", "Agent teams do NOT isolate teammates in worktrees, so the work must be partitioned so each teammate owns a different set of files to avoid file conflicts.", "A background bash command runs one shell command without blocking the conversation but does NOT spawn an agent.", "To involve a non-Claude tool in any of these approaches, expose it to Claude as an MCP server.", "Running multiple sessions or subagents at once multiplies token usage (see Costs for rate-limit details).", "Subagents are Markdown files with YAML frontmatter; the body becomes the subagent's system prompt. Only `name` and `description` frontmatter fields are required.", "Subagent scope precedence (highest to lowest): (1) Managed settings (`.claude/agents/` in managed settings dir, org-wide), (2) `--agents` CLI flag (current session), (3) `.claude/agents/` (project), (4) `~/.claude/agents/` (user, all projects), (5) plugin `agents/` directory. When names collide, higher priority wins.", "Project subagents are discovered by walking up from cwd; every `.claude/agents/` between cwd and repo root is scanned. As of v2.1.178, when nested dirs define the same `name`, the definition closest to the working directory wins.", "`.claude/agents/` and `~/.claude/agents/` are scanned recursively; subfolders do not affect identity (identity = `name` frontmatter only). Two files in one scope with the same `name` cause one to be silently discarded.", "Plugin `agents/` subfolders DO become part of the scoped identifier: `agents/review/security.md` in plugin `my-plugin` registers as `my-plugin:review:security`.", "Plugin subagents do not support `hooks`, `mcpServers`, or `permissionMode` frontmatter fields (ignored for security). To use them, copy the file into `.claude/agents/` or `~/.claude/agents/`.", "`tools` field is an allowlist (inherits all if omitted); `disallowedTools` is a denylist. If both set, `disallowedTools` applies first, then `tools` resolves against the remainder; a tool in both is removed.", "Tool fields accept MCP patterns: `mcp__<server>` or `mcp__<server>__*` grant/remove all tools from a server; in `disallowedTools`, `mcp__*` removes all MCP tools from any server.", "`model` field options: `sonnet`, `opus`, `haiku`, `fable`, a full model ID (e.g. `claude-opus-4-8`), or `inherit`. Defaults to `inherit`.", "Subagent model resolution order: (1) `CLAUDE_CODE_SUBAGENT_MODEL` env var, (2) per-invocation `model` parameter, (3) subagent `model` frontmatter, (4) main conversation's model.", "`permissionMode` options: `default`, `acceptEdits`, `auto`, `dontAsk`, `bypassPermissions`, `plan`. If parent uses `bypassPermissions` or `acceptEdits`, that takes precedence and cannot be overridden by the subagent. If parent uses `auto` mode, subagent inherits auto and its `permissionMode` is ignored.", "Tools unavailable to subagents even if listed: `AskUserQuestion`, `EnterPlanMode`, `ScheduleWakeup`, `WaitForMcpServers`, and `ExitPlanMode` (unless `permissionMode: plan`).", "Built-in subagents: Explore (Haiku, read-only, file/code search), Plan (inherits model, read-only, plan-mode research), general-purpose (inherits model, all tools). Helper agents: statusline-setup (Sonnet), claude-code-guide (Haiku).", "Explore and Plan subagents SKIP CLAUDE.md files and git status to stay fast/cheap; every other built-in and custom subagent loads both. There is no frontmatter field or setting to change which agents skip them.", "Block a built-in subagent type via `permissions.deny: [\"Agent(Explore)\"]` (format `Agent(subagent-name)`), or CLI `--disallowedTools \"Agent(Explore)\"`. Deny the `Agent` tool itself to block all delegation.", "In non-interactive mode and the Agent SDK, set `CLAUDE_AGENT_SDK_DISABLE_BUILTIN_AGENTS=1` to remove all built-in subagent types.", "`--agents` CLI flag accepts JSON (not saved to disk, session-only) with fields: description, prompt, tools, disallowedTools, model, permissionMode, mcpServers, hooks, maxTurns, skills, initialPrompt, memory, effort, background, isolation, color. `prompt` = system prompt.", "`skills` frontmatter preloads FULL skill content (not just description) into the subagent at startup. Subagents can still invoke unlisted project/user/plugin skills via the Skill tool unless `Skill` is removed from tools/added to disallowedTools. Cannot preload skills with `disable-model-invocation: true`.", "`memory` field scopes: `user` (`~/.claude/agent-memory/<name>/`), `project` (`.claude/agent-memory/<name>/`, version-controlled), `local` (`.claude/agent-memory-local/<name>/`, not VC'd). When enabled, first 200 lines or 25KB of MEMORY.md (whichever first) is injected, and Read/Write/Edit are auto-enabled. `project` is the recommended default.", "`isolation: worktree` runs the subagent in a temporary git worktree branched (by default) from the default branch, not parent HEAD; worktree auto-cleaned if no changes made.", "`mcpServers` entries are either a string referencing an already-configured server (shares parent connection) or an inline definition (connected at subagent start, disconnected at finish). Defining inline keeps the server's tool descriptions out of the main conversation context.", "As of v2.1.153, MCP restrictions (`--strict-mcp-config`, `--bare`, enterprise managed MCP, `allowedMcpServers`/`deniedMcpServers`) also cover servers in subagent frontmatter. `--strict-mcp-config` does NOT filter servers passed inline via `--agents` or SDK `agents` option.", "Frontmatter `hooks` run only while that subagent is active; in frontmatter `Stop` is auto-converted to `SubagentStop` at runtime. settings.json supports `SubagentStart` and `SubagentStop` events (matcher = agent type name) for main-session lifecycle hooks.", "`--agent <name>` runs the whole session as that subagent: its system prompt fully replaces the default Claude Code system prompt (like `--system-prompt`); CLAUDE.md/project memory still load. Set `agent` in `.claude/settings.json` for a per-project default; CLI flag overrides the setting.", "`Agent(worker, researcher)` syntax in `tools` is an allowlist of which subagent types a `--agent` main thread can spawn. `Agent` without parens = spawn any; omitting `Agent` = cannot spawn any. The parenthesized list is ignored inside a (non-main) subagent definition.", "In v2.1.63 the Task tool was renamed to Agent; existing `Task(...)` references still work as aliases.", "As of v2.1.172 subagents can spawn nested subagents (same scopes). Depth limit is fixed at 5 (a subagent at depth 5 gets no Agent tool) and is not configurable. A fork cannot spawn another fork.", "Each subagent starts with fresh isolated context: it does NOT see conversation history, prior skills invoked, or files already read. Initial context = own system prompt + env details + delegation task message + CLAUDE.md/memory hierarchy + git status snapshot + preloaded skills. (Explore/Plan omit CLAUDE.md and git.)", "A fork inherits the entire conversation (system prompt, tools, model, message history) instead of starting fresh; its tool calls stay isolated and only its final result returns. Forks require v2.1.117+; `/fork` enabled by default from v2.1.161 (earlier needs `CLAUDE_CODE_FORK_SUBAGENT=1`). A fork cannot spawn further forks.", "When `CLAUDE_CODE_FORK_SUBAGENT=1`, every subagent spawn runs in the background regardless of the `background` field; set `CLAUDE_CODE_DISABLE_BACKGROUND_TASKS=1` to keep spawns synchronous.", "A fork's first request reuses the parent's prompt cache (system prompt + tool definitions identical), making forking cheaper than a fresh subagent. Named subagents use a separate cache.", "As of v2.1.186, a background subagent's permission prompt surfaces in the main session naming the subagent (approve, or Esc denies that one tool call without stopping it). Before v2.1.186, background subagents auto-denied any prompting tool call.", "Subagent transcripts stored at `~/.claude/projects/{project}/{sessionId}/subagents/agent-{agentId}.jsonl`; persist independently of main conversation (unaffected by main compaction); cleaned up per `cleanupPeriodDays` setting (default 30 days).", "Built-in Explore and Plan are one-shot, return no agent ID, and cannot be resumed; use general-purpose or a custom subagent to continue work. Claude resumes via the `SendMessage` tool with the agent ID/name; a stopped subagent receiving SendMessage auto-resumes in the background.", "Subagents auto-compact using the same logic as the main conversation; `CLAUDE_AUTOCOMPACT_PCT_OVERRIDE` applies to subagents too. Set `CLAUDE_CODE_DISABLE_BACKGROUND_TASKS=1` to disable all background tasks.", "`bypassPermissions` still allows writes to `.git`, `.claude`, `.vscode`, `.idea`, `.husky`, `.cargo`, `.devcontainer`, etc.; explicit `ask` rules and root/home removals like `rm -rf /` still prompt.", "Subagent `cd` commands do not persist between Bash/PowerShell calls and do not affect the main conversation's working directory. Subagents start in the main conversation's cwd.", "Directories added with `--add-dir` are scanned for subagents: a `.claude/agents/` inside an added dir loads alongside project subagents.", "Subagents created/edited as files on disk are loaded at session start (require restart to load); subagents created via the `/agents` interface take effect immediately.", "`/btw` answers a quick question with full conversation context but no tool access, and the answer is discarded (not added to history) — cheaper than spawning a subagent."]}, "MCP (connecting tools)": {"pages": ["managed-mcp", "mcp", "mcp-quickstart"], "bestPractices": ["Never store API keys/credentials in `env` blocks of managed-mcp.json — any user on the machine can read it. Use ${VAR} expansion from each user's environment, per-user OAuth/headers, or headersHelper for connection-time credentials.", "Choose the restriction pattern by control needed: disable MCP (empty map), fixed deployment (managed-mcp.json), approved catalog (allowedMcpServers + allowManagedMcpServersOnly:true), plugin-only (strictPluginOnlyCustomization with mcp), soft allowlist, or denylist-only.", "For enforcement, always enforce allowlists by serverUrl/serverCommand, never by serverName — names are user-assigned labels and trivially spoofed.", "Set allowManagedMcpServersOnly:true alongside allowedMcpServers in a managed source so users cannot broaden the allowlist via their own settings.", "After deploying a restriction, validate on a managed machine with `claude mcp list` and an expected-failure `claude mcp add` to confirm the policy is read.", "When rolling out a new restriction, proactively tell affected users which servers are blocked — previously-configured servers silently disappear from /mcp and claude mcp list with no policy reason given.", "Put admin-only flags (allowManagedMcpServersOnly, allowAllClaudeAiMcps) only in managed settings tiers; in user/project settings they are silently ignored.", "Enable OpenTelemetry export with OTEL_LOG_TOOL_DETAILS=1 to monitor which MCP servers/tools your org actually uses before tightening policy.", "Distribute an approved server catalog via a managed plugin marketplace (browsable from /plugin) or an internal wiki with the exact `claude mcp add` commands, since there is no built-in registry.", "For team-shared MCP, add servers at --scope project so config lands in .mcp.json at the project root and check it into version control; everyone on the team gets the same servers.", "Use env var expansion in .mcp.json (${API_KEY}, ${VAR:-default}) to share project config while keeping secrets and machine-specific paths out of version control.", "Prefer remote HTTP transport over SSE (deprecated) and over WebSocket when the server only responds to requests (HTTP supports OAuth and --transport; WebSocket supports neither).", "Keep MCP context usage low by leaving Tool Search at its default (deferred loading); adding more MCP servers then has minimal context impact. Reserve alwaysLoad:true for the small set of tools needed on every turn, since each upfront tool consumes context.", "For MCP servers you don't control that frequently exceed the 10,000-token warning, raise MAX_MCP_OUTPUT_TOKENS, or ask the author to add the anthropic/maxResultSizeChars annotation or paginate.", "Restrict an MCP server to a security-approved scope subset by pinning oauth.scopes in .mcp.json (it overrides discovered scopes); widen only when a needed tool returns 403 insufficient_scope.", "For non-OAuth auth (Kerberos, short-lived tokens, internal SSO) use headersHelper to generate headers at connection time rather than committing static tokens.", "For enterprise governance, use managed-mcp.json with allowedMcpServers/deniedMcpServers to centrally control which servers users can connect to; opt a repo out of cloud connectors with disableClaudeAiConnectors:true in checked-in project settings.", "Verify and trust each MCP server before connecting; servers that fetch external content expose you to prompt-injection risk.", "Bundle MCP servers in plugins for team consistency — everyone gets the same tools automatically when the plugin is enabled, no manual mcp add needed.", "Use claude mcp login <name> from the shell (v2.1.186+) to authenticate without opening a session; add --no-browser (with ssh -t) when on a remote host.", "For MCP server authors: write concise server instructions and tool descriptions (each truncated at 2KB) with critical details first, so Tool Search can find your tools.", "Distribute MCP servers to a team by adding at `--scope project` and committing `.mcp.json` to the repo; it acts as configuration-as-code teammates approve on clone.", "Use `--scope user` for personal servers you want in every project (e.g. a docs search server); use `local` (default) for project-specific experiments.", "Remove MCP servers you no longer use (`claude mcp remove <name>`) — every connected server consumes context window in every session because its tool names and instructions load each time.", "Prefer hand-editing `.mcp.json` for team/project servers since it is checked into the repo; restart the session after editing because it's only read at startup.", "For first-run slow stdio servers (npx downloading packages), bump `MCP_TIMEOUT` (ms) rather than assuming a failed connection; re-run `claude mcp list` after a moment.", "Diagnose connection failures by transport: for HTTP run `curl -I <url>` (404/405 = up, 401/403 = needs auth, no response = network); for stdio run the configured command directly to surface the real error.", "For org-wide control, manage MCP access via managed settings/policy (/en/managed-mcp) rather than per-user config."], "gotchas": ["managed-mcp.json CANNOT be delivered via server-managed settings — it must go to a system path via MDM/admin-privileged process; misplacing it means it is silently not read.", "Deploying managed-mcp.json silently suppresses BOTH claude.ai connectors (including org admin-configured ones) and plugin-provided servers; allowAllClaudeAiMcps only restores claude.ai connectors, never plugin servers.", "When policy blocks a previously-configured server, it silently disappears from /mcp and `claude mcp list` with no warning that policy is the reason.", "serverName is NOT a security control — a user can label any server 'github'; only serverUrl/serverCommand enforce identity. A serverName allowlist entry never matches if any serverUrl/serverCommand entry of the same transport exists.", "allowedMcpServers unset (all allowed) vs empty array [] (nothing allowed) behave very differently — easy to lock everyone out with [].", "serverCommand requires EXACT argument match including order and every flag; a missing -y or an extra --flag fails the match.", "Denylists always merge from every settings source (including user settings) and always override allowlists, even under allowManagedMcpServersOnly — users can always block managed servers for themselves.", "allowManagedMcpServersOnly is distinct from allowManagedPermissionRulesOnly; setting the permission-rules flag does nothing for the MCP allowlist.", "serverName allowlist entries are restricted to [A-Za-z0-9_-]; denylist serverName (v2.1.182+) accepts any string — different validation between the two lists.", "allowAllClaudeAiMcps requires Claude Code v2.1.149+; older clients ignore it and connectors stay suppressed.", "Anthropic does not security-audit MCP servers in its directory — approval is the admin's responsibility.", "Scope definitions do NOT merge: when a server is defined in multiple scopes, only the entire entry from the highest-precedence source is used.", "MCP 'local scope' stores in ~/.claude.json (home dir), NOT in .claude/settings.local.json — easy to confuse with general local settings.", "For stdio servers you MUST separate server args with '--'; without it Claude Code parses the server's flags (e.g. --port) as its own options.", "Placing the server name directly after --env makes the CLI read the name as another KEY=value pair and reject it; put another option in between.", "Missing required env var with no default in .mcp.json causes Claude Code to fail to parse the entire config.", "Project-scoped .mcp.json servers are NOT auto-trusted — they require approval; reset stale choices with claude mcp reset-project-choices.", "claude.ai connectors silently do NOT load when ANTHROPIC_API_KEY, ANTHROPIC_AUTH_TOKEN, apiKeyHelper, Bedrock, or Vertex auth is active — even after /login. Run /status to check active auth.", "If headers.Authorization is set but rejected, Claude Code reports a failed connection rather than falling back to OAuth — token must be valid for the MCP endpoint or remove the header.", "Stdio servers do NOT auto-reconnect (only HTTP/SSE do); auth and not-found startup errors are never retried.", "Tool descriptions and server instructions over 2KB are silently truncated.", "Tool Search is unsupported on Haiku models and on pre-Sonnet-4.5/Opus-4.5 Vertex AI; setting ENABLE_TOOL_SEARCH=true on those causes requests to fail; it also auto-disables behind a non-first-party ANTHROPIC_BASE_URL proxy.", "The server name 'workspace' is reserved and will be skipped with a warning.", "alwaysLoad:true blocks session startup until that server connects (capped at 5s), unlike normal non-blocking MCP startup.", "_meta anthropic/maxResultSizeChars (ceiling 500,000 chars) only raises the limit for text content; image-returning tools are still capped by MAX_MCP_OUTPUT_TOKENS.", "${CLAUDE_PROJECT_DIR} in project/user-scoped .mcp.json needs a default (${CLAUDE_PROJECT_DIR:-.}) because it's set in the server's env, not Claude Code's; only plugin configs substitute it directly.", "disableClaudeAiConnectors uses any-source-true semantics — a project-level false cannot re-enable connectors disabled by a user- or policy-level true; and it does NOT apply to Claude Code on the web sessions (connectors arrive as --mcp-config there).", "Import from Claude Desktop only works on macOS and WSL; duplicate-named imports get a numeric suffix.", "Local-scoped servers are tied to the exact project/repo root where you ran `claude mcp add`; running it in a different directory makes the server invisible there (`/mcp` shows 'No MCP servers configured'). Use `--scope user` to avoid this.", "Editing config at the wrong path silently fails — only `~/.claude.json` and `<project>/.mcp.json` are read; common wrong guesses (`~/.claude/mcp.json`, `%APPDATA%\\Claude\\mcp.json`) are ignored.", ".mcp.json changes don't apply mid-session — Claude Code reads it only at session start; you must restart.", "Malformed `.mcp.json` entries are silently skipped; run `/mcp` to see the parse warning naming the offending field.", "The `Added` confirmation only means the entry was saved, not that the server actually starts/connects — always verify with `claude mcp list`.", "Omitting the `--` separator before a stdio server's launch command produces a wrong/garbled command; `claude mcp get <name>` reveals the mismatch.", "If you previously rejected a project-scoped server prompt, it stays rejected until you run `claude mcp reset-project-choices`.", "A server can connect yet expose no tools if a required env var (e.g. API key) is missing — pass it via `--env KEY=value` or the `.mcp.json` `env` field.", "Adding a server with a name already used at the same scope errors with 'Server already exists'; remove the old one or pick a new name.", "In PowerShell use `curl.exe` (not `curl`, which aliases Invoke-WebRequest) when testing HTTP server reachability."], "claims": ["By default, anyone running Claude Code can connect any MCP server they choose; Anthropic reviews directory connectors against listing criteria but does NOT security-audit or manage any MCP server.", "`managed-mcp.json` deploys a fixed server set with EXCLUSIVE control: Claude Code loads only servers that file defines; users cannot add, modify, or use any other MCP server, including plugin-provided servers.", "`managed-mcp.json` paths: macOS `/Library/Application Support/ClaudeCode/managed-mcp.json`; Linux/WSL `/etc/claude-code/managed-mcp.json`; Windows `C:\\Program Files\\ClaudeCode\\managed-mcp.json`.", "`managed-mcp.json` is a standalone file and CANNOT be delivered through server-managed settings; deploy via MDM/device management (Jamf, configuration profile on macOS; Group Policy or Intune on Windows; fleet management on Linux) — any process with administrator privileges that can write to the system path.", "`managed-mcp.json` uses the same format as a project `.mcp.json`: a top-level `mcpServers` map; server entries support `type` (`http`/`stdio`), `url`, `command`, `args`, `env`.", "Disable MCP entirely by deploying `managed-mcp.json` with an empty server map `{\"mcpServers\": {}}` — users see no servers in `/mcp` and `claude mcp add` fails with the enterprise-policy error.", "Deploying `managed-mcp.json` suppresses claude.ai connectors by default (including admin-configured org connectors) AND plugin-provided servers.", "`allowAllClaudeAiMcps: true` loads claude.ai connectors alongside the managed set; requires Claude Code v2.1.149 or later. It does NOT un-suppress plugin-provided servers. Allowlists/denylists still apply to those connectors.", "`allowAllClaudeAiMcps` and `allowManagedMcpServersOnly` and `allowAllClaudeAiMcps` are read only from admin-controlled tiers (server-managed settings, MDM plist/HKLM registry, or system `managed-settings.json`); placing them in user/project settings has no effect.", "Allowlist/denylist entries are objects with a single key: `serverUrl` (remote, exact or `*` wildcards), `serverCommand` (exact command+args array for stdio), or `serverName` (user-assigned label, exact match, no wildcards).", "`serverName` is NOT a security control: it is the label a user assigns, so a user can call any server `github`. Use `serverCommand` or `serverUrl` to enforce which servers actually run.", "`allowedMcpServers` unset = all servers allowed; empty array `[]` = no servers allowed; populated = only matching allowed. `deniedMcpServers` unset or `[]` = nothing blocked; populated = matching blocked.", "Server evaluation order: (1) merge allow/deny lists from all sources (denylist always merges from all sources; allowlist merges from all sources unless `allowManagedMcpServersOnly: true` keeps only the managed allowlist); (2) check denylist — any match blocks, nothing overrides; (3) check allowlist.", "Denylist always takes precedence over allowlist (a server matching both is blocked).", "In the allowlist, a remote server is allowed by a `serverUrl` entry; a `serverName` match counts ONLY when the allowlist contains no `serverUrl` entries. A stdio server is allowed by `serverCommand`; `serverName` counts only when no `serverCommand` entries exist.", "`serverCommand` matches exactly: every argument in order. `[\"npx\",\"-y\",\"server\"]` does not match `[\"npx\",\"server\"]` or with an extra `--flag`.", "`serverUrl` supports `*` wildcards anywhere including the scheme; hostname matching is case-insensitive and ignores trailing FQDN dot; paths stay case-sensitive. A URL pattern with no path matches any path.", "`serverName` validation differs by list: in `deniedMcpServers` (v2.1.182+) it accepts any non-empty string (can block claude.ai connectors by display name); in `allowedMcpServers` it is limited to letters, numbers, hyphens, and underscores.", "To make the allowlist authoritative, set `allowedMcpServers` and `allowManagedMcpServersOnly: true` together in a managed settings source. Without `allowManagedMcpServersOnly`, allowlists from every source merge (including user `~/.claude/settings.json`), so users can broaden it.", "`allowManagedMcpServersOnly` is separate from `allowManagedPermissionRulesOnly` (which locks permission rules only); setting the permission flag does NOT enforce the MCP allowlist.", "With `managed-mcp.json` deployed, `allowedMcpServers`/`deniedMcpServers` still apply to managed servers (a managed server that fails them won't load), and a user's own `deniedMcpServers` merges in so users can block a managed server for themselves.", "Plugin-servers-only pattern: use `strictPluginOnlyCustomization` with `mcp` in the list — servers can only come from plugins, users can't add their own. Distribute servers via a managed plugin marketplace so users install from `/plugin`.", "Disable all claude.ai connectors entirely with `disableClaudeAiConnectors`.", "Validate managed-mcp.json is active: `claude mcp list` shows only the managed servers; `claude mcp add --transport http test https://example.com/mcp` fails with `Cannot add MCP server: enterprise MCP configuration is active and has exclusive control over MCP servers` (URL need not be real — policy rejects before contacting).", "Claude Code has no built-in MCP server registry users can browse/install from; for an approved catalog, share the list + `claude mcp add` commands (e.g. internal wiki) or distribute as plugins via a managed marketplace.", "Monitor MCP usage via OpenTelemetry export: set `OTEL_LOG_TOOL_DETAILS=1` to include MCP server and tool names in tool events, then aggregate in your collector.", "MCP servers are configured at three scopes: local (default, current project only, private, stored in ~/.claude.json), project (current project only, shared via version control, stored in .mcp.json at project root), user (all your projects, private, stored in ~/.claude.json).", "Scope flag values: 'local' (was 'project' in older versions), 'project', 'user' (was 'global' in older versions). Set with --scope.", "Scope precedence (highest first, when a server is defined in multiple places, one definition is used and fields are NOT merged): 1. Local, 2. Project, 3. User, 4. Plugin-provided servers, 5. claude.ai connectors. The three scopes match duplicates by name; plugins and connectors match by endpoint (URL or command).", "Add remote HTTP server: claude mcp add --transport http <name> <url>. HTTP is the recommended transport for remote servers.", "Add SSE server: claude mcp add --transport sse <name> <url>. SSE transport is DEPRECATED; use HTTP instead.", "Add local stdio server: claude mcp add [options] <name> -- <command> [args...]. The '--' separates Claude's options (--transport, --env, --scope) from the server command; everything after '--' is passed untouched.", "Add WebSocket server only via .mcp.json or claude mcp add-json with type 'ws'; the --transport flag does NOT accept ws. WebSocket auth is header-only (no OAuth).", "In JSON config (.mcp.json, ~/.claude.json, claude mcp add-json), the type field accepts 'streamable-http' as an alias for 'http'.", "--env accepts multiple KEY=value pairs. Do not place the server name directly after --env (it gets read as another pair and rejected); put another option between --env and the server name.", "Management commands: claude mcp list, claude mcp get <name>, claude mcp remove <name>; /mcp inside Claude Code checks server status.", "Project-scoped .mcp.json servers require approval before use. Pending servers show as '⏸ Pending approval' in claude mcp list and get; rejected as '✗ Rejected'. Reset approval choices with: claude mcp reset-project-choices.", ".mcp.json format: {\"mcpServers\": {\"<name>\": {\"command\":...,\"args\":[],\"env\":{}}}} for stdio, or {\"type\":\"http\",\"url\":...,\"headers\":{}} for HTTP.", "Local-scoped servers are stored in ~/.claude.json under projects.<project-path>.mcpServers. Note: MCP 'local scope' (~/.claude.json) differs from general local settings (.claude/settings.local.json).", "Env var expansion in .mcp.json supports ${VAR} and ${VAR:-default}, expandable in command, args, env, url, and headers. If a required var is unset with no default, Claude Code fails to parse the config.", "OAuth 2.0 supported for HTTP servers. Claude Code marks a server as needing auth on 401 or 403. Authenticate via /mcp panel, or from CLI (v2.1.186+): claude mcp login <name>, claude mcp logout <name>. Over SSH use --no-browser and connect with ssh -t.", "Bearer/header auth: claude mcp add --transport http <name> <url> --header \"Authorization: Bearer <token>\". If headers.Authorization is set and rejected, Claude Code reports failure rather than falling back to OAuth.", "Pre-configured OAuth: --client-id <id>, --client-secret (prompts masked, or set MCP_CLIENT_SECRET env var for CI), --callback-port <port> (fixes OAuth callback to http://localhost:PORT/callback). These flags apply only to HTTP/SSE, not stdio. Secret stored in system keychain/credentials file, not config.", "oauth.scopes in .mcp.json pins requested scopes (space-separated string) and takes precedence over authServerMetadataUrl and discovered scopes — the supported way to restrict an MCP server to a security-approved subset. oauth.authServerMetadataUrl (v2.1.64+, must be https) overrides OAuth discovery.", "headersHelper (in .mcp.json) runs a shell command at connection time to generate auth headers; must write a JSON object of string key-value pairs to stdout, runs in a shell with a 10-second timeout, overrides static headers with same name, runs fresh on each connect (no caching). At project/local scope it only runs after accepting the workspace trust dialog. Env vars provided: CLAUDE_CODE_MCP_SERVER_NAME, CLAUDE_CODE_MCP_SERVER_URL.", "MCP output: warning when any MCP tool output exceeds 10,000 tokens. Default maximum is 25,000 tokens, raised via MAX_MCP_OUTPUT_TOKENS env var. Server authors can set _meta[\"anthropic/maxResultSizeChars\"] per tool (hard ceiling 500,000 chars) for text content; image-returning tools remain subject to MAX_MCP_OUTPUT_TOKENS.", "MCP_TIMEOUT env var sets server startup timeout (e.g. MCP_TIMEOUT=10000). Per-server tool execution timeout: 'timeout' field (ms) in the server's .mcp.json entry overrides MCP_TOOL_TIMEOUT for that server. Values below 1000 are ignored and fall through to MCP_TOOL_TIMEOUT (default ~28 hours). HTTP/SSE first-byte fetch budget has a 60-second minimum.", "MCP Tool Search is enabled by default: tool definitions are deferred (only tool names + server instructions load at session start) and discovered on demand via a search tool. No fixed per-server tool cap; the limit is the context window budget.", "ENABLE_TOOL_SEARCH values: (unset)=all deferred, falls back to upfront on Vertex AI or non-first-party ANTHROPIC_BASE_URL; true=all deferred even on Vertex/proxies (sends beta header); auto=load upfront if tools fit within 10% of context window else defer; auto:N=custom percentage; false=all loaded upfront. Requires a model supporting tool_reference blocks; Haiku does not support it. On Vertex AI supported for Sonnet 4.5+/Opus 4.5+.", "Disable ToolSearch tool via permissions: {\"permissions\":{\"deny\":[\"ToolSearch\"]}}. Without tool search, Claude uses WaitForMcpServers to wait on background-connecting servers; with tool search the wait happens inside ToolSearch.", "alwaysLoad:true on a server config loads all its tools upfront regardless of ENABLE_TOOL_SEARCH (available all server types, v2.1.121+). It also blocks startup until the server connects, capped at the 5-second connect timeout. A server/tool can also set _meta \"anthropic/alwaysLoad\": true per tool.", "Tool descriptions and server instructions are truncated at 2KB each. Put critical details near the start.", "HTTP/SSE servers auto-reconnect mid-session with exponential backoff: up to 5 attempts, starting 1s delay doubling each time, then marked failed (retry from /mcp). Stdio servers are NOT auto-reconnected. v2.1.121+: initial connection retried up to 3 times on transient errors (5xx, connection refused, timeout); auth and not-found errors are NOT retried.", "Plugin-bundled MCP servers: defined in .mcp.json at plugin root or inline in plugin.json under mcpServers; start automatically when plugin enabled; use ${CLAUDE_PLUGIN_ROOT}, ${CLAUDE_PLUGIN_DATA}, ${CLAUDE_PROJECT_DIR}. Run /reload-plugins to connect/disconnect after enable/disable mid-session. Tool name form: mcp__plugin_<plugin-name>_<server-name>__<tool-name>.", "Claude.ai connectors: servers added in Claude.ai (claude.ai/customize/connectors; on Team/Enterprise only admins can add) are auto-available in Claude Code. Loaded ONLY when active auth is the Claude.ai subscription — NOT when ANTHROPIC_API_KEY, ANTHROPIC_AUTH_TOKEN, apiKeyHelper, Bedrock, or Vertex is active.", "Disable claude.ai connectors: set disableClaudeAiConnectors:true in any settings scope (any-source-true: true anywhere wins; project false cannot re-enable a user/policy true), or ENABLE_CLAUDEAI_MCP_SERVERS=false env var (current shell). Block individual connectors by name/URL via deniedMcpServers (e.g. serverName \"claude.ai Slack\"). Servers passed via --mcp-config are unaffected.", "claude mcp serve runs Claude Code itself as a stdio MCP server exposing its tools (View, Edit, LS, etc.); the connecting client is responsible for tool-call confirmation.", "Import from Claude Desktop: claude mcp add-from-claude-desktop (macOS and WSL only); use --scope user to import to user config; duplicate names get a numeric suffix (e.g. server_1).", "MCP resources referenced via @ mentions: format @server:protocol://resource/path (e.g. @github:issue://123). Multiple resources per prompt allowed; fetched and included as attachments.", "MCP prompts become slash commands: /mcp__servername__promptname, args passed space-separated (e.g. /mcp__github__pr_review 456). Spaces in names normalized to underscores.", "For stdio servers Claude Code sets CLAUDE_PROJECT_DIR in the spawned server's environment to the project root. Referencing it via ${CLAUDE_PROJECT_DIR} in project/user-scoped .mcp.json command/args requires a default like ${CLAUDE_PROJECT_DIR:-.}; plugin configs substitute it directly without a default.", "The server name 'workspace' is reserved for internal use — Claude Code skips a server with that name at load time and warns to rename it.", "Managed MCP (enterprise/admin): deploy a fixed server set via managed-mcp.json, restrict with allowedMcpServers and deniedMcpServers. Documented at /en/managed-mcp.", "MCP servers can be scaffolded via the official mcp-server-dev plugin: /plugin install mcp-server-dev@claude-plugins-official then /mcp-server-dev:build-mcp-server (run /plugin marketplace add anthropics/claude-plugins-official first if marketplace not found).", "Per docs (Use MCP servers from Claude.ai): On Team and Enterprise plans, only admins can add MCP connectors in Claude.ai.", "Add an MCP server with `claude mcp add [--transport http|sse] <name> <url>` for hosted servers, or `claude mcp add <name> -- <command> <args>` for local stdio servers (everything after `--` is the launch command).", "`claude mcp add` defaults to `local` scope: private to you and active only in the current project.", "Three scopes exist: `local` (stored in `~/.claude.json` under the project entry; only you, only this project — the default), `project` (stored in `.mcp.json` in project root; everyone who clones the repo), and `user` (stored in `~/.claude.json` under top-level `mcpServers`; only you, all projects). Set with `--scope project` or `--scope user`.", "To share an MCP server with a team, add at `--scope project` (writes `.mcp.json` in project root) and commit `.mcp.json` to version control. Teammates who clone get a prompt to approve the server before it connects.", "Scope is fixed at add time; to change scope you must `claude mcp remove <name> --scope <old>` then re-add with the new `--scope`.", "`claude mcp list` shows each server with a status: `✓ Connected`, `! Connected · tools fetch failed`, `! Needs authentication`, `✗ Failed to connect`, `✗ Connection error`, or `⏸ Pending approval` (project-scoped server not yet approved).", "`claude mcp get <name>` shows which scope holds a server's definition and the full config (including the launch command for stdio servers).", "`claude mcp remove <name>`; if the name exists at multiple scopes, remove reports `exists in multiple scopes` and you must pass `--scope` to disambiguate.", "Inside a session, `/mcp` checks/manages servers, reconnects, and authenticates. OAuth servers (Sentry, Linear, Notion) are signed in via `/mcp` → select server → `Authenticate` → browser sign-in.", "Servers using a static token instead of OAuth pass it at add time: `--header \"Authorization: Bearer <token>\"`.", "`.mcp.json` format: top-level `mcpServers` object; HTTP entries use `\"type\":\"http\"` + `\"url\"`; stdio entries use `\"type\":\"stdio\"` + `\"command\"` + `\"args\"` (array). Env vars go in an `env` field.", "Local stdio servers use the default `stdio` transport (no `--transport` flag needed); hosted servers require `--transport http` (or sse).", "Pass server environment variables (e.g. API keys) with `--env KEY=value` on `claude mcp add`, or via the `env` field in `.mcp.json`.", "Claude Code reads `.mcp.json` only at session start; editing it requires exiting and restarting the session to take effect.", "Config files Claude Code actually reads are `~/.claude.json` and `<project>/.mcp.json` only. It does NOT read `~/.claude/config/mcp.json`, `~/.claude/mcp.json`, or `%APPDATA%\\Claude\\mcp.json`.", "On Windows `~/.claude.json` resolves to `%USERPROFILE%\\.claude.json`. If `CLAUDE_CONFIG_DIR` is set, Claude Code reads `.claude.json` from inside that directory instead.", "Default MCP server startup timeout is 30 seconds; override with `MCP_TIMEOUT` env var in milliseconds, e.g. `MCP_TIMEOUT=60000 claude`.", "`claude mcp reset-project-choices` resets project-scoped server approvals (use if you previously rejected a server prompt).", "`claude mcp add-from-claude-desktop` (macOS or WSL) imports servers from Claude Desktop's `claude_desktop_config.json` into the CLI.", "Claude.ai connectors added at claude.ai/customize/connectors load automatically in the CLI when signed in with that account. Claude Code on the web reads `.mcp.json` from the repository.", "Organization-level MCP governance is via managed settings and policy controls (referenced page /en/managed-mcp)."]}};

// __CHUNK__ (injected)
const themes = Object.entries(CHUNK);
log(`synthesizing ${themes.length} themes`);

const OUT = {
  type: "object", additionalProperties: false, required: ["markdown"],
  properties: { markdown: { type: "string", description: "the clean compendium section in markdown" } },
};

const results = await pipeline(
  themes,
  ([theme, d]) => agent(
    `You are compiling the DEFINITIVE compendium section on "${theme}" for a lead setting up and optimally running Claude Code (+ Codex) for a team. Below are raw extractions pulled from every official docs page in this theme — they are redundant, unordered, and overlapping. Distill them into ONE clean, dense, well-organized reference section in markdown.\n\n` +
    `RULES:\n` +
    `- DEDUPLICATE hard — the raw is very repetitive; each point appears once, in the best-worded form.\n` +
    `- Organize with ## and ### sub-headings by sub-topic; lead with what matters most for a TEAM setup and optimal use.\n` +
    `- Keep EXACT facts: flag names, file paths, setting keys, precedence, limits, commands. Put config/commands/file names in \`\`\` code fences. Use a markdown table where it genuinely helps (e.g. settings keys, precedence).\n` +
    `- End with a "### Gotchas" subsection capturing the pitfalls.\n` +
    `- Be COMPENDIOUS: complete and dense, but zero filler — this is a reference, not a tutorial. Aim for thorough coverage of everything in the raw material that bears on team setup / optimal use / best practices.\n` +
    `- Start the section with a single \`## ${theme}\` heading.\n\n` +
    `SOURCE PAGES: ${d.pages.join(", ")}\n\n` +
    `RAW BEST PRACTICES (${(d.bestPractices || []).length}):\n` + (d.bestPractices || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW GOTCHAS (${(d.gotchas || []).length}):\n` + (d.gotchas || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW FACTS (${(d.claims || []).length}):\n` + (d.claims || []).map((x) => `- ${x}`).join("\n"),
    { agentType: "general-purpose", effort: "high", schema: OUT, label: theme.slice(0, 28), phase: "Synthesize" },
  ),
);

const out = {};
themes.forEach(([t], i) => { if (results[i]?.markdown) out[t] = results[i].markdown; });
log(`synthesized ${Object.keys(out).length} sections`);
return { sections: out };
